window.COURSE_DATA = {
  id: "c20-exam",
  questions: [{"id": 1, "sec": "Principles & Load Calculations", "q": "An air conditioner provides 36,000 BTU/h of cooling and draws 3,000 watts. What is its EER?", "opts": ["6.0", "12.0", "9.0", "18.0"], "correct": 1, "re": "EER = cooling capacity (BTU/h) ÷ power input (watts) = 36,000 ÷ 3,000 = 12.0. EER rates steady-state efficiency at a fixed condition (95°F outdoor).", "rr": "EER = мощность охлаждения (BTU/h) ÷ потребляемая мощность (ватт) = 36,000 ÷ 3,000 = 12.0. EER — КПД в установившемся режиме при фиксированных условиях (95°F снаружи).", "qr": "Кондиционер даёт 36,000 BTU/h охлаждения и потребляет 3,000 ватт. Какой у него EER?", "optsr": ["6.0", "12.0", "9.0", "18.0"]}, {"id": 2, "sec": "Principles & Load Calculations", "q": "One ton of refrigeration equals how many BTU/h?", "opts": ["15,000", "6,000", "10,000", "12,000"], "correct": 3, "re": "One ton of refrigeration = 12,000 BTU/h — the heat needed to melt one ton of ice in 24 hours (288,000 BTU ÷ 24 h).", "rr": "Одна тонна (ton of refrigeration) = 12,000 BTU/h — тепло, нужное чтобы растопить одну тонну льда за 24 часа (288,000 BTU ÷ 24 ч).", "qr": "Одна тонна холодопроизводительности (ton) равна скольким BTU/h?", "optsr": ["15,000", "6,000", "10,000", "12,000"]}, {"id": 3, "sec": "Principles & Load Calculations", "q": "A common rule of thumb for residential cooling airflow is approximately how much CFM per ton?", "opts": ["200 CFM", "400 CFM", "100 CFM", "800 CFM"], "correct": 1, "re": "About 400 CFM per ton (range 350–450) is standard residential design airflow — lower (~350) for humid climates, higher (~450) for dry climates.", "rr": "Около 400 CFM на тонну (диапазон 350–450) — стандартный проектный воздухопоток для жилья; меньше (~350) во влажном климате, больше (~450) в сухом.", "qr": "Грубое правило для жилого охлаждения — сколько примерно CFM на тонну?", "optsr": ["200 CFM", "400 CFM", "100 CFM", "800 CFM"]}, {"id": 4, "sec": "Principles & Load Calculations", "q": "Which formula calculates the sensible heat of an airstream?", "opts": ["Qs = 500 × GPM × ΔT", "Qs = 1.08 × CFM × ΔT", "Qs = 4.5 × CFM × Δh", "Qs = 0.68 × CFM × Δgrains"], "correct": 1, "re": "Sensible heat: Qs = 1.08 × CFM × ΔT(°F). The 1.08 factor combines air density and specific heat at standard conditions. 0.68 = latent (grains), 4.5 = total (enthalpy), 500 = water.", "rr": "Явное тепло: Qs = 1.08 × CFM × ΔT(°F). Коэффициент 1.08 учитывает плотность и теплоёмкость воздуха при стандартных условиях. 0.68 — скрытое (grains), 4.5 — полное (enthalpy), 500 — вода.", "qr": "Какая формула считает явное (sensible) тепло воздушного потока?", "optsr": ["Qs = 500 × GPM × ΔT", "Qs = 1.08 × CFM × ΔT", "Qs = 4.5 × CFM × Δh", "Qs = 0.68 × CFM × Δgrains"]}, {"id": 5, "sec": "Principles & Load Calculations", "q": "Total heat (sensible + latent) of an airstream is found using which factor?", "opts": ["4.5", "0.68", "1.08", "60"], "correct": 0, "re": "Total heat Qt = 4.5 × CFM × Δh (enthalpy, BTU/lb). 1.08 = sensible, 0.68 = latent (grains of moisture).", "rr": "Полное тепло Qt = 4.5 × CFM × Δh (enthalpy, BTU/lb). 1.08 — явное, 0.68 — скрытое (по grains влаги).", "qr": "Полное тепло (явное + скрытое) воздушного потока считают с каким коэффициентом?", "optsr": ["4.5", "0.68", "1.08", "60"]}, {"id": 6, "sec": "Principles & Load Calculations", "q": "ACCA Manual J is used to determine what?", "opts": ["Commercial load", "Equipment model selection", "Duct sizing", "Residential heating and cooling load"], "correct": 3, "re": "Manual J = Residential Load Calculation — it finds the building's heating/cooling load (BTU/h). Manual D = duct design, Manual S = equipment selection, Manual N = commercial load.", "rr": "Manual J = Residential Load Calculation — определяет тепловую нагрузку здания (BTU/h). Manual D — воздуховоды, Manual S — подбор оборудования, Manual N — коммерческая нагрузка.", "qr": "Для чего используется ACCA Manual J?", "optsr": ["Коммерческая нагрузка", "Подбор модели оборудования", "Подбор воздуховодов", "Тепловая нагрузка жилья (отопление/охлаждение)"]}, {"id": 7, "sec": "Principles & Load Calculations", "q": "Which ACCA manual covers residential duct system design?", "opts": ["Manual D", "Manual S", "Manual P", "Manual J"], "correct": 0, "re": "Manual D = Residential Duct Systems. It sizes ducts using the available static pressure and the resulting friction rate.", "rr": "Manual D = Residential Duct Systems. Подбирает воздуховоды по доступному статическому давлению и итоговому friction rate.", "qr": "Какой ACCA manual описывает проектирование жилых воздуховодов?", "optsr": ["Manual D", "Manual S", "Manual P", "Manual J"]}, {"id": 8, "sec": "Principles & Load Calculations", "q": "After calculating the load, which ACCA manual guides correct equipment selection?", "opts": ["Manual S", "Manual D", "Manual J", "Manual N"], "correct": 0, "re": "Manual S = Residential Equipment Selection — it matches equipment capacity to the Manual J load so the system isn't oversized.", "rr": "Manual S = Residential Equipment Selection — подбирает мощность оборудования под нагрузку из Manual J, чтобы не было oversizing.", "qr": "После расчёта нагрузки какой ACCA manual ведёт правильный подбор оборудования?", "optsr": ["Manual S", "Manual D", "Manual J", "Manual N"]}, {"id": 9, "sec": "Principles & Load Calculations", "q": "How does SEER differ from EER?", "opts": ["SEER measures airflow", "SEER applies only to heat pumps", "SEER is measured at full load only", "SEER is a seasonal average over a range of conditions"], "correct": 3, "re": "SEER (Seasonal Energy Efficiency Ratio) averages efficiency across a cooling season and varying outdoor temps; EER is a single steady-state rating at 95°F. SEER is higher than EER for the same unit.", "rr": "SEER (Seasonal EER) усредняет КПД за сезон при разной наружной температуре; EER — одна точка при 95°F. У одного и того же агрегата SEER выше, чем EER.", "qr": "Чем SEER отличается от EER?", "optsr": ["SEER измеряет воздухопоток", "SEER только для тепловых насосов", "SEER меряется только при полной нагрузке", "SEER — сезонное среднее по диапазону условий"]}, {"id": 10, "sec": "Principles & Load Calculations", "q": "The coefficient of performance (COP) of a heat pump is defined as:", "opts": ["BTU ÷ ton", "Heat output ÷ work input", "CFM ÷ watts", "Work input ÷ heat output"], "correct": 1, "re": "COP = useful heat output ÷ energy input (same units). COP of 3 means 3 units of heat per unit of electricity. COP ≈ EER ÷ 3.412.", "rr": "COP = полезное тепло на выходе ÷ затраченная энергия (в одних единицах). COP=3 значит 3 единицы тепла на 1 единицу электричества. COP ≈ EER ÷ 3.412.", "qr": "Коэффициент эффективности (COP) теплового насоса определяется как:", "optsr": ["BTU ÷ тонна", "Тепло на выходе ÷ работа на входе", "CFM ÷ ватт", "Работа на входе ÷ тепло на выходе"]}, {"id": 11, "sec": "Principles & Load Calculations", "q": "On a psychrometric chart, the moisture in the air relative to the maximum it can hold at that temperature is called:", "opts": ["Wet-bulb temperature", "Enthalpy", "Dew point", "Relative humidity"], "correct": 3, "re": "Relative humidity (RH) = actual moisture ÷ maximum the air can hold at that dry-bulb temp, as a percent.", "rr": "Relative humidity (RH) = фактическая влага ÷ максимум, который воздух может удержать при этой dry-bulb температуре, в процентах.", "qr": "На психрометрической диаграмме влага в воздухе относительно максимума при данной температуре — это:", "optsr": ["Wet-bulb температура", "Enthalpy", "Точка росы (dew point)", "Relative humidity (отн. влажность)"]}, {"id": 12, "sec": "Principles & Load Calculations", "q": "The temperature at which water vapor in the air begins to condense is the:", "opts": ["Dry-bulb temperature", "Wet-bulb temperature", "Design temperature", "Dew point"], "correct": 3, "re": "Dew point is where air becomes saturated (100% RH) and moisture condenses. Coil surfaces below dew point produce condensate (dehumidification).", "rr": "Dew point — точка, где воздух насыщается (100% RH) и влага конденсируется. Поверхности испарителя ниже точки росы дают конденсат (осушение).", "qr": "Температура, при которой пар в воздухе начинает конденсироваться, — это:", "optsr": ["Dry-bulb температура", "Wet-bulb температура", "Проектная температура", "Dew point (точка росы)"]}, {"id": 13, "sec": "Principles & Load Calculations", "q": "A sling psychrometer is used to measure:", "opts": ["Refrigerant pressure", "Airflow velocity", "Wet-bulb and dry-bulb temperatures", "Static pressure"], "correct": 2, "re": "A sling psychrometer reads dry-bulb and wet-bulb; the wet-bulb depression gives RH and dew point on the psychrometric chart.", "rr": "Sling psychrometer показывает dry-bulb и wet-bulb; разница (wet-bulb depression) даёт RH и точку росы по психрометрической диаграмме.", "qr": "Sling psychrometer используется для измерения:", "optsr": ["Давления хладагента", "Скорости воздуха", "Wet-bulb и dry-bulb температур", "Статического давления"]}, {"id": 14, "sec": "Principles & Load Calculations", "q": "Outdoor design conditions for load calculations are typically based on:", "opts": ["A code-mandated 110°F", "The single hottest day on record", "The average yearly temperature", "ASHRAE/ACCA 1% and 99% design values"], "correct": 3, "re": "Manual J uses ASHRAE statistical design conditions (e.g., 1% summer, 99% winter) so equipment is sized for typical extremes, not record extremes — avoiding oversizing.", "rr": "Manual J использует статистические условия ASHRAE (напр., 1% лето, 99% зима), чтобы подобрать под типичные экстремумы, а не рекордные — это исключает oversizing.", "qr": "Наружные расчётные условия для load calc обычно берут из:", "optsr": ["Обязательных по коду 110°F", "Самого жаркого дня в истории", "Среднегодовой температуры", "Значений ASHRAE/ACCA 1% и 99%"]}, {"id": 15, "sec": "Principles & Load Calculations", "q": "A residential air handler is typically rated for a total external static pressure (TESP) of about:", "opts": ["5.0 in. w.c.", "0.5 in. w.c.", "0.05 in. w.c.", "15 in. w.c."], "correct": 1, "re": "Most residential air handlers/furnaces are rated near 0.5 in. w.c. TESP. Measured static above this signals restrictive ducts, a dirty filter, or undersized returns.", "rr": "Большинство жилых air handler/печей рассчитаны на ~0.5 in. w.c. TESP. Замеренный статик выше — признак узких воздуховодов, грязного фильтра или малого return.", "qr": "Жилой воздухообрабатывающий агрегат обычно рассчитан на TESP около:", "optsr": ["5.0 in. w.c.", "0.5 in. w.c.", "0.05 in. w.c.", "15 in. w.c."]}, {"id": 16, "sec": "Principles & Load Calculations", "q": "In the equal-friction duct design method, the friction rate is expressed in:", "opts": ["BTU per hour", "CFM per ton", "Inches of water column per 100 ft", "Degrees per foot"], "correct": 2, "re": "Friction rate is in inches of water column per 100 ft of duct. Manual D derives it from available static pressure and total effective length.", "rr": "Friction rate — в дюймах вод. ст. (in. w.c.) на 100 футов воздуховода. Manual D выводит его из доступного статического давления и общей эффективной длины.", "qr": "В методе equal-friction для воздуховодов friction rate выражается в:", "optsr": ["BTU в час", "CFM на тонну", "Дюймах вод. ст. на 100 футов", "Градусах на фут"]}, {"id": 17, "sec": "Principles & Load Calculations", "q": "Recommended air velocity in residential main supply trunks is generally:", "opts": ["700–900 fpm", "2,000–2,500 fpm", "100–300 fpm", "4,000+ fpm"], "correct": 0, "re": "Residential supply trunks run roughly 700–900 fpm (branches lower) to limit noise and friction; commercial systems use higher velocities.", "rr": "В жилых supply-магистралях обычно 700–900 fpm (ветки ниже), чтобы ограничить шум и трение; в коммерции скорости выше.", "qr": "Рекомендуемая скорость воздуха в магистральных supply-воздуховодах жилья обычно:", "optsr": ["700–900 fpm", "2,000–2,500 fpm", "100–300 fpm", "4,000+ fpm"]}, {"id": 18, "sec": "Principles & Load Calculations", "q": "To estimate nominal tonnage from design airflow, you divide CFM by approximately:", "opts": ["400", "12,000", "200", "100"], "correct": 0, "re": "At ~400 CFM/ton, tonnage ≈ CFM ÷ 400 (e.g., 1,600 CFM ÷ 400 ≈ 4 tons). This is airflow-based; actual capacity comes from a Manual J load.", "rr": "При ~400 CFM/тонну тоннаж ≈ CFM ÷ 400 (напр., 1,600 ÷ 400 ≈ 4 тонны). Это по воздуху; реальная мощность — из Manual J.", "qr": "Чтобы оценить номинальную тоннажность по проектному воздухопотоку, CFM делят примерно на:", "optsr": ["400", "12,000", "200", "100"]}, {"id": 19, "sec": "Principles & Load Calculations", "q": "Summer cooling load on a building is most affected by:", "opts": ["The furnace paint color", "Duct length alone", "Floor area only", "Windows/solar gain, insulation, and infiltration"], "correct": 3, "re": "Cooling load is driven by solar gain through glazing, conduction through walls/roof/insulation, infiltration, and internal gains (people, appliances) — all in Manual J.", "rr": "Нагрузку охлаждения определяют солнечный приток через остекление, теплопередача через стены/крышу/утепление, инфильтрация и внутренние притоки (люди, приборы) — всё в Manual J.", "qr": "На летнюю нагрузку охлаждения здания сильнее всего влияют:", "optsr": ["Цвет краски печи", "Только длина воздуховодов", "Только площадь пола", "Окна/солнечный приток, утепление и инфильтрация"]}, {"id": 20, "sec": "Principles & Load Calculations", "q": "Air infiltration into a building is commonly expressed as:", "opts": ["Air changes per hour (ACH)", "BTU per ton", "Microns", "Static pressure"], "correct": 0, "re": "Infiltration/ventilation is often given in ACH (air changes per hour) or CFM. Tighter homes have lower ACH and a lower infiltration load.", "rr": "Инфильтрацию/вентиляцию часто задают в ACH (воздухообмен в час) или CFM. У более герметичных домов ниже ACH и меньше нагрузка от инфильтрации.", "qr": "Инфильтрацию воздуха в здание обычно выражают в:", "optsr": ["Воздухообменах в час (ACH)", "BTU на тонну", "Микронах", "Статическом давлении"]}, {"id": 21, "sec": "Principles & Load Calculations", "q": "An undersized return air grille will most likely cause:", "opts": ["Lower amp draw", "Increased SEER", "Low head pressure", "High static pressure and reduced airflow"], "correct": 3, "re": "Undersized returns raise static pressure, starve the blower, cut airflow (CFM), and can freeze the coil and raise energy use.", "rr": "Малый return повышает статическое давление, «душит» вентилятор, снижает CFM и может приводить к обмерзанию испарителя и росту энергопотребления.", "qr": "Недостаточный по размеру return-грилль скорее всего вызовет:", "optsr": ["Снижение тока (amp)", "Рост SEER", "Низкое head давление", "Высокий статик и снижение воздухопотока"]}, {"id": 22, "sec": "Principles & Load Calculations", "q": "A nominal 4-ton air conditioner has a rated cooling capacity of:", "opts": ["24,000 BTU/h", "36,000 BTU/h", "60,000 BTU/h", "48,000 BTU/h"], "correct": 3, "re": "4 tons × 12,000 BTU/h = 48,000 BTU/h nominal cooling capacity.", "rr": "4 тонны × 12,000 BTU/h = 48,000 BTU/h номинальной холодопроизводительности.", "qr": "Номинальный 4-тонный кондиционер имеет холодопроизводительность:", "optsr": ["24,000 BTU/h", "36,000 BTU/h", "60,000 BTU/h", "48,000 BTU/h"]}, {"id": 23, "sec": "Principles & Load Calculations", "q": "A complete job estimate should include material, labor, overhead, and:", "opts": ["Profit (markup)", "Only sales tax", "Refrigerant only", "The customer's utility bill"], "correct": 0, "re": "A complete estimate covers material, labor, equipment, overhead, permits, and a profit markup. Omitting overhead/profit leads to losses.", "rr": "Полная смета учитывает материалы, труд, оборудование, накладные, разрешения и наценку-прибыль. Без накладных/прибыли — убытки.", "qr": "Полная смета по объекту должна включать материалы, труд, накладные и:", "optsr": ["Прибыль (markup)", "Только налог с продаж", "Только хладагент", "Счёт клиента за коммуналку"]}, {"id": 24, "sec": "Principles & Load Calculations", "q": "Oversizing an air conditioner most commonly results in:", "opts": ["Higher SEER", "Short cycling and poor humidity control", "Lower installation cost", "Better dehumidification"], "correct": 1, "re": "An oversized unit short-cycles: it hits setpoint before removing enough moisture, leaving the space cold and clammy. Manual J/S sizing prevents this.", "rr": "Завышенный агрегат работает короткими циклами: достигает уставки раньше, чем убирает влагу — холодно и сыро. Подбор по Manual J/S это предотвращает.", "qr": "Завышение мощности (oversizing) кондиционера чаще всего ведёт к:", "optsr": ["Более высокому SEER", "Short cycling и плохому контролю влажности", "Меньшей стоимости монтажа", "Лучшему осушению"]}, {"id": 25, "sec": "Principles & Load Calculations", "q": "On a psychrometric chart, lines of constant enthalpy run nearly parallel to lines of constant:", "opts": ["Dry-bulb temperature", "Relative humidity", "Dew point", "Wet-bulb temperature"], "correct": 3, "re": "Constant-enthalpy lines closely follow constant wet-bulb lines, which is why wet-bulb is a good index of total heat content.", "rr": "Линии постоянной enthalpy почти совпадают с линиями постоянной wet-bulb — поэтому wet-bulb хороший индикатор полного теплосодержания.", "qr": "На психрометрической диаграмме линии постоянной enthalpy почти параллельны линиям постоянной:", "optsr": ["Dry-bulb температуры", "Relative humidity", "Точки росы", "Wet-bulb температуры"]}, {"id": 26, "sec": "Fabrication & Installation", "q": "Joining copper refrigerant tubing on a high-pressure system is normally done by:", "opts": ["Compression fittings only", "Soldering below 840°F", "Brazing above 840°F", "Gluing"], "correct": 2, "re": "Refrigerant joints are brazed with filler melting above 840°F (often ~1,150°F) for strength under high pressure. Soldering (<840°F) is too weak for refrigerant lines.", "rr": "Соединения хладагента паяют brazing с припоем, плавящимся выше 840°F (часто ~1,150°F) — для прочности под высоким давлением. Мягкая пайка (<840°F) слишком слаба.", "qr": "Соединение медных трубок хладагента на системе высокого давления обычно делают:", "optsr": ["Только обжимными фитингами", "Пайкой мягким припоем ниже 840°F", "Brazing (твёрдой пайкой) выше 840°F", "Клеем"]}, {"id": 27, "sec": "Fabrication & Installation", "q": "Why is dry nitrogen flowed through tubing while brazing refrigerant lines?", "opts": ["To add charge", "To test for leaks", "To prevent internal oxidation/scale", "To cool the joint"], "correct": 2, "re": "Flowing nitrogen purges oxygen so no copper oxide (black scale) forms inside the tubing. Scale can clog metering devices and contaminate the system.", "rr": "Продувка азотом вытесняет кислород, и внутри трубки не образуется оксид меди (чёрная окалина). Окалина забивает дозаторы и загрязняет систему.", "qr": "Зачем при brazing продувают трубки сухим азотом (nitrogen)?", "optsr": ["Чтобы добавить заправку", "Чтобы найти течь", "Чтобы не было внутреннего окисления/окалины", "Чтобы охладить шов"]}, {"id": 28, "sec": "Fabrication & Installation", "q": "A deep vacuum on a refrigerant system is typically pulled to about:", "opts": ["0 psig", "500 microns", "28 in. Hg", "5 psig"], "correct": 1, "re": "Target ~500 microns (and the system holds it) to remove moisture and noncondensables. A micron gauge — not a compound gauge — confirms the level.", "rr": "Цель — ~500 микрон (и система держит), чтобы убрать влагу и неконденсируемые газы. Уровень подтверждает micron gauge, а не обычный манометр.", "qr": "Глубокий вакуум в системе хладагента обычно тянут примерно до:", "optsr": ["0 psig", "500 микрон", "28 in. Hg", "5 psig"]}, {"id": 29, "sec": "Fabrication & Installation", "q": "Moisture left in a refrigerant system can combine with refrigerant and oil to form:", "opts": ["Acids and sludge", "Pure water vapor only", "Nitrogen", "Extra capacity"], "correct": 0, "re": "Moisture reacts with refrigerant and oil to form acids that corrode components and damage the compressor — why evacuation and a filter-drier matter.", "rr": "Влага реагирует с хладагентом и маслом, образуя кислоты, которые корродируют узлы и убивают компрессор — поэтому важны вакуумирование и filter-drier.", "qr": "Влага, оставшаяся в системе, в сочетании с хладагентом и маслом образует:", "optsr": ["Кислоты и шлам", "Только чистый водяной пар", "Азот", "Дополнительную мощность"]}, {"id": 30, "sec": "Fabrication & Installation", "q": "In a split system, the larger-diameter, insulated refrigerant line is the:", "opts": ["Liquid line", "Hot gas bypass", "Suction (vapor) line", "Drain line"], "correct": 2, "re": "The suction line carries cool low-pressure vapor to the compressor; it's larger and insulated to prevent heat gain and sweating. The liquid line is smaller and uninsulated.", "rr": "Suction line несёт холодный пар низкого давления к компрессору; она толще и изолирована, чтобы не было нагрева и конденсата. Liquid line тоньше и без изоляции.", "qr": "В сплит-системе бóльшая по диаметру, изолированная трубка хладагента — это:", "optsr": ["Liquid line (жидкостная)", "Hot gas bypass", "Suction (паровая) line", "Дренаж"]}, {"id": 31, "sec": "Fabrication & Installation", "q": "A condensate drain from a cooling coil should include a:", "opts": ["P-trap", "Relief valve", "Check valve", "Pressure switch"], "correct": 0, "re": "A P-trap stops blower pressure from pulling air in or pushing it out through the drain, lets condensate flow, and blocks odors/air bypass.", "rr": "P-trap не даёт давлению вентилятора подсасывать или выдувать воздух через дренаж, обеспечивает сток конденсата и блокирует запахи/перетоки воздуха.", "qr": "Дренаж конденсата от испарителя должен включать:", "optsr": ["P-trap (сифон)", "Предохранительный клапан", "Обратный клапан", "Реле давления"]}, {"id": 32, "sec": "Fabrication & Installation", "q": "Minimum slope for a horizontal condensate drain line is generally:", "opts": ["Uphill", "1 in. per foot", "No slope needed", "1/8 in. per foot"], "correct": 3, "re": "At least 1/8 in. per foot (about 1%) toward the drain so condensate flows by gravity and doesn't pool, which causes overflow and microbial growth.", "rr": "Не менее 1/8 in. на фут (~1%) в сторону слива, чтобы конденсат шёл самотёком и не застаивался (иначе перелив и рост биоплёнки).", "qr": "Минимальный уклон горизонтальной дренажной линии конденсата обычно:", "optsr": ["Вверх", "1 in. на фут", "Уклон не нужен", "1/8 in. на фут"]}, {"id": 33, "sec": "Fabrication & Installation", "q": "The electrical disconnect for an outdoor condensing unit must be located:", "opts": ["Anywhere convenient", "Within sight of the unit", "In the attic", "At the meter only"], "correct": 1, "re": "NEC requires a disconnecting means within sight of and readily accessible to the equipment so a technician can lock it out before servicing.", "rr": "NEC требует средство отключения в пределах видимости и в лёгком доступе у оборудования, чтобы техник мог сделать LOTO перед обслуживанием.", "qr": "Электрический disconnect для наружного конденсатора должен находиться:", "optsr": ["Где удобно", "В пределах видимости агрегата", "На чердаке", "Только у счётчика"]}, {"id": 34, "sec": "Fabrication & Installation", "q": "On a condensing unit nameplate, MOCP refers to the:", "opts": ["Motor oil capacity", "Maximum overcurrent protection (breaker/fuse)", "Minimum circuit ampacity", "Maximum operating pressure"], "correct": 1, "re": "MOCP = Maximum Overcurrent Protection — the largest breaker/fuse allowed. MCA (Minimum Circuit Ampacity) sets the minimum wire size. Both must be followed.", "rr": "MOCP = Maximum Overcurrent Protection — наибольший допустимый автомат/предохранитель. MCA (Minimum Circuit Ampacity) задаёт минимальное сечение провода. Соблюдают оба.", "qr": "На шильдике конденсатора MOCP означает:", "optsr": ["Объём моторного масла", "Макс. защита от сверхтока (автомат/предохранитель)", "Минимальная токопроводимость цепи", "Макс. рабочее давление"]}, {"id": 35, "sec": "Fabrication & Installation", "q": "A thermostatic expansion valve (TXV) controls refrigerant flow to maintain constant:", "opts": ["Head pressure", "Subcooling", "Condenser temperature", "Evaporator superheat"], "correct": 3, "re": "A TXV modulates to hold relatively constant evaporator superheat across loads, feeding the coil efficiently. A fixed orifice does not adjust.", "rr": "TXV модулирует, удерживая относительно постоянный superheat испарителя при разной нагрузке, эффективно питая змеевик. Фиксированный orifice не подстраивается.", "qr": "Терморегулирующий вентиль (TXV) регулирует поток хладагента, поддерживая постоянным:", "optsr": ["Head давление", "Subcooling", "Температуру конденсатора", "Superheat испарителя"]}, {"id": 36, "sec": "Fabrication & Installation", "q": "A filter-drier is normally installed in the:", "opts": ["Condensate drain", "Suction line near the compressor", "Discharge line", "Liquid line ahead of the metering device"], "correct": 3, "re": "The liquid-line filter-drier removes moisture and debris and protects the metering device. The arrow on the drier must point in the flow direction.", "rr": "Filter-drier на liquid line убирает влагу и мусор и защищает дозатор. Стрелка на drier должна смотреть по направлению потока.", "qr": "Filter-drier обычно ставят в:", "optsr": ["Дренаж конденсата", "Suction line у компрессора", "Discharge line", "Liquid line перед дозатором"]}, {"id": 37, "sec": "Fabrication & Installation", "q": "A system with a TXV is most accurately charged using the:", "opts": ["Box-weight guess", "Superheat method", "Subcooling method", "Sight only"], "correct": 2, "re": "TXV systems are charged by subcooling (liquid line), since the TXV already controls superheat. Fixed-orifice (piston) systems use the superheat method.", "rr": "Системы с TXV заправляют по subcooling (liquid line), т.к. TXV уже держит superheat. Системы с фиксированным orifice (piston) — по методу superheat.", "qr": "Систему с TXV точнее всего заправлять методом:", "optsr": ["На глаз по коробке", "Superheat", "Subcooling", "Визуально"]}, {"id": 38, "sec": "Fabrication & Installation", "q": "Superheat is the number of degrees a refrigerant vapor is heated:", "opts": ["Above its saturation (boiling) temperature", "Below dew point", "Above ambient", "Below its condensing temperature"], "correct": 0, "re": "Superheat = vapor temp − saturation temp at that pressure. It confirms all liquid has boiled off before the compressor, protecting it from slugging.", "rr": "Superheat = темп. пара − темп. насыщения при этом давлении. Подтверждает, что вся жидкость выкипела до компрессора, защищая его от гидроудара.", "qr": "Superheat — это число градусов, на которое пар хладагента нагрет:", "optsr": ["Выше температуры насыщения (кипения)", "Ниже точки росы", "Выше окружающей", "Ниже температуры конденсации"]}, {"id": 39, "sec": "Fabrication & Installation", "q": "Subcooling is the number of degrees liquid refrigerant is cooled:", "opts": ["Above ambient", "Above its saturation temperature", "Below its condensing (saturation) temperature", "Below the evaporator temperature"], "correct": 2, "re": "Subcooling = saturation temp − liquid temp at the condenser/liquid line. Adequate subcooling ensures solid liquid feeds the metering device.", "rr": "Subcooling = темп. насыщения − темп. жидкости на конденсаторе/liquid line. Достаточный subcooling гарантирует, что в дозатор идёт чистая жидкость.", "qr": "Subcooling — это число градусов, на которое жидкий хладагент охлаждён:", "optsr": ["Выше окружающей", "Выше температуры насыщения", "Ниже температуры конденсации (насыщения)", "Ниже температуры испарителя"]}, {"id": 40, "sec": "Fabrication & Installation", "q": "The correct instrument to verify a deep vacuum is a:", "opts": ["Micron (vacuum) gauge", "Clamp ammeter", "Manometer", "Compound gauge"], "correct": 0, "re": "A micron gauge reads the deep-vacuum range accurately; a standard compound gauge can't tell 1,000 from 25,000 microns.", "rr": "Micron gauge точно показывает диапазон глубокого вакуума; обычный compound gauge не различит 1,000 и 25,000 микрон.", "qr": "Правильный прибор для проверки глубокого вакуума — это:", "optsr": ["Micron (вакуумный) gauge", "Токовые клещи", "Манометр", "Compound gauge"]}, {"id": 41, "sec": "Fabrication & Installation", "q": "Typical manifold (outlet) gas pressure for a natural-gas furnace is about:", "opts": ["11 in. w.c.", "1 psi", "3.5 in. w.c.", "25 in. w.c."], "correct": 2, "re": "Natural-gas furnaces run ~3.5 in. w.c. manifold pressure; LP (propane) runs ~10–11 in. w.c. Always set per the rating plate with a manometer.", "rr": "Печи на природном газе — ~3.5 in. w.c. manifold; на LP (пропан) — ~10–11 in. w.c. Всегда выставляют по шильдику манометром.", "qr": "Типичное manifold (выходное) давление газа для печи на природном газе:", "optsr": ["11 in. w.c.", "1 psi", "3.5 in. w.c.", "25 in. w.c."]}, {"id": 42, "sec": "Fabrication & Installation", "q": "Fuel-burning furnaces installed in a confined space require:", "opts": ["No special air", "Adequate combustion and ventilation air", "Only return air", "A larger filter"], "correct": 1, "re": "Combustion appliances need sufficient combustion/ventilation air per the Mechanical Code; too little air causes incomplete combustion, CO, and backdrafting.", "rr": "Топливным приборам нужен достаточный воздух для горения/вентиляции по Mechanical Code; нехватка ведёт к неполному сгоранию, CO и обратной тяге.", "qr": "Печи на топливе в стеснённом пространстве требуют:", "optsr": ["Никакого особого воздуха", "Достаточного воздуха для горения и вентиляции", "Только return-воздуха", "Большего фильтра"]}, {"id": 43, "sec": "Fabrication & Installation", "q": "A standard mid-efficiency furnace using a Type-B vent is classified as:", "opts": ["Category III", "Category I", "Category IV", "Category II"], "correct": 1, "re": "Category I appliances vent with natural draft (non-positive, non-condensing) into a B-vent. Category IV (condensing, 90%+) uses sealed PVC venting.", "rr": "Category I — естественная тяга (без избыточного давления, не конденсационная) в B-vent. Category IV (конденсационная, 90%+) — герметичный PVC vent.", "qr": "Стандартная печь средней эффективности с Type-B vent относится к:", "optsr": ["Category III", "Category I", "Category IV", "Category II"]}, {"id": 44, "sec": "Fabrication & Installation", "q": "Per California Title 24, newly installed ducts in unconditioned space must be insulated to at least:", "opts": ["R-4", "R-6 / R-8 (climate dependent)", "R-2", "No insulation"], "correct": 1, "re": "Title 24 typically requires duct insulation of R-6 to R-8 depending on climate zone, plus duct-leakage sealing/testing on most alterations.", "rr": "Title 24 обычно требует изоляцию воздуховодов R-6…R-8 в зависимости от климатической зоны, плюс герметизацию и тест на утечки при большинстве работ.", "qr": "По California Title 24 новые воздуховоды в неконд. пространстве изолируют минимум до:", "optsr": ["R-4", "R-6 / R-8 (по климату)", "R-2", "Без изоляции"]}, {"id": 45, "sec": "Fabrication & Installation", "q": "The preferred material for permanently sealing duct joints is:", "opts": ["Mastic (with mesh on gaps)", "Spray paint", "Caulk only", "Cloth-backed (gray) duct tape"], "correct": 0, "re": "Duct mastic (with fiberglass mesh on larger gaps) gives a durable, code-accepted seal. Standard cloth duct tape dries and fails; UL-181 tapes are allowed where listed.", "rr": "Duct mastic (с сеткой на больших зазорах) даёт прочный и принимаемый кодом шов. Обычная тканевая лента пересыхает и отваливается; ленты UL-181 допустимы там, где сертифицированы.", "qr": "Предпочтительный материал для постоянной герметизации стыков воздуховодов:", "optsr": ["Mastic (с mesh на зазорах)", "Краска из баллона", "Только герметик", "Серая тканевая duct tape"]}, {"id": 46, "sec": "Fabrication & Installation", "q": "Flexible duct should be supported at intervals not exceeding about:", "opts": ["4 ft", "1 ft", "12 ft", "No support needed"], "correct": 0, "re": "Flex duct is typically supported at intervals up to ~4 ft with max sag near 1/2 in. per foot of spacing, using wide straps to avoid pinching and airflow restriction.", "rr": "Flex duct обычно поддерживают с шагом до ~4 футов, провис не более ~1/2 in. на фут шага, широкими хомутами — чтобы не пережать и не задушить поток.", "qr": "Гибкий воздуховод (flex duct) поддерживают с интервалом не более примерно:", "optsr": ["4 фута", "1 фут", "12 футов", "Опора не нужна"]}, {"id": 47, "sec": "Fabrication & Installation", "q": "Before opening a sealed refrigerant system for repair, the technician must first:", "opts": ["Cut the line open", "Add refrigerant", "Recover the refrigerant per EPA 608", "Run the compressor"], "correct": 2, "re": "EPA Section 608 requires recovering refrigerant into approved equipment before opening the system; venting to atmosphere is illegal.", "rr": "EPA Section 608 требует откачать хладагент в одобренное оборудование до вскрытия; выпуск в атмосферу незаконен.", "qr": "Перед вскрытием герметичной системы хладагента для ремонта техник должен сначала:", "optsr": ["Срезать линию", "Добавить хладагент", "Откачать (recover) хладагент по EPA 608", "Запустить компрессор"]}, {"id": 48, "sec": "Fabrication & Installation", "q": "A normal cooling temperature split (return minus supply air) is about:", "opts": ["2–5°F", "50°F+", "14–22°F", "30–40°F"], "correct": 2, "re": "A properly charged system with correct airflow shows roughly a 14–22°F drop across the evaporator. Outside this range points to airflow or charge problems.", "rr": "Правильно заправленная система с верным воздухопотоком даёт перепад ~14–22°F на испарителе. Вне диапазона — проблемы с воздухом или заправкой.", "qr": "Нормальный temperature split при охлаждении (return минус supply) около:", "optsr": ["2–5°F", "50°F+", "14–22°F", "30–40°F"]}, {"id": 49, "sec": "Fabrication & Installation", "q": "On a typical low-voltage thermostat, the 'Y' terminal controls the:", "opts": ["Fan only", "Common", "Heat", "Cooling (compressor) contactor"], "correct": 3, "re": "Y = cooling call (energizes the compressor contactor). G = fan, W = heat, R = 24V power, C = common. Correct wiring is essential.", "rr": "Y = вызов охлаждения (включает контактор компрессора). G = вентилятор, W = тепло, R = 24V питание, C = common. Правильная разводка обязательна.", "qr": "На обычном низковольтном термостате клемма 'Y' управляет:", "optsr": ["Только вентилятором", "Common", "Отоплением", "Cooling (контактор компрессора)"]}, {"id": 50, "sec": "Fabrication & Installation", "q": "A condensing unit should be set on a level pad primarily to:", "opts": ["Increase SEER", "Improve appearance", "Ensure proper compressor oil return and drainage", "Reduce wire size"], "correct": 2, "re": "A level unit ensures correct oil return to the compressor and proper water drainage; an unlevel pad causes oil migration and premature compressor failure.", "rr": "Ровный агрегат обеспечивает правильный возврат масла в компрессор и сток воды; перекос ведёт к миграции масла и преждевременному выходу компрессора.", "qr": "Конденсатор ставят на ровную площадку (pad) в первую очередь чтобы:", "optsr": ["Поднять SEER", "Улучшить вид", "Обеспечить возврат масла в компрессор и сток воды", "Уменьшить сечение провода"]}, {"id": 51, "sec": "Fabrication & Installation", "q": "When silver-brazing near a service valve, the technician should:", "opts": ["Skip the nitrogen", "Braze with the valve fully open and unprotected", "Protect/cool the valve and keep nitrogen flowing", "Pump down only"], "correct": 2, "re": "Heat-sensitive valves should be protected (wet rag/heat sink) with nitrogen flowing to prevent seal damage and internal oxidation.", "rr": "Теплочувствительные вентили защищают (мокрая ветошь/теплоотвод) и держат продувку азотом, чтобы не повредить уплотнения и не дать внутреннего окисления.", "qr": "При brazing рядом с сервисным вентилем техник должен:", "optsr": ["Обойтись без азота", "Паять с полностью открытым незащищённым вентилем", "Защитить/охлаждать вентиль и продувать азотом", "Только сделать pump down"]}, {"id": 52, "sec": "Fabrication & Installation", "q": "Suction-line insulation is installed to:", "opts": ["Reduce noise only", "Prevent heat gain and sweating on the cold line", "Increase head pressure", "Block sunlight only"], "correct": 1, "re": "Insulating the cold suction line prevents heat gain (efficiency loss) and condensation that drips and causes damage.", "rr": "Изоляция холодной suction-линии предотвращает нагрев (потеря КПД) и конденсат, который капает и портит конструкции.", "qr": "Изоляцию suction-линии ставят, чтобы:", "optsr": ["Только снизить шум", "Не допустить нагрева и конденсата на холодной линии", "Поднять head давление", "Только закрыть от солнца"]}, {"id": 53, "sec": "Fabrication & Installation", "q": "For sheet-metal duct, a lower gauge number means the metal is:", "opts": ["Always galvanized", "The same thickness", "Thicker", "Thinner"], "correct": 2, "re": "Lower gauge = thicker sheet metal. Larger ducts need heavier (lower-gauge) metal and reinforcement per SMACNA.", "rr": "Меньший gauge = более толстый лист. Бóльшие воздуховоды требуют более толстого (меньший gauge) металла и усиления по SMACNA.", "qr": "Для листового металла воздуховода меньший номер gauge означает металл:", "optsr": ["Всегда оцинкованный", "Той же толщины", "Толще", "Тоньше"]}, {"id": 54, "sec": "Fabrication & Installation", "q": "During startup, verifying correct airflow before checking the charge matters because:", "opts": ["It saves refrigerant", "Charge doesn't matter", "Refrigerant readings are only valid at correct airflow", "Airflow has no effect"], "correct": 2, "re": "Pressures, superheat, and subcooling are only meaningful at proper airflow. Confirm airflow/temperature split first, then evaluate and adjust charge.", "rr": "Давления, superheat и subcooling имеют смысл только при правильном воздухопотоке. Сначала подтверждают airflow/temperature split, затем оценивают и корректируют заправку.", "qr": "При пуске сначала проверяют правильный воздухопоток, а потом заправку, потому что:", "optsr": ["Это экономит хладагент", "Заправка не важна", "Показания по хладагенту верны только при правильном воздухопотоке", "Воздухопоток не влияет"]}, {"id": 55, "sec": "TR", "q": "A frozen evaporator coil is most commonly caused by:", "opts": ["Low airflow or low refrigerant charge", "High head pressure only", "Too clean a filter", "Oversized ducts"], "correct": 0, "re": "Restricted airflow (dirty filter/coil, blower issue) or low charge drops coil temperature below freezing, icing it. Diagnose airflow first, then charge.", "rr": "Зажатый воздухопоток (грязный фильтр/змеевик, вентилятор) или нехватка заправки опускают температуру змеевика ниже нуля. Сначала проверяют airflow, потом заправку.", "qr": "Обмерзание испарителя чаще всего вызвано:", "optsr": ["Низким воздухопотоком или нехваткой хладагента", "Только высоким head давлением", "Слишком чистым фильтром", "Слишком большими воздуховодами"]}, {"id": 56, "sec": "TR", "q": "Low refrigerant charge typically produces:", "opts": ["High head pressure", "High suction and low superheat", "Low suction pressure and high superheat", "High subcooling"], "correct": 2, "re": "Undercharge starves the evaporator: low suction, high superheat, low subcooling. Confirm, weigh-in correctly, and find the leak.", "rr": "Недозаправка «душит» испаритель: низкое suction, высокий superheat, низкий subcooling. Подтверждают, дозаправляют по весу и ищут течь.", "qr": "Недозаправка хладагентом обычно даёт:", "optsr": ["Высокое head давление", "Высокое suction и низкий superheat", "Низкое suction давление и высокий superheat", "Высокий subcooling"]}, {"id": 57, "sec": "TR", "q": "An overcharged system most often shows:", "opts": ["Low subcooling", "Low head pressure", "High head pressure and high subcooling", "High superheat"], "correct": 2, "re": "Overcharge backs liquid into the condenser: high head pressure and high subcooling, low superheat. Recover refrigerant to correct the charge.", "rr": "Перезаправка загоняет жидкость в конденсатор: высокое head давление и высокий subcooling, низкий superheat. Откачивают часть хладагента до нормы.", "qr": "Перезаправленная система чаще всего показывает:", "optsr": ["Низкий subcooling", "Низкое head давление", "Высокое head давление и высокий subcooling", "Высокий superheat"]}, {"id": 58, "sec": "TR", "q": "A dirty or blocked outdoor condenser coil will cause:", "opts": ["High head (discharge) pressure", "Low head pressure", "Low amp draw", "A frozen condenser"], "correct": 0, "re": "Poor condenser heat rejection raises head pressure and compressor amps, cuts capacity, and can trip on high pressure. Clean the coil.", "rr": "Плохой отвод тепла конденсатором повышает head давление и ток компрессора, снижает мощность и может выбивать по высокому давлению. Чистят змеевик.", "qr": "Грязный или забитый наружный конденсатор вызовет:", "optsr": ["Высокое head (discharge) давление", "Низкое head давление", "Низкий ток", "Обмерзание конденсатора"]}, {"id": 59, "sec": "TR", "q": "A failed (open) run capacitor on a single-phase compressor will typically cause it to:", "opts": ["Be unaffected", "Have a higher SEER", "Run faster", "Hum, draw high amps, and not start"], "correct": 3, "re": "A failed run/start capacitor prevents starting torque: the motor hums, draws locked-rotor amps, and may trip. Test microfarads against the rating.", "rr": "Неисправный run/start-capacitor лишает пускового момента: мотор гудит, тянет locked-rotor amps и может выбить. Проверяют ёмкость (microfarads) против номинала.", "qr": "Неисправный (обрыв) run-capacitor у однофазного компрессора обычно приводит к тому, что он:", "optsr": ["Не затронут", "Имеет более высокий SEER", "Работает быстрее", "Гудит, тянет высокий ток и не запускается"]}, {"id": 60, "sec": "TR", "q": "A contactor in an air-conditioning condenser functions to:", "opts": ["Drain condensate", "Switch line voltage to the compressor and fan", "Meter refrigerant", "Filter air"], "correct": 1, "re": "The contactor is an electrically operated switch that closes on a 24V call to send line voltage to the compressor and condenser fan. Pitted contacts cause failures.", "rr": "Контактор — электрически управляемый выключатель, который по сигналу 24V подаёт сетевое напряжение на компрессор и вентилятор конденсатора. Подгоревшие контакты дают отказы.", "qr": "Контактор в наружном блоке кондиционера служит для:", "optsr": ["Слива конденсата", "Подачи сетевого напряжения на компрессор и вентилятор", "Дозирования хладагента", "Фильтрации воздуха"]}, {"id": 61, "sec": "TR", "q": "In a heat pump, a stuck reversing valve will cause:", "opts": ["Higher efficiency", "Correct operation", "Frozen condensate", "Failure to switch between heating and cooling, or pressure bypass"], "correct": 3, "re": "A stuck reversing (4-way) valve traps one mode or bypasses high/low sides (pressures equalize). Check the solenoid and the temperature split across the valve ports.", "rr": "Заклинивший reversing (4-ходовой) клапан запирает один режим или перепускает между high/low сторонами (давления выравниваются). Проверяют соленоид и перепад температур на портах клапана.", "qr": "В тепловом насосе заклинивший reversing valve вызовет:", "optsr": ["Более высокий КПД", "Нормальную работу", "Обмерзание конденсата", "Невозможность переключения отопление/охлаждение или перепуск давления"]}, {"id": 62, "sec": "TR", "q": "The purpose of a heat pump's defrost cycle is to:", "opts": ["Cool the house", "Melt frost from the outdoor coil in heating mode", "Charge the system", "Clean the filter"], "correct": 1, "re": "In heating, the outdoor coil collects frost; defrost briefly reverses the cycle (and may energize aux heat) to melt the ice, then returns to heating.", "rr": "В отоплении наружный змеевик покрывается инеем; defrost кратко реверсирует цикл (может включить aux heat), растапливает лёд и возвращается к отоплению.", "qr": "Назначение цикла оттайки (defrost) теплового насоса:", "optsr": ["Охлаждать дом", "Растопить иней с наружного змеевика в режиме отопления", "Заправить систему", "Почистить фильтр"]}, {"id": 63, "sec": "TR", "q": "A large temperature drop across a liquid-line filter-drier usually indicates:", "opts": ["Overcharge", "Normal operation", "Low airflow", "A restriction (clogged drier)"], "correct": 3, "re": "A noticeable temperature drop/sweating across the drier signals a restriction. A restricted drier/metering device starves the evaporator (low suction, high superheat).", "rr": "Заметный перепад/потение на drier — признак засора. Забитый drier/дозатор «душит» испаритель (низкое suction, высокий superheat).", "qr": "Большой перепад температур на liquid-line filter-drier обычно указывает на:", "optsr": ["Перезаправку", "Нормальную работу", "Низкий воздухопоток", "Засор (забитый drier)"]}, {"id": 64, "sec": "TR", "q": "Noncondensable gases (air) in a refrigerant system cause:", "opts": ["Low head pressure", "More subcooling", "Low superheat", "Abnormally high head pressure"], "correct": 3, "re": "Air/noncondensables raise head pressure above the normal saturation value for the temperature. Recover, evacuate to a deep vacuum, and recharge.", "rr": "Воздух/неконденсируемые поднимают head давление выше нормального значения насыщения для данной температуры. Откачивают, тянут глубокий вакуум и заправляют заново.", "qr": "Неконденсируемые газы (воздух) в системе хладагента вызывают:", "optsr": ["Низкое head давление", "Больший subcooling", "Низкий superheat", "Аномально высокое head давление"]}, {"id": 65, "sec": "TR", "q": "A gas furnace that lights but shuts off after a few seconds most likely has a faulty:", "opts": ["Flame sensor/thermocouple not proving flame", "Condensate pump", "Air filter", "Blower wheel"], "correct": 0, "re": "If the flame sensor/thermocouple doesn't prove flame, the control closes the gas valve as a safety. Clean or replace the sensor and verify the microamp signal and ground.", "rr": "Если flame sensor/thermocouple не подтверждает пламя, плата закрывает газовый клапан как защиту. Чистят или меняют датчик, проверяют сигнал в microamp и заземление.", "qr": "Газовая печь зажигается, но гаснет через несколько секунд — вероятнее всего неисправен:", "optsr": ["Flame sensor/thermocouple, не подтверждающий пламя", "Помпа конденсата", "Воздушный фильтр", "Крыльчатка вентилятора"]}, {"id": 66, "sec": "TR", "q": "A hot surface igniter (HSI) that is cracked or open will result in:", "opts": ["No ignition (no heat)", "Continuous heating", "Cooling only", "High head pressure"], "correct": 0, "re": "A cracked/open HSI won't glow, so ignition fails — no heat. Check resistance and for visible cracks; handle without touching the element.", "rr": "Треснувший/оборванный HSI не раскаляется, розжиг не проходит — нет тепла. Проверяют сопротивление и трещины; берут, не касаясь самого элемента.", "qr": "Треснувший или оборванный hot surface igniter (HSI) приведёт к:", "optsr": ["Отсутствию розжига (нет тепла)", "Непрерывному нагреву", "Только охлаждению", "Высокому head давлению"]}, {"id": 67, "sec": "TR", "q": "A furnace rollout or high-limit switch that trips repeatedly indicates:", "opts": ["Normal operation", "Overheating from blocked flue or low airflow", "A dirty condenser", "Low gas pressure only"], "correct": 1, "re": "Limit/rollout trips signal overheating from restricted airflow (dirty filter/coil/blower) or a blocked flue/heat-exchanger problem. Find the root cause — don't just reset.", "rr": "Срабатывания limit/rollout — признак перегрева из-за зажатого воздухопотока (фильтр/змеевик/вентилятор) или забитого дымохода/проблемы теплообменника. Ищут причину, а не просто сбрасывают.", "qr": "Повторное срабатывание rollout или high-limit switch печи указывает на:", "optsr": ["Нормальную работу", "Перегрев из-за забитого дымохода или малого воздухопотока", "Грязный конденсатор", "Только низкое давление газа"]}, {"id": 68, "sec": "TR", "q": "If a furnace inducer runs but the pressure switch won't close, check for:", "opts": ["Low refrigerant", "A dirty evaporator", "A blocked flue/condensate or cracked hose to the switch", "Open windows"], "correct": 2, "re": "The pressure switch proves inducer draft. Failure to close is often a blocked vent/condensate, plugged or cracked sensing hose, or weak inducer — verify before replacing the switch.", "rr": "Pressure switch подтверждает тягу inducer. Несрабатывание часто из-за забитого vent/конденсата, засорённого или треснувшего сигнального шланга или слабого inducer — проверяют до замены реле.", "qr": "Если inducer печи работает, но pressure switch не замыкается, проверяют:", "optsr": ["Нехватку хладагента", "Грязный испаритель", "Забитый дымоход/конденсат или треснувший шланг к реле", "Открытые окна"]}, {"id": 69, "sec": "TR", "q": "An ECM blower motor offers what advantage over a standard PSC motor?", "opts": ["Variable speed and constant-airflow control", "Lower efficiency", "No electronics", "Higher amp draw"], "correct": 0, "re": "ECM (electronically commutated) motors vary speed to maintain target airflow against changing static pressure, improving comfort and efficiency vs. fixed-speed PSC motors.", "rr": "ECM (electronically commutated) меняет скорость, удерживая заданный воздухопоток при меняющемся статическом давлении — лучше комфорт и КПД, чем у PSC с фикс. скоростью.", "qr": "Какое преимущество даёт ECM-двигатель вентилятора по сравнению с обычным PSC?", "optsr": ["Переменная скорость и постоянный воздухопоток", "Меньший КПД", "Отсутствие электроники", "Больший ток"]}, {"id": 70, "sec": "TR", "q": "The best first step to confirm a suspected refrigerant leak is to:", "opts": ["Add refrigerant and hope", "Use an electronic leak detector, bubbles, or UV dye", "Replace the compressor", "Ignore it"], "correct": 1, "re": "Locate the leak with an electronic detector, soap bubbles, or UV dye before repairing. EPA requires repairing significant leaks rather than topping off repeatedly.", "rr": "Сначала находят течь электронным детектором, пузырьками или UV-краской, затем чинят. EPA требует устранять значимые течи, а не доливать снова и снова.", "qr": "Лучший первый шаг при подозрении на течь хладагента:", "optsr": ["Добавить хладагент и надеяться", "Использовать электронный течеискатель, пузырьки или UV-краску", "Поменять компрессор", "Игнорировать"]}, {"id": 71, "sec": "TR", "q": "Measured compressor amperage well above the rated RLA indicates:", "opts": ["A problem such as high head pressure, low voltage, or a mechanical issue", "Correct operation", "An oversized air filter", "Normal light load"], "correct": 0, "re": "Amps above RLA (Rated Load Amps) point to high head pressure, a restricted condenser, low voltage, or a failing compressor. Investigate before it overheats.", "rr": "Ток выше RLA (Rated Load Amps) — признак высокого head давления, забитого конденсатора, низкого напряжения или умирающего компрессора. Разбираются до перегрева.", "qr": "Замеренный ток компрессора заметно выше номинального RLA указывает на:", "optsr": ["Проблему: высокое head давление, низкое напряжение или механику", "Нормальную работу", "Завышенный фильтр", "Нормальную малую нагрузку"]}, {"id": 72, "sec": "TR", "q": "A system with high superheat and low suction pressure most likely has:", "opts": ["An overcharge", "Too much airflow", "An undercharge or a restriction", "A dirty condenser"], "correct": 2, "re": "High superheat + low suction = a starved evaporator, from undercharge or a liquid-line/metering restriction. Check subcooling to distinguish the two.", "rr": "Высокий superheat + низкое suction = «голодный» испаритель из-за недозаправки или засора liquid-line/дозатора. Smотрят subcooling, чтобы отличить одно от другого.", "qr": "Система с высоким superheat и низким suction давлением скорее всего имеет:", "optsr": ["Перезаправку", "Слишком большой воздухопоток", "Недозаправку или засор", "Грязный конденсатор"]}, {"id": 73, "sec": "TR", "q": "A condensate float (safety) switch is designed to:", "opts": ["Increase airflow", "Shut the system off if the drain pan overflows", "Boost the charge", "Defrost the coil"], "correct": 1, "re": "A float switch interrupts the cooling call when condensate backs up, preventing water damage. A tripped float points to a clogged drain or trap.", "rr": "Float switch разрывает вызов охлаждения при переполнении конденсата, предотвращая залив. Сработавший поплавок указывает на забитый дренаж или сифон.", "qr": "Поплавковый (float) выключатель конденсата предназначен, чтобы:", "optsr": ["Увеличить воздухопоток", "Отключить систему при переполнении поддона", "Поднять заправку", "Оттаять змеевик"]}, {"id": 74, "sec": "TR", "q": "In cold weather a heat pump relies on supplemental (auxiliary) heat because:", "opts": ["The reversing valve fails", "It runs in cooling", "Capacity and COP drop as outdoor temperature falls", "The compressor stops"], "correct": 2, "re": "As outdoor temperature drops, a heat pump's capacity and COP decline, so electric or gas auxiliary/backup heat supplements it to meet the load.", "rr": "С падением наружной температуры мощность и COP теплового насоса снижаются, поэтому электрический или газовый auxiliary/backup обогрев его дополняет, чтобы покрыть нагрузку.", "qr": "В холода тепловой насос опирается на доп. (auxiliary) обогрев, потому что:", "optsr": ["Reversing valve отказывает", "Он работает на охлаждение", "Мощность и COP падают со снижением наружной температуры", "Компрессор останавливается"]}, {"id": 75, "sec": "TR", "q": "Low indoor airflow during cooling will typically cause:", "opts": ["No effect on the coil", "High subcooling", "High suction pressure", "Low suction pressure and possible coil freezing"], "correct": 3, "re": "Reduced airflow lowers evaporator load, dropping suction pressure and coil temperature — leading to icing. Check the filter, coil, blower speed, and ducts.", "rr": "Снижение воздухопотока уменьшает нагрузку на испаритель, опуская suction давление и температуру змеевика — отсюда обмерзание. Проверяют фильтр, змеевик, скорость вентилятора и воздуховоды.", "qr": "Низкий воздухопоток в помещении при охлаждении обычно вызывает:", "optsr": ["Нет влияния на змеевик", "Высокий subcooling", "Высокое suction давление", "Низкое suction давление и возможное обмерзание"]}, {"id": 76, "sec": "TR", "q": "Routine maintenance that most improves condenser efficiency is:", "opts": ["Removing the filter", "Adding refrigerant every visit", "Increasing fan speed", "Cleaning the outdoor coil and clearing debris"], "correct": 3, "re": "A clean condenser coil rejects heat properly, lowering head pressure and amp draw. Coil cleaning and clearance around the unit are key maintenance items.", "rr": "Чистый конденсатор нормально отводит тепло, снижая head давление и ток. Чистка змеевика и зазор вокруг агрегата — ключевые пункты обслуживания.", "qr": "Регулярное обслуживание, сильнее всего повышающее эффективность конденсатора:", "optsr": ["Снимать фильтр", "Доливать хладагент каждый визит", "Повышать скорость вентилятора", "Чистить наружный змеевик и убирать мусор"]}, {"id": 77, "sec": "TR", "q": "The recommended interval to inspect/replace a standard 1-inch air filter is roughly:", "opts": ["Every 5 years", "Never", "Only when it disintegrates", "Every 1–3 months"], "correct": 3, "re": "Standard 1-inch filters are checked monthly and replaced every 1–3 months (sooner with pets/dust). Clogged filters restrict airflow and freeze coils.", "rr": "Обычные 1-дюймовые фильтры проверяют ежемесячно и меняют каждые 1–3 месяца (чаще при животных/пыли). Забитые фильтры душат поток и морозят змеевик.", "qr": "Рекомендуемый интервал проверки/замены обычного 1-дюймового фильтра примерно:", "optsr": ["Раз в 5 лет", "Никогда", "Только когда развалится", "Каждые 1–3 месяца"]}, {"id": 78, "sec": "TR", "q": "A 'short cycling' compressor (frequent on/off) can be caused by:", "opts": ["Proper airflow", "A clean filter", "Correct sizing", "Oversized equipment, low charge, or a control/pressure problem"], "correct": 3, "re": "Short cycling stems from oversizing, charge issues, dirty coils tripping safeties, or faulty controls. Diagnose the root cause to protect the compressor.", "rr": "Short cycling возникает из-за oversizing, проблем с заправкой, грязных змеевиков, выбивающих защиты, или неисправных контролей. Ищут причину, чтобы спасти компрессор.", "qr": "Short cycling компрессора (частые вкл/выкл) может быть вызван:", "optsr": ["Нормальным воздухопотоком", "Чистым фильтром", "Правильным подбором", "Завышенным оборудованием, недозаправкой или проблемой контроля/давления"]}, {"id": 79, "sec": "Safety & Field Practices", "q": "Lockout/tagout (LOTO) procedures are required to:", "opts": ["Test capacitors", "Prevent accidental energizing of equipment during service", "Speed up work", "Improve efficiency"], "correct": 1, "re": "Cal/OSHA LOTO (Title 8) requires de-energizing and locking/tagging energy sources before service so equipment can't start unexpectedly and injure the worker.", "rr": "Cal/OSHA LOTO (Title 8) требует обесточить и заблокировать/обозначить источники энергии до обслуживания, чтобы оборудование не запустилось внезапно и не травмировало работника.", "qr": "Процедуры lockout/tagout (LOTO) нужны, чтобы:", "optsr": ["Проверить конденсаторы", "Не допустить случайной подачи питания при обслуживании", "Ускорить работу", "Повысить КПД"]}, {"id": 80, "sec": "Safety & Field Practices", "q": "Before working inside a disconnected condenser, a technician should still:", "opts": ["Add refrigerant", "Run the fan", "Assume it's safe", "Discharge the capacitor and verify zero voltage"], "correct": 3, "re": "Capacitors store a lethal charge after power is off. Discharge them safely and verify the absence of voltage with a meter before touching terminals.", "rr": "Конденсаторы хранят смертельный заряд и после снятия питания. Их безопасно разряжают и проверяют отсутствие напряжения прибором до касания клемм.", "qr": "Перед работой внутри обесточенного конденсатора техник всё равно должен:", "optsr": ["Добавить хладагент", "Запустить вентилятор", "Считать, что безопасно", "Разрядить конденсатор и проверить отсутствие напряжения"]}, {"id": 81, "sec": "Safety & Field Practices", "q": "Appropriate eye protection when brazing is:", "opts": ["Shaded brazing goggles", "No protection", "Sunglasses only", "A dust mask"], "correct": 0, "re": "Brazing produces intense light and heat; shaded brazing goggles (plus gloves and ventilation) protect the eyes from glare and sparks.", "rr": "Brazing даёт яркий свет и жар; затемнённые очки для пайки (плюс перчатки и вентиляция) защищают глаза от блеска и искр.", "qr": "Подходящая защита глаз при brazing:", "optsr": ["Затемнённые очки для пайки", "Без защиты", "Только солнцезащитные очки", "Пылевая маска"]}, {"id": 82, "sec": "Safety & Field Practices", "q": "Refrigerant leaking into a confined, unventilated space is dangerous mainly because it can:", "opts": ["Raise humidity", "Displace oxygen and cause asphyxiation", "Increase outdoor pressure", "Improve air quality"], "correct": 1, "re": "Most refrigerants are heavier than air and can displace oxygen in low/confined spaces, causing asphyxiation. Ensure ventilation and follow the SDS.", "rr": "Большинство хладагентов тяжелее воздуха и вытесняют кислород в низких/замкнутых местах, вызывая удушье. Обеспечивают вентиляцию и следуют SDS.", "qr": "Утечка хладагента в замкнутое непроветриваемое пространство опасна в основном тем, что может:", "optsr": ["Повысить влажность", "Вытеснить кислород и вызвать удушье", "Повысить наружное давление", "Улучшить качество воздуха"]}, {"id": 83, "sec": "Safety & Field Practices", "q": "A2L refrigerants such as R-32 and R-454B are classified as:", "opts": ["Mildly flammable, lower toxicity", "Nonflammable", "Explosive like propane", "Highly toxic"], "correct": 0, "re": "A2L refrigerants are mildly flammable (lower flammability) and low toxicity. Follow equipment listings, leak detection/mitigation, and use no open flames during service.", "rr": "A2L — слабогорючие (низкая горючесть) и малотоксичные. Соблюдают листинги оборудования, детекцию/митигацию утечек и не используют открытый огонь при обслуживании.", "qr": "Хладагенты A2L, такие как R-32 и R-454B, классифицируются как:", "optsr": ["Слабогорючие, низкой токсичности", "Негорючие", "Взрывоопасные как пропан", "Высокотоксичные"]}, {"id": 84, "sec": "Safety & Field Practices", "q": "The correct way to confirm a circuit is de-energized before service is to:", "opts": ["Use a properly rated meter (test-known-test)", "Touch the wires", "Listen for humming", "Ask a coworker"], "correct": 0, "re": "Verify zero voltage with a rated meter using the test-known-live-test method. Never rely on a breaker label alone before contacting conductors.", "rr": "Проверяют отсутствие напряжения прибором нужного класса методом «проверь-на-известном-проверь». Нельзя полагаться только на надпись автомата перед касанием проводников.", "qr": "Правильный способ убедиться, что цепь обесточена перед работой:", "optsr": ["Использовать прибор нужного класса (test-known-test)", "Потрогать провода", "Слушать гудение", "Спросить коллегу"]}, {"id": 85, "sec": "Safety & Field Practices", "q": "Portable electric tools used outdoors or in damp areas should be protected by a:", "opts": ["GFCI", "Transformer only", "Surge strip", "Larger fuse"], "correct": 0, "re": "A GFCI (ground-fault circuit interrupter) trips on small ground-fault currents, preventing electrocution in wet/outdoor conditions — required by Cal/OSHA and NEC.", "rr": "GFCI (ground-fault circuit interrupter) срабатывает на малые токи утечки на землю, предотвращая поражение во влажных/наружных условиях — требуется Cal/OSHA и NEC.", "qr": "Переносной электроинструмент на улице или во влажных местах должен защищаться:", "optsr": ["GFCI", "Только трансформатором", "Сетевым фильтром", "Бóльшим предохранителем"]}, {"id": 86, "sec": "Safety & Field Practices", "q": "A straight (extension) ladder should be set at a base-to-height ratio of about:", "opts": ["1:1", "1:4", "1:20", "1:10"], "correct": 1, "re": "The 4-to-1 rule: place the base 1 ft out for every 4 ft of working height. Use the proper duty rating and secure/tie off the ladder.", "rr": "Правило 4-к-1: основание отодвигают на 1 фут на каждые 4 фута рабочей высоты. Используют нужный класс нагрузки и фиксируют лестницу.", "qr": "Прямую (раздвижную) лестницу ставят с соотношением основание-к-высоте примерно:", "optsr": ["1:1", "1:4", "1:20", "1:10"]}, {"id": 87, "sec": "Safety & Field Practices", "q": "Compressed-gas cylinders (refrigerant or nitrogen) must be:", "opts": ["Secured upright and kept away from heat sources", "Laid on their side near heat", "Left uncapped while moved", "Filled to 100%"], "correct": 0, "re": "Cylinders are secured upright with the cap on when moved, kept below ~125°F, and never overfilled (refrigerant ≤80%) to prevent rupture.", "rr": "Баллоны закрепляют вертикально с колпачком при перемещении, держат ниже ~125°F и никогда не переполняют (хладагент ≤80%), чтобы не разорвало.", "qr": "Баллоны со сжатым газом (хладагент или nitrogen) должны быть:", "optsr": ["Закреплены вертикально и вдали от тепла", "Положены набок у источника тепла", "Без колпачка при перемещении", "Заполнены на 100%"]}, {"id": 88, "sec": "Safety & Field Practices", "q": "A pressurized nitrogen cylinder must always be used with a:", "opts": ["Torch", "Pressure regulator", "No regulator", "Vacuum pump"], "correct": 1, "re": "Nitrogen is stored at very high pressure; a regulator reduces it to a safe working pressure. Never pressure-test a system above its rated test pressure.", "rr": "Азот хранится под очень высоким давлением; регулятор снижает его до безопасного рабочего. Систему нельзя опрессовывать выше её допустимого test pressure.", "qr": "Баллон со сжатым азотом (nitrogen) всегда используют с:", "optsr": ["Горелкой", "Регулятором давления", "Без регулятора", "Вакуумным насосом"]}, {"id": 89, "sec": "Safety & Field Practices", "q": "Venting CFC/HCFC/HFC refrigerant to the atmosphere during service is:", "opts": ["Required", "Only illegal indoors", "Allowed in small amounts", "Prohibited under the Clean Air Act (EPA 608)"], "correct": 3, "re": "EPA Section 608 prohibits knowingly venting refrigerants. Technicians must recover refrigerant with certified equipment and hold EPA 608 certification.", "rr": "EPA Section 608 запрещает осознанный выпуск хладагентов. Техник обязан откачивать хладагент сертифицированным оборудованием и иметь сертификат EPA 608.", "qr": "Выпуск хладагента CFC/HCFC/HFC в атмосферу при обслуживании:", "optsr": ["Обязателен", "Незаконен только внутри помещений", "Разрешён в малых количествах", "Запрещён по Clean Air Act (EPA 608)"]}, {"id": 90, "sec": "Safety & Field Practices", "q": "Carbon monoxide (CO) from incomplete combustion is dangerous because it is:", "opts": ["Harmless outdoors", "Visible and smelly", "Colorless, odorless, and toxic", "Heavier than refrigerant"], "correct": 2, "re": "CO is colorless and odorless and binds hemoglobin, causing poisoning. Proper combustion air, venting, and a CO detector are essential; investigate any spillage.", "rr": "CO бесцветен и без запаха, связывает гемоглобин и вызывает отравление. Нужны достаточный воздух для горения, тяга и CO-детектор; любой spillage расследуют.", "qr": "Угарный газ (CO) от неполного сгорания опасен тем, что он:", "optsr": ["Безвреден на улице", "Видимый и пахучий", "Бесцветный, без запаха и токсичный", "Тяжелее хладагента"]}, {"id": 91, "sec": "Safety & Field Practices", "q": "A Safety Data Sheet (SDS) provides information on:", "opts": ["Equipment SEER", "Duct sizing", "Hazards, handling, and first aid for a chemical", "Warranty terms"], "correct": 2, "re": "Under HazCom, an SDS lists a product's hazards, safe handling, PPE, first aid, and emergency measures. It must be accessible to workers on the job.", "rr": "По HazCom SDS перечисляет опасности продукта, безопасное обращение, PPE, первую помощь и аварийные меры. Он должен быть доступен работникам на объекте.", "qr": "Safety Data Sheet (SDS) содержит информацию о:", "optsr": ["SEER оборудования", "Подборе воздуховодов", "Опасностях, обращении и первой помощи по химвеществу", "Условиях гарантии"]}, {"id": 92, "sec": "Safety & Field Practices", "q": "Cal/OSHA's Heat Illness Prevention standard requires employers to provide:", "opts": ["Only overtime pay", "Extra refrigerant", "Water, shade, rest, and training", "Nothing outdoors"], "correct": 2, "re": "Cal/OSHA's Heat Illness Prevention standard (Title 8 §3395) requires drinking water, shade for rest, rest breaks, training, and acclimatization for outdoor work.", "rr": "Стандарт Cal/OSHA Heat Illness Prevention (Title 8 §3395) требует питьевую воду, тень для отдыха, перерывы, обучение и акклиматизацию при работе на улице.", "qr": "Стандарт Cal/OSHA по профилактике теплового удара требует от работодателя обеспечить:", "optsr": ["Только оплату сверхурочных", "Дополнительный хладагент", "Воду, тень, отдых и обучение", "Ничего на улице"]}, {"id": 93, "sec": "Safety & Field Practices", "q": "The correct fire extinguisher class for an energized electrical fire is:", "opts": ["Class A", "Class D", "Class C", "Class B"], "correct": 2, "re": "Class C extinguishers are rated for energized electrical equipment (non-conductive agent). Class A = ordinary combustibles, B = flammable liquids, D = metals.", "rr": "Огнетушители Class C рассчитаны на электрооборудование под напряжением (непроводящий состав). Class A — обычные горючие, B — горючие жидкости, D — металлы.", "qr": "Правильный класс огнетушителя для пожара под напряжением:", "optsr": ["Class A", "Class D", "Class C", "Class B"]}, {"id": 94, "sec": "Safety & Field Practices", "q": "Before disturbing suspect old pipe or duct insulation that may contain asbestos, the technician should:", "opts": ["Vacuum it with a shop vac", "Burn it", "Stop and have it tested/handled by qualified personnel", "Cut it freely"], "correct": 2, "re": "Disturbing asbestos releases hazardous fibers. Suspect materials must be tested and handled per regulations by trained/certified personnel — not by untrained workers.", "rr": "Нарушение asbestos высвобождает опасные волокна. Подозрительные материалы тестируют и обрабатывают по нормам обученные/сертифицированные люди — не неподготовленные работники.", "qr": "Перед тем как тронуть старую изоляцию труб/воздуховодов, возможно содержащую asbestos, техник должен:", "optsr": ["Пропылесосить shop-vac'ом", "Сжечь её", "Остановиться и поручить тест/работу квалифицированным специалистам", "Резать свободно"]}, {"id": 95, "sec": "Safety & Field Practices", "q": "When entering a confined space such as a crawlspace or tank, the first thing to test for is:", "opts": ["Oxygen level and a hazardous/toxic atmosphere", "Wi-Fi signal", "Noise", "Paint color"], "correct": 0, "re": "Confined spaces require atmospheric testing (oxygen, flammable, toxic) and a permit/procedure before entry, since oxygen deficiency or toxic gases can be fatal.", "rr": "Замкнутые пространства требуют замера атмосферы (кислород, горючее, токсины) и разрешения/процедуры до входа, т.к. нехватка кислорода или токсичные газы смертельны.", "qr": "При входе в замкнутое пространство (подполье, бак) в первую очередь проверяют:", "optsr": ["Уровень кислорода и опасную/токсичную атмосферу", "Сигнал Wi-Fi", "Шум", "Цвет краски"]}, {"id": 96, "sec": "Safety & Field Practices", "q": "Proper PPE when handling liquid refrigerant includes:", "opts": ["Shorts", "Open-toe shoes", "No gloves", "Safety glasses and gloves to prevent frostbite/eye injury"], "correct": 3, "re": "Liquid refrigerant can cause frostbite and eye injury. Wear safety glasses and gloves and work in a ventilated area per the SDS.", "rr": "Жидкий хладагент вызывает обморожение и травмы глаз. Надевают защитные очки и перчатки, работают в проветриваемом месте по SDS.", "qr": "Правильный PPE при работе с жидким хладагентом включает:", "optsr": ["Шорты", "Открытую обувь", "Без перчаток", "Защитные очки и перчатки против обморожения/травмы глаз"]}, {"id": 97, "sec": "Safety & Field Practices", "q": "Fall protection considerations under Cal/OSHA apply when working:", "opts": ["At elevated heights and roof edges per Cal/OSHA thresholds", "Only on ladders", "Only above 50 ft", "Never on residential jobs"], "correct": 0, "re": "Cal/OSHA requires fall protection at defined heights (e.g., roof edges, elevated platforms). Use guardrails, personal fall arrest, or other approved methods per Title 8.", "rr": "Cal/OSHA требует защиту от падения на установленных высотах (края крыш, поднятые площадки). Применяют ограждения, страховочные системы (PFAS) или иные одобренные методы по Title 8.", "qr": "Защита от падения по Cal/OSHA применяется при работе:", "optsr": ["На высоте и у краёв крыши по порогам Cal/OSHA", "Только на лестницах", "Только выше 50 футов", "Никогда на жилых объектах"]}, {"id": 98, "sec": "Safety & Field Practices", "q": "Cutting or grinding materials that produce silica dust requires:", "opts": ["Only gloves", "More refrigerant", "Dust controls and respiratory protection", "No precautions"], "correct": 2, "re": "Respirable crystalline silica is a serious health hazard; Cal/OSHA requires water/dust controls and respiratory protection when cutting concrete, masonry, etc.", "rr": "Вдыхаемый кристаллический silica — серьёзная опасность для здоровья; Cal/OSHA требует водяное/пылевое подавление и респираторную защиту при резке бетона, кладки и т.п.", "qr": "Резка или шлифовка материалов, дающих кремнеземную (silica) пыль, требует:", "optsr": ["Только перчаток", "Больше хладагента", "Пылеподавления и защиты органов дыхания", "Никаких мер"]}, {"id": 99, "sec": "Safety & Field Practices", "q": "When servicing rooftop equipment, the technician should be most aware of:", "opts": ["The SEER rating", "Paint", "Filter size", "Roof edges, skylights, and fall/heat hazards"], "correct": 3, "re": "Rooftop work adds fall hazards (edges, skylights), heat exposure, and electrical/refrigerant hazards. Plan access, fall protection, and heat-illness measures.", "rr": "Работа на крыше добавляет риски падения (края, световые люки), жару и электро/хладагентные опасности. Планируют доступ, защиту от падения и меры против теплового удара.", "qr": "При обслуживании оборудования на крыше техник в первую очередь учитывает:", "optsr": ["Рейтинг SEER", "Краску", "Размер фильтра", "Края крыши, световые люки и опасности падения/жары"]}, {"id": 100, "sec": "Safety & Field Practices", "q": "The first action if liquid refrigerant contacts the skin (frostbite) is to:", "opts": ["Apply direct heat", "Ignore it", "Rub vigorously", "Flush with plenty of lukewarm water and seek medical care"], "correct": 3, "re": "For refrigerant frostbite, flush with plenty of lukewarm (not hot) water, do not rub, protect the area, and get medical attention per the SDS.", "rr": "При обморожении хладагентом промывают большим количеством тёплой (не горячей) воды, не растирают, защищают участок и обращаются за медпомощью по SDS.", "qr": "Первое действие при попадании жидкого хладагента на кожу (обморожение):", "optsr": ["Приложить прямой жар", "Игнорировать", "Энергично растереть", "Промыть большим количеством тёплой воды и обратиться к врачу"]}, {"id": 101, "sec": "Principles & Load Calculations", "q": "On a psychrometric chart, the wet-bulb temperature lines are used primarily to determine:", "opts": ["Air velocity", "Total heat content (enthalpy)", "Duct size", "Refrigerant charge"], "correct": 1, "re": "Wet-bulb temperature relates directly to enthalpy (total heat). Lines of constant wet-bulb run nearly parallel to enthalpy lines on the psychrometric chart.", "rr": "Wet-bulb напрямую связан с enthalpy (полным теплом); линии постоянного wet-bulb идут почти параллельно линиям enthalpy.", "qr": "На психрометрической диаграмме линии температуры по мокрому термометру (wet-bulb) служат прежде всего для определения:", "optsr": ["Скорости воздуха", "Полного теплосодержания (enthalpy)", "Размера воздуховода", "Заправки хладагентом"]}, {"id": 102, "sec": "Principles & Load Calculations", "q": "The sensible heat ratio (SHR) of a cooling load is the ratio of:", "opts": ["Total to sensible heat", "Latent to total heat", "Sensible to total heat", "Airflow to load"], "correct": 2, "re": "SHR = sensible heat ÷ total (sensible + latent) heat. A lower SHR means more moisture removal is required from the equipment.", "rr": "SHR = sensible ÷ total (sensible + latent). Чем ниже SHR, тем больше влаги должно удалять оборудование.", "qr": "Коэффициент явного тепла (SHR) охлаждающей нагрузки — это отношение:", "optsr": ["Полного к явному теплу", "Скрытого к полному теплу", "Явного к полному теплу", "Расхода воздуха к нагрузке"]}, {"id": 103, "sec": "Principles & Load Calculations", "q": "ACCA Manual D is used to:", "opts": ["Calculate the heat load", "Design and size the duct system", "Select the thermostat", "Size the equipment"], "correct": 1, "re": "Manual D is the residential duct-design standard: it sizes ducts based on the available static pressure (friction rate) and required airflow.", "rr": "Manual D — стандарт проектирования воздуховодов: рассчитывает дакты по доступному статическому давлению (friction rate) и нужному расходу.", "qr": "ACCA Manual D применяется для:", "optsr": ["Расчёта тепловой нагрузки", "Проектирования и расчёта воздуховодов", "Выбора термостата", "Подбора оборудования"]}, {"id": 104, "sec": "Principles & Load Calculations", "q": "In Manual D, the friction rate is determined from the available static pressure and the:", "opts": ["Roof slope", "Total equivalent length of the longest run", "Number of registers", "Refrigerant type"], "correct": 1, "re": "Friction rate = (available static pressure × 100) ÷ total effective length of the longest supply-and-return run, including fitting equivalent lengths.", "rr": "Friction rate = (доступное статическое × 100) ÷ полная эффективная длина самого длинного участка подачи+обратки, включая эквив. длины фитингов.", "qr": "В Manual D friction rate определяется по доступному статическому давлению и:", "optsr": ["Уклону крыши", "Полной эквивалентной длине самого длинного участка", "Числу решёток", "Типу хладагента"]}, {"id": 105, "sec": "Principles & Load Calculations", "q": "ACCA Manual S is used to:", "opts": ["Design ventilation", "Calculate heat loss", "Select equipment to match the Manual J load", "Size ductwork"], "correct": 2, "re": "Manual S selects equipment so that its sensible and latent capacity (at design conditions) matches the Manual J load, limiting oversizing.", "rr": "Manual S подбирает оборудование так, чтобы его sensible и latent производительность (при расчётных условиях) соответствовала нагрузке Manual J, ограничивая завышение.", "qr": "ACCA Manual S применяется для:", "optsr": ["Проектирования вентиляции", "Расчёта теплопотерь", "Подбора оборудования под нагрузку Manual J", "Расчёта воздуховодов"]}, {"id": 106, "sec": "Principles & Load Calculations", "q": "Per Manual S, cooling equipment should generally not be oversized beyond about what percentage of the design cooling load?", "opts": ["115% (15% over) for AC", "200%", "15% over", "No limit"], "correct": 0, "re": "Manual S typically limits AC sizing to about 115% of the design sensible load (and up to ~125% for heat pumps in some cases) to maintain dehumidification and efficiency.", "rr": "Manual S обычно ограничивает подбор AC примерно 115% расчётной sensible-нагрузки (до ~125% для тепловых насосов в части случаев) ради осушения и КПД.", "qr": "Согласно Manual S, охлаждающее оборудование, как правило, не завышают сверх примерно какого процента расчётной нагрузки?", "optsr": ["115% (на 15% выше) для AC", "200%", "На 15%", "Без ограничения"]}, {"id": 107, "sec": "Principles & Load Calculations", "q": "A common residential design airflow target for a cooling system is approximately:", "opts": ["50 CFM per ton", "400 CFM per ton", "100 CFM per ton", "1200 CFM per ton"], "correct": 1, "re": "The standard design airflow for comfort cooling is about 400 CFM per ton (350–450 CFM/ton range), adjusted for climate humidity.", "rr": "Стандартный расчётный расход для комфортного охлаждения — около 400 CFM на тонну (диапазон 350–450), с поправкой на влажность климата.", "qr": "Типовой расчётный расход воздуха для жилого охлаждения составляет примерно:", "optsr": ["50 CFM на тонну", "400 CFM на тонну", "100 CFM на тонну", "1200 CFM на тонну"]}, {"id": 108, "sec": "Principles & Load Calculations", "q": "In dry desert climates, design airflow is often raised toward 450 CFM/ton, while in humid climates it may be lowered toward 350 CFM/ton in order to:", "opts": ["Lower the SEER", "Increase noise", "Reduce wire size", "Balance sensible vs latent removal"], "correct": 3, "re": "Higher airflow boosts sensible capacity (dry climates); lower airflow increases latent (moisture) removal needed in humid climates.", "rr": "Больший расход повышает sensible (сухой климат); меньший расход усиливает удаление latent (влаги), нужное во влажном климате.", "qr": "В сухом климате расчётный расход часто поднимают к 450 CFM/тонна, а во влажном снижают к 350 CFM/тонна, чтобы:", "optsr": ["Снизить SEER", "Увеличить шум", "Уменьшить сечение провода", "Сбалансировать удаление явного и скрытого тепла"]}, {"id": 109, "sec": "Principles & Load Calculations", "q": "The 'design temperature difference' in a heating load calculation is the difference between:", "opts": ["Wet and dry bulb", "Two adjacent rooms", "Supply and return air", "Indoor design temp and outdoor design temp"], "correct": 3, "re": "Heating design ΔT = indoor design temperature minus the 99% winter outdoor design temperature for the location (from Manual J tables / ASHRAE data).", "rr": "Расчётный ΔT отопления = внутренняя расчётная температура минус 99% зимняя наружная расчётная температура для местности (таблицы Manual J / ASHRAE).", "qr": "«Расчётная разность температур» в расчёте отопительной нагрузки — это разница между:", "optsr": ["Мокрым и сухим термометром", "Двумя соседними комнатами", "Подачей и обраткой", "Внутренней и наружной расчётной температурой"]}, {"id": 110, "sec": "Principles & Load Calculations", "q": "Latent heat load in a building comes primarily from:", "opts": ["Lighting", "Moisture sources (people, cooking, infiltration)", "Sunlight through windows", "Wall conduction"], "correct": 1, "re": "Latent load is moisture: occupants, cooking, showers, plants, and humid infiltration/ventilation air. Solar, conduction and lighting are sensible loads.", "rr": "Latent — это влага: люди, готовка, душ, растения, влажный приточный/инфильтрационный воздух. Солнце, теплопроводность и свет — sensible.", "qr": "Скрытая (latent) нагрузка в здании возникает в основном от:", "optsr": ["Освещения", "Источников влаги (люди, готовка, инфильтрация)", "Солнца через окна", "Теплопроводности стен"]}, {"id": 111, "sec": "Principles & Load Calculations", "q": "When reading a psychrometric chart, the dew-point temperature is found by following a horizontal line to the saturation curve from the:", "opts": ["Dry-bulb axis", "Enthalpy scale", "Humidity ratio (moisture content)", "CFM scale"], "correct": 2, "re": "Dew point corresponds to the humidity ratio: move horizontally (constant moisture content) left to the 100% saturation curve to read dew-point temperature.", "rr": "Dew point соответствует humidity ratio: двигаясь горизонтально (постоянное влагосодержание) влево к кривой 100% насыщения, читаем точку росы.", "qr": "На психрометрической диаграмме температура точки росы (dew point) находится движением по горизонтали к кривой насыщения от:", "optsr": ["Оси сухого термометра", "Шкалы enthalpy", "Влагосодержания (humidity ratio)", "Шкалы CFM"]}, {"id": 112, "sec": "Principles & Load Calculations", "q": "A ductulator is a tool used to relate duct size, airflow, friction loss, and:", "opts": ["Air velocity", "Voltage", "Refrigerant pressure", "Flame temperature"], "correct": 0, "re": "A ductulator (round/rectangular slide chart) relates CFM, friction rate per 100 ft, duct dimension, and velocity for duct sizing.", "rr": "Ductulator (круглая/прямоугольная линейка) связывает CFM, friction rate на 100 футов, размер дакта и скорость для подбора воздуховодов.", "qr": "Ductulator — инструмент, связывающий размер воздуховода, расход, потери на трение и:", "optsr": ["Скорость воздуха", "Напряжение", "Давление хладагента", "Температуру пламени"]}, {"id": 113, "sec": "Principles & Load Calculations", "q": "Infiltration in a load calculation refers to:", "opts": ["Unintended air leakage through the building envelope", "Oil in the compressor", "Water in the duct", "Refrigerant leaking"], "correct": 0, "re": "Infiltration is uncontrolled outdoor air leaking through cracks, gaps and openings, adding both sensible and latent load.", "rr": "Инфильтрация — неконтролируемый наружный воздух через щели, зазоры и проёмы, добавляющий и sensible, и latent нагрузку.", "qr": "Инфильтрация в расчёте нагрузки — это:", "optsr": ["Неконтролируемая утечка воздуха через ограждения здания", "Масло в компрессоре", "Вода в воздуховоде", "Утечка хладагента"]}, {"id": 114, "sec": "Principles & Load Calculations", "q": "Manual J design uses the 1% cooling and 99% heating outdoor design temperatures, which means the equipment is sized for:", "opts": ["Near-extreme but typical seasonal conditions", "Indoor temperature only", "The absolute record extremes", "Average annual temperature"], "correct": 0, "re": "The 1%/99% values are exceeded only ~1% of the time, so sizing to true record extremes would oversize the system most of the year.", "rr": "Значения 1%/99% превышаются лишь ~1% времени; подбор под истинные рекорды завысил бы систему большую часть года.", "qr": "Manual J использует расчётные наружные температуры 1% (охлаждение) и 99% (отопление), то есть оборудование подбирается под:", "optsr": ["Близкие к экстремальным, но типичные сезонные условия", "Только внутреннюю температуру", "Абсолютные рекордные экстремумы", "Среднегодовую температуру"]}, {"id": 115, "sec": "Principles & Load Calculations", "q": "Duct gain/loss in an unconditioned attic is reduced primarily by:", "opts": ["Higher voltage", "Sealing and insulating the ducts", "Larger registers", "More refrigerant"], "correct": 1, "re": "Sealing leaks (mastic) and insulating ducts (e.g., R-8) cuts conductive and leakage losses through hot/cold unconditioned spaces.", "rr": "Герметизация (mastic) и утепление дактов (например R-8) уменьшают потери теплопроводностью и через утечки в жарких/холодных неотапливаемых зонах.", "qr": "Теплопотери/теплопритоки воздуховодов в неотапливаемом чердаке снижаются прежде всего за счёт:", "optsr": ["Более высокого напряжения", "Герметизации и утепления воздуховодов", "Бо́льших решёток", "Большего количества хладагента"]}, {"id": 116, "sec": "Principles & Load Calculations", "q": "For residential ventilation, ASHRAE Standard 62.2 specifies a minimum amount of:", "opts": ["Mechanical fresh-air ventilation based on floor area and occupants", "Compressor oil", "Refrigerant per ton", "Duct insulation"], "correct": 0, "re": "ASHRAE 62.2 sets a whole-house mechanical ventilation rate from floor area and number of bedrooms/occupants to ensure indoor air quality.", "rr": "ASHRAE 62.2 задаёт расход механической вентиляции всего дома по площади и числу спален/жильцов для качества воздуха.", "qr": "Для жилой вентиляции стандарт ASHRAE 62.2 задаёт минимум:", "optsr": ["Механической приточной вентиляции по площади и числу жильцов", "Масла компрессора", "Хладагента на тонну", "Изоляции воздуховодов"]}, {"id": 117, "sec": "Principles & Load Calculations", "q": "A blower's external static pressure (ESP) rating represents the static pressure it can overcome across:", "opts": ["The duct system, coil, and filter combined", "The refrigerant lines", "The compressor", "Only the filter"], "correct": 0, "re": "ESP is the total static the blower must work against — supply ducts, return ducts, coil, filter, and registers — at the rated airflow.", "rr": "ESP — суммарное статическое, против которого работает вентилятор: подача, обратка, испаритель, фильтр и решётки при номинальном расходе.", "qr": "Внешнее статическое давление (ESP) вентилятора — это давление, которое он преодолевает по:", "optsr": ["Системе воздуховодов, испарителю и фильтру вместе", "Линиям хладагента", "Компрессору", "Только фильтру"]}, {"id": 118, "sec": "Principles & Load Calculations", "q": "When estimating a job, the difference between 'direct' and 'overhead' costs is that overhead includes:", "opts": ["Costs not tied to one specific job (office, insurance, trucks)", "Refrigerant only", "Materials installed in the job", "Permit fees only"], "correct": 0, "re": "Direct costs are job-specific (material, labor on that job); overhead is ongoing business cost spread across all jobs (rent, insurance, vehicles, admin).", "rr": "Прямые затраты — по объекту (материал, труд на нём); накладные — постоянные расходы бизнеса на все объекты (аренда, страховка, авто, администрирование).", "qr": "При составлении сметы разница между «прямыми» и «накладными» расходами в том, что накладные включают:", "optsr": ["Затраты, не привязанные к одному объекту (офис, страховка, машины)", "Только хладагент", "Материалы, установленные на объекте", "Только пошлины за разрешение"]}, {"id": 119, "sec": "Principles & Load Calculations", "q": "A heat pump's supplemental (auxiliary) heat must be sized to cover:", "opts": ["The heating load not met by the heat pump below the balance point", "The duct loss only", "The cooling load", "The latent load only"], "correct": 0, "re": "Below the balance point the heat pump can't meet the full heating load, so auxiliary heat (often electric strips) covers the shortfall down to design temp.", "rr": "Ниже точки баланса насос не покрывает полную отопительную нагрузку, поэтому aux-нагрев (часто ТЭНы) добирает разницу до расчётной температуры.", "qr": "Дополнительный (auxiliary) нагрев теплового насоса подбирается, чтобы покрыть:", "optsr": ["Отопительную нагрузку, не покрываемую насосом ниже точки баланса", "Только потери воздуховодов", "Охлаждающую нагрузку", "Только скрытую нагрузку"]}, {"id": 120, "sec": "Principles & Load Calculations", "q": "The 'balance point' of a heat pump is the outdoor temperature at which:", "opts": ["Heat pump output exactly equals the building heat loss", "Defrost begins", "The compressor fails", "The SEER is highest"], "correct": 0, "re": "At the balance point, the heat pump's declining capacity equals the building's rising heat loss; below it, supplemental heat is needed.", "rr": "В точке баланса падающая производительность насоса равна растущим теплопотерям здания; ниже неё нужен дополнительный нагрев.", "qr": "«Точка баланса» теплового насоса — это наружная температура, при которой:", "optsr": ["Отдача насоса точно равна теплопотерям здания", "Начинается разморозка", "Компрессор выходит из строя", "SEER максимален"]}, {"id": 121, "sec": "Principles & Load Calculations", "q": "To convert sensible heat removed to required CFM, the standard formula uses the constant 1.08 with:", "opts": ["Voltage", "ΔT and CFM", "Wet-bulb only", "Refrigerant subcooling"], "correct": 1, "re": "Sensible heat (BTU/h) = 1.08 × CFM × ΔT (dry-bulb temperature difference) at standard air conditions.", "rr": "Sensible (BTU/ч) = 1.08 × CFM × ΔT (разность по сухому термометру) при стандартных условиях воздуха.", "qr": "Чтобы связать удаляемое явное тепло с нужным CFM, стандартная формула использует коэффициент 1.08 совместно с:", "optsr": ["Напряжением", "ΔT и CFM", "Только мокрым термометром", "Subcooling хладагента"]}, {"id": 122, "sec": "Principles & Load Calculations", "q": "In a load calculation, north-facing windows generally contribute ___ solar heat gain than west-facing windows.", "opts": ["Less", "No window gain exists", "More", "Identical"], "correct": 0, "re": "West-facing glass receives intense low-angle afternoon sun (peak cooling time), so it gains far more solar heat than north glass.", "rr": "Западное остекление получает интенсивное низкое послеполуденное солнце (пик нагрузки), поэтому даёт гораздо больше теплопритока, чем северное.", "qr": "В расчёте нагрузки окна, выходящие на север, дают ___ солнечного теплопритока, чем окна на запад.", "optsr": ["Меньше", "Окна не дают притока", "Больше", "Одинаково"]}, {"id": 123, "sec": "Principles & Load Calculations", "q": "A 'manual takeoff' during estimating refers to:", "opts": ["Pumping down refrigerant", "Removing old equipment", "Shutting off the gas", "Counting/listing all materials and quantities from the plans"], "correct": 3, "re": "A takeoff is itemizing every fitting, length of duct/pipe, register, and unit from the drawings to build an accurate material list and bid.", "rr": "Takeoff — перечисление каждого фитинга, длины дакта/трубы, решётки и блока по чертежам, чтобы составить точный список материалов и заявку.", "qr": "«Takeoff» (выборка) при составлении сметы — это:", "optsr": ["Откачка хладагента", "Демонтаж старого оборудования", "Отключение газа", "Подсчёт и перечень всех материалов и количеств по чертежам"]}, {"id": 124, "sec": "Principles & Load Calculations", "q": "Selecting a furnace, the output capacity (not input) should be matched to the heating load because output reflects:", "opts": ["The SEER", "Heat actually delivered after combustion efficiency (AFUE)", "The gas line size", "The filter size"], "correct": 1, "re": "Input × AFUE = output (delivered heat). The building heat-loss load must be met by output BTU/h, not the higher input rating.", "rr": "Input × AFUE = output (отданное тепло). Теплопотери здания должны покрываться выходными BTU/ч, а не более высоким input.", "qr": "При подборе печи под нагрузку сравнивают выходную (output), а не входную мощность, потому что output отражает:", "optsr": ["SEER", "Реально отданное тепло с учётом КПД сгорания (AFUE)", "Размер газовой линии", "Размер фильтра"]}, {"id": 125, "sec": "Principles & Load Calculations", "q": "A jurisdiction requires a permit for an HVAC changeout primarily to ensure:", "opts": ["Lower refrigerant cost", "Higher contractor profit", "Code compliance and inspection of the installation", "Faster installation"], "correct": 2, "re": "Permits trigger inspection so the work meets mechanical, electrical, and energy codes — protecting safety and property value.", "rr": "Permit запускает инспекцию, чтобы работа отвечала механическим, электрическим и энергетическим нормам — защита безопасности и стоимости объекта.", "qr": "Юрисдикция требует разрешение (permit) на замену HVAC прежде всего чтобы обеспечить:", "optsr": ["Снижение цены хладагента", "Бо́льшую прибыль подрядчика", "Соответствие нормам и инспекцию монтажа", "Более быстрый монтаж"]}, {"id": 126, "sec": "Fabrication & Installation", "q": "When brazing copper-to-copper refrigerant joints, a BCuP (copper-phosphorus) alloy is preferred because it:", "opts": ["Cannot be used on refrigeration", "Requires flux on copper", "Melts at room temperature", "Is self-fluxing on copper-to-copper joints"], "correct": 3, "re": "BCuP alloys are self-fluxing on copper-to-copper joints due to the phosphorus; flux is still required when brazing copper to brass or steel.", "rr": "Сплавы BCuP самофлюсуются на медь-медь благодаря фосфору; флюс всё же нужен при пайке меди к латуни или стали.", "qr": "При пайке медь-медь в холодильных линиях предпочитают сплав BCuP (медь-фосфор), потому что он:", "optsr": ["Непригоден для холодильной техники", "Требует флюс на меди", "Плавится при комнатной температуре", "Самофлюсуется на соединениях медь-медь"]}, {"id": 127, "sec": "Fabrication & Installation", "q": "Flowing dry nitrogen through tubing while brazing prevents:", "opts": ["High superheat", "Overheating the torch", "Refrigerant loss", "Formation of copper-oxide scale inside the pipe"], "correct": 3, "re": "Without an inert nitrogen purge, the inside of the tubing oxidizes, forming flaky copper-oxide scale that can clog metering devices and contaminate the system.", "rr": "Без инертной продувки азотом внутренняя поверхность трубы окисляется, образуя хлопья окиси меди, забивающие дозаторы и загрязняющие систему.", "qr": "Продувка сухим азотом через трубу во время пайки предотвращает:", "optsr": ["Высокий superheat", "Перегрев горелки", "Потерю хладагента", "Образование окалины окиси меди внутри трубы"]}, {"id": 128, "sec": "Fabrication & Installation", "q": "A typical low-flow nitrogen purge pressure while brazing is about:", "opts": ["0 psig", "500 psig", "150 psig", "2–3 psig (a gentle flow)"], "correct": 3, "re": "Only a gentle nitrogen flow (a few psig) is needed to displace oxygen; high pressure would blow molten braze out of the joint.", "rr": "Нужен лишь мягкий поток азота (несколько psig), чтобы вытеснить кислород; высокое давление выдует расплавленный припой из стыка.", "qr": "Типовое давление продувки азотом при пайке (малый поток) составляет около:", "optsr": ["0 psig", "500 psig", "150 psig", "2–3 psig (мягкий поток)"]}, {"id": 129, "sec": "Fabrication & Installation", "q": "Before charging a new system, a deep vacuum is pulled to remove moisture and:", "opts": ["Raise head pressure", "Boil off and evacuate non-condensables and water vapor", "Increase superheat", "Add refrigerant"], "correct": 1, "re": "A deep vacuum (e.g., ≤500 microns) lowers the boiling point of water so trapped moisture vaporizes and is evacuated along with air/non-condensables.", "rr": "Глубокий вакуум (например ≤500 микрон) снижает точку кипения воды, так что влага испаряется и откачивается вместе с воздухом/неконденсируемыми.", "qr": "Перед заправкой новой системы создают глубокий вакуум, чтобы удалить влагу и:", "optsr": ["Поднять давление нагнетания", "Выпарить и откачать неконденсируемые газы и пары воды", "Повысить superheat", "Добавить хладагент"]}, {"id": 130, "sec": "Fabrication & Installation", "q": "A system is considered properly evacuated when a micron gauge holds below 500 microns and:", "opts": ["Holds stable (decay test passes) after isolating the pump", "Shows high superheat", "Rises quickly when valved off", "Reads 0 psig"], "correct": 0, "re": "After isolating the vacuum pump, the micron level should hold (a slow, small rise that levels off); a rapid rise indicates remaining moisture or a leak.", "rr": "После отсечки вакуумного насоса уровень микрон должен держаться (медленный малый рост с выходом на плато); быстрый рост — остаточная влага или утечка.", "qr": "Систему считают правильно отвакуумированной, когда микронный вакуумметр держит ниже 500 микрон и:", "optsr": ["Держится стабильно (decay-тест пройден) после отсечки насоса", "Показывает высокий superheat", "Быстро растёт после перекрытия", "Показывает 0 psig"]}, {"id": 131, "sec": "Fabrication & Installation", "q": "Suction-line refrigerant piping that rises vertically may require a P-trap or proper sizing to ensure:", "opts": ["Lower voltage", "Faster defrost", "Oil return to the compressor", "Higher subcooling"], "correct": 2, "re": "Oil travels with refrigerant; on long vertical risers, correct velocity (and traps where needed) keeps oil moving back to the compressor instead of pooling.", "rr": "Масло движется с хладагентом; на длинных вертикальных стояках правильная скорость (и ловушки где нужно) возвращают масло в компрессор, а не дают ему скапливаться.", "qr": "Всасывающая линия хладагента, поднимающаяся вертикально, может требовать P-trap или правильного диаметра, чтобы обеспечить:", "optsr": ["Меньшее напряжение", "Быструю разморозку", "Возврат масла в компрессор", "Более высокий subcooling"]}, {"id": 132, "sec": "Fabrication & Installation", "q": "Refrigerant suction lines should be insulated primarily to:", "opts": ["Prevent heat gain and surface condensation/sweating", "Increase pressure", "Reduce noise only", "Speed up brazing"], "correct": 0, "re": "Insulating the cold suction line prevents capacity-robbing heat gain and stops condensation that can drip and cause water damage.", "rr": "Изоляция холодной всасывающей линии предотвращает теплоприток (потерю производительности) и образование конденсата, который капает и портит конструкции.", "qr": "Всасывающие линии хладагента изолируют прежде всего чтобы:", "optsr": ["Предотвратить теплоприток и конденсат/потение на поверхности", "Повысить давление", "Только снизить шум", "Ускорить пайку"]}, {"id": 133, "sec": "Fabrication & Installation", "q": "A condensate drain line from a cooling coil typically requires:", "opts": ["Upward slope", "Pressurization", "A trap and proper downward slope", "No slope"], "correct": 2, "re": "A trap counters blower negative pressure so condensate drains freely; the line must slope downward (e.g., 1/8 in per foot) toward the drain.", "rr": "Сифон компенсирует разрежение от вентилятора, чтобы конденсат стекал свободно; линия должна идти под уклон вниз (например 1/8 дюйма на фут) к дренажу.", "qr": "Дренажная линия конденсата от испарителя обычно требует:", "optsr": ["Уклона вверх", "Наддува", "Сифон (trap) и правильный уклон вниз", "Без уклона"]}, {"id": 134, "sec": "Fabrication & Installation", "q": "A secondary (overflow) condensate switch or pan is installed to:", "opts": ["Lower head pressure", "Boost refrigerant", "Increase airflow", "Shut the system off or catch water if the primary drain clogs"], "correct": 3, "re": "Codes require overflow protection (float switch and/or secondary pan) to prevent water damage when the primary condensate drain backs up.", "rr": "Нормы требуют защиту от перелива (поплавковый выключатель и/или вторичный поддон) для предотвращения протечек при засоре основного дренажа.", "qr": "Вторичный (аварийный) выключатель или поддон конденсата ставят, чтобы:", "optsr": ["Снизить давление нагнетания", "Добавить хладагент", "Увеличить расход воздуха", "Отключить систему или собрать воду при засоре основного дренажа"]}, {"id": 135, "sec": "Fabrication & Installation", "q": "The minimum circuit ampacity (MCA) on a unit's data plate is used to size the:", "opts": ["Duct", "Branch-circuit conductors (wire)", "Filter", "Refrigerant charge"], "correct": 1, "re": "MCA tells the installer the minimum wire ampacity required; MOP/MOCP gives the maximum overcurrent (breaker/fuse) size.", "rr": "MCA указывает минимальную ампачность провода; MOP/MOCP задаёт максимальный номинал защиты (автомат/предохранитель).", "qr": "Минимальная токовая нагрузка цепи (MCA) на шильдике блока используется для подбора:", "optsr": ["Воздуховода", "Проводников ответвления (провода)", "Фильтра", "Заправки хладагентом"]}, {"id": 136, "sec": "Fabrication & Installation", "q": "The MOP (maximum overcurrent protection) value on the data plate sets the:", "opts": ["Refrigerant type", "Duct gauge", "Largest allowable breaker/fuse size", "Wire color"], "correct": 2, "re": "MOP (a.k.a. MOCP) is the largest breaker or fuse permitted to protect the equipment; you may not exceed it even if larger wire is used.", "rr": "MOP (он же MOCP) — наибольший допустимый автомат или предохранитель для защиты оборудования; превышать нельзя, даже если провод толще.", "qr": "Значение MOP (максимальная защита от сверхтока) на шильдике задаёт:", "optsr": ["Тип хладагента", "Толщину дакта", "Наибольший допустимый номинал автомата/предохранителя", "Цвет провода"]}, {"id": 137, "sec": "Fabrication & Installation", "q": "In standard low-voltage thermostat wiring, the 'C' terminal provides:", "opts": ["The common (return) side of the 24 V transformer", "The fan signal", "The cooling call", "The heat call"], "correct": 0, "re": "R is the 24 V hot, C is the common return; together they power the thermostat. Y=cool, G=fan, W=heat, O/B=reversing valve.", "rr": "R — это 24 В «горячий», C — общий обратный; вместе они питают термостат. Y=охлаждение, G=вентилятор, W=нагрев, O/B=реверс-клапан.", "qr": "В стандартной низковольтной разводке термостата клемма «C» обеспечивает:", "optsr": ["Общий (обратный) провод трансформатора 24 В", "Сигнал вентилятора", "Вызов охлаждения", "Вызов нагрева"]}, {"id": 138, "sec": "Fabrication & Installation", "q": "On a heat pump thermostat, the 'O' terminal energizes the reversing valve in:", "opts": ["Cooling mode", "Heating mode", "Emergency heat", "Defrost only"], "correct": 0, "re": "Most heat pumps energize the reversing valve with 'O' in cooling. (Some older systems use 'B' to energize in heating instead.)", "rr": "Большинство тепловых насосов запитывают реверс-клапан через «O» в охлаждении. (Некоторые старые системы используют «B» для запитки в нагреве.)", "qr": "На термостате теплового насоса клемма «O» запитывает реверс-клапан в режиме:", "optsr": ["Охлаждения", "Нагрева", "Аварийного нагрева", "Только разморозки"]}, {"id": 139, "sec": "Fabrication & Installation", "q": "A 24 V control transformer rated in VA is selected so its VA capacity:", "opts": ["Equals line voltage", "Is always 5 VA", "Matches the SEER", "Meets or exceeds the total connected control load"], "correct": 3, "re": "The transformer VA must supply the combined draw of contactor coil, relays, and accessories; undersizing causes voltage droop and chatter.", "rr": "VA трансформатора должно покрывать суммарный ток катушки контактора, реле и аксессуаров; занижение даёт просадку напряжения и дребезг.", "qr": "Управляющий трансформатор 24 В, измеряемый в VA, подбирают так, чтобы его мощность:", "optsr": ["Равнялась линейному напряжению", "Всегда была 5 VA", "Совпадала с SEER", "Покрывала суммарную нагрузку управления"]}, {"id": 140, "sec": "Fabrication & Installation", "q": "SMACNA standards for sheet-metal duct specify minimum metal gauge based primarily on:", "opts": ["Paint color", "Thermostat brand", "Duct size and operating pressure class", "Refrigerant type"], "correct": 2, "re": "Larger ducts and higher static-pressure classes require thicker (lower-gauge) metal and more reinforcement per SMACNA HVAC Duct Construction Standards.", "rr": "Бо́льшие дакты и более высокий класс статического давления требуют более толстого (меньший gauge) металла и усиления по SMACNA HVAC Duct Construction Standards.", "qr": "Стандарты SMACNA для металлических воздуховодов задают минимальную толщину металла в основном по:", "optsr": ["Цвету краски", "Бренду термостата", "Размеру дакта и классу рабочего давления", "Типу хладагента"]}, {"id": 141, "sec": "Fabrication & Installation", "q": "Duct seams and joints are best sealed with:", "opts": ["Standard cloth 'duct tape'", "Refrigerant oil", "UL-181 mastic or approved foil tape", "Silicone caulk only"], "correct": 2, "re": "Cloth duct tape fails over time; codes call for UL-181 listed mastic or foil tape on seams to limit leakage.", "rr": "Тканевая duct tape со временем отслаивается; нормы требуют мастику или фольгированную ленту с листингом UL-181 на швы для снижения утечек.", "qr": "Швы и стыки воздуховодов лучше всего герметизировать:", "optsr": ["Обычной тканевой «duct tape»", "Холодильным маслом", "Мастикой UL-181 или одобренной фольгированной лентой", "Только силиконовым герметиком"]}, {"id": 142, "sec": "Fabrication & Installation", "q": "A gas furnace requires combustion air. An atmospherically-vented furnace in a confined space needs:", "opts": ["Two openings (high and low) for combustion/ventilation air", "More refrigerant", "No air openings", "Only an exhaust fan"], "correct": 0, "re": "Confined spaces need two permanent openings (one near the top, one near the bottom) sized per code to supply combustion and dilution air.", "rr": "Тесным помещениям нужны два постоянных отверстия (вверху и внизу), рассчитанные по нормам, для воздуха горения и разбавления.", "qr": "Газовой печи нужен воздух для горения. Печь с атмосферным дымоудалением в тесном помещении требует:", "optsr": ["Два отверстия (верхнее и нижнее) для воздуха горения/вентиляции", "Больше хладагента", "Никаких отверстий", "Только вытяжной вентилятор"]}, {"id": 143, "sec": "Fabrication & Installation", "q": "A Category IV gas furnace (high-efficiency condensing) is vented with:", "opts": ["Masonry chimney only", "No vent", "Sealed plastic (PVC/CPVC) because flue gases are cool and positive-pressure", "Single-wall metal pipe"], "correct": 2, "re": "Condensing (Cat IV) furnaces produce cool, positive-pressure, moisture-laden flue gas, vented through sealed plastic with a condensate drain.", "rr": "Конденсационные печи (Cat IV) дают холодный, под избыточным давлением, насыщенный влагой дымовой газ — удаляется герметичным пластиком с дренажом конденсата.", "qr": "Газовая печь Category IV (высокоэффективная конденсационная) удаляет продукты сгорания через:", "optsr": ["Только кирпичный дымоход", "Без дымохода", "Герметичный пластик (PVC/CPVC), т.к. газы холодные и под давлением", "Одностенную металлическую трубу"]}, {"id": 144, "sec": "Fabrication & Installation", "q": "During startup, measuring total external static pressure (TESP) verifies the:", "opts": ["Gas pressure", "Refrigerant charge", "Flame color", "Airflow/duct performance against the blower table"], "correct": 3, "re": "Comparing measured TESP to the blower performance table confirms whether the system is moving the design airflow; high TESP means restriction.", "rr": "Сравнение измеренного TESP с таблицей вентилятора подтверждает, движет ли система расчётный расход; высокий TESP — сужение/сопротивление.", "qr": "При запуске измерение полного внешнего статического давления (TESP) проверяет:", "optsr": ["Давление газа", "Заправку хладагентом", "Цвет пламени", "Производительность воздуховодов/расход по таблице вентилятора"]}, {"id": 145, "sec": "Fabrication & Installation", "q": "The gas manifold pressure on a typical residential natural-gas furnace is set near:", "opts": ["25 in WC", "3.5 in WC", "11 in WC", "0.5 in WC"], "correct": 1, "re": "Natural-gas furnaces commonly run about 3.5 in WC manifold pressure (LP propane near 10–11 in WC); always verify with the rating plate and a manometer.", "rr": "Печи на природном газе обычно работают около 3.5 in WC на манифольде (пропан LP около 10–11 in WC); всегда сверяйтесь с шильдиком и манометром.", "qr": "Давление газа на манифольде типовой бытовой печи на природном газе устанавливается около:", "optsr": ["25 in WC", "3.5 in WC", "11 in WC", "0.5 in WC"]}, {"id": 146, "sec": "Fabrication & Installation", "q": "After installing a new condenser, the technician verifies charge on a fixed-orifice (piston) system primarily by:", "opts": ["Voltage", "Subcooling", "Duct size", "Superheat (with a charging chart)"], "correct": 3, "re": "Fixed-orifice/piston systems are charged by superheat (using a target chart with indoor wet-bulb and outdoor dry-bulb); TXV systems use subcooling.", "rr": "Системы с фикс. дросселем/piston заправляют по superheat (по целевой таблице с indoor wet-bulb и outdoor dry-bulb); системы с TXV — по subcooling.", "qr": "После установки нового конденсатора заправку системы с фикс. дросселем (piston) проверяют прежде всего по:", "optsr": ["Напряжению", "Subcooling", "Размеру дакта", "Superheat (по charging-таблице)"]}, {"id": 147, "sec": "Fabrication & Installation", "q": "A TXV-equipped system is charged to a target:", "opts": ["Superheat value", "Voltage value", "Subcooling value", "CFM value"], "correct": 2, "re": "Because a TXV maintains evaporator superheat automatically, correct charge is verified at the condenser by subcooling per the manufacturer's spec.", "rr": "Поскольку TXV сам поддерживает superheat испарителя, правильную заправку проверяют на конденсаторе по subcooling согласно спецификации производителя.", "qr": "Систему с TXV заправляют до целевого значения:", "optsr": ["Superheat", "Напряжения", "Subcooling", "CFM"]}, {"id": 148, "sec": "Fabrication & Installation", "q": "Line-set sizing matters because an oversized suction line can cause:", "opts": ["Too much subcooling", "High voltage", "Low refrigerant velocity and poor oil return", "Excess airflow"], "correct": 2, "re": "If suction velocity is too low (line too large or run too long without proper sizing), oil won't return to the compressor, risking lubrication failure.", "rr": "Если скорость всасывания слишком мала (линия велика или длинна без правильного расчёта), масло не вернётся в компрессор — риск отказа смазки.", "qr": "Подбор диаметра линий важен, потому что завышенная всасывающая линия может вызвать:", "optsr": ["Слишком большой subcooling", "Высокое напряжение", "Низкую скорость хладагента и плохой возврат масла", "Избыточный расход воздуха"]}, {"id": 149, "sec": "Fabrication & Installation", "q": "A disconnecting means (service disconnect) must be installed:", "opts": ["Within sight of the outdoor unit", "In the attic only", "Inside the compressor", "At the thermostat"], "correct": 0, "re": "Electrical code requires a disconnect within sight of and readily accessible to the outdoor unit so it can be safely de-energized for service.", "rr": "Электрические нормы требуют разъединитель в зоне прямой видимости и в лёгком доступе у наружного блока, чтобы безопасно его обесточить для обслуживания.", "qr": "Разъединитель (service disconnect) должен быть установлен:", "optsr": ["В зоне видимости от наружного блока", "Только на чердаке", "Внутри компрессора", "У термостата"]}, {"id": 150, "sec": "Fabrication & Installation", "q": "When connecting flexible duct, it should be:", "opts": ["Left disconnected", "Compressed and kinked to save space", "Pulled taut and supported to avoid sag and restriction", "Filled with refrigerant"], "correct": 2, "re": "Flex duct must be stretched tight and supported at intervals; sags, kinks, and compression sharply increase static pressure and cut airflow.", "rr": "Гибкий дакт натягивают и поддерживают через интервалы; провисания, заломы и сжатие резко повышают статическое давление и режут расход.", "qr": "При подключении гибкого воздуховода его следует:", "optsr": ["Оставить отсоединённым", "Сжать и заломить для экономии места", "Натянуть и поддержать, избегая провисания и сужения", "Заполнить хладагентом"]}, {"id": 151, "sec": "Fabrication & Installation", "q": "The purpose of a P-trap/condensate trap depth being adequate is to:", "opts": ["Increase airflow", "Lower gas pressure", "Add refrigerant", "Prevent air pull-through or bubbling that blocks drainage"], "correct": 3, "re": "On draw-through coils the blower's negative pressure can hold water in the line; a properly sized trap seals against it so condensate drains.", "rr": "На draw-through испарителях разрежение вентилятора удерживает воду в линии; правильный сифон герметизирует от него, и конденсат стекает.", "qr": "Достаточная глубина P-trap/сифона конденсата нужна, чтобы:", "optsr": ["Увеличить расход воздуха", "Снизить давление газа", "Добавить хладагент", "Не дать подсосу воздуха или бульканью блокировать слив"]}, {"id": 152, "sec": "Fabrication & Installation", "q": "Before opening a system to replace a component, the refrigerant must be:", "opts": ["Recovered into an approved recovery cylinder", "Burned off", "Vented to atmosphere", "Mixed with nitrogen"], "correct": 0, "re": "EPA Section 608 prohibits venting; refrigerant must be recovered with certified equipment into a DOT-approved recovery cylinder.", "rr": "EPA Section 608 запрещает стравливание; хладагент откачивают сертифицированным оборудованием в одобренный DOT recovery-баллон.", "qr": "Перед вскрытием системы для замены компонента хладагент необходимо:", "optsr": ["Откачать в одобренный recovery-баллон", "Сжечь", "Стравить в атмосферу", "Смешать с азотом"]}, {"id": 153, "sec": "Fabrication & Installation", "q": "A new line set is pressure-tested for leaks before evacuation using:", "opts": ["Water", "Propane", "Pure oxygen", "Dry nitrogen (often with a trace of refrigerant for a detector)"], "correct": 3, "re": "Dry nitrogen is used for pressure/leak testing because it's inert and dry; oxygen is dangerous (combustion) and must never be used.", "rr": "Для опрессовки/поиска утечек применяют сухой азот — он инертен и сух; кислород опасен (горение) и применять его нельзя.", "qr": "Новый комплект линий перед вакуумированием проверяют на утечки с помощью:", "optsr": ["Воды", "Пропана", "Чистого кислорода", "Сухого азота (иногда с примесью хладагента для детектора)"]}, {"id": 154, "sec": "Fabrication & Installation", "q": "Commissioning a heat pump includes verifying defrost operation, which is best confirmed by:", "opts": ["Reading the thermostat brand", "Initiating/observing a defrost cycle and reversing-valve shift", "Checking the filter", "Measuring SEER"], "correct": 1, "re": "During defrost the unit reverses to cooling, the outdoor fan stops, and the coil clears ice; observing this cycle confirms the defrost board and reversing valve work.", "rr": "При разморозке блок переходит в охлаждение, наружный вентилятор останавливается, иней сходит; наблюдение этого цикла подтверждает работу defrost-платы и реверс-клапана.", "qr": "Пусконаладка теплового насоса включает проверку разморозки, которую лучше всего подтвердить:", "optsr": ["Чтением бренда термостата", "Запуском/наблюдением цикла defrost и переключения реверс-клапана", "Проверкой фильтра", "Измерением SEER"]}, {"id": 155, "sec": "TR", "q": "High superheat together with low subcooling most often indicates the system is:", "opts": ["Undercharged (low on refrigerant)", "Airflow too high", "Overcharged", "Voltage too high"], "correct": 0, "re": "Low charge starves the evaporator (high superheat) and leaves little liquid in the condenser (low subcooling) — classic undercharge signature.", "rr": "Недозаправка обедняет испаритель (высокий superheat) и оставляет мало жидкости в конденсаторе (низкий subcooling) — классическая картина недозаправки.", "qr": "Высокий superheat вместе с низким subcooling чаще всего указывает, что система:", "optsr": ["Недозаправлена (мало хладагента)", "Слишком большой расход воздуха", "Перезаправлена", "Слишком высокое напряжение"]}, {"id": 156, "sec": "TR", "q": "Low superheat with high subcooling most often indicates:", "opts": ["Open contactor", "Overcharge (too much refrigerant)", "Dirty filter", "Undercharge"], "correct": 1, "re": "Excess charge floods the condenser (high subcooling) and can flood the evaporator (low superheat) — the overcharge signature.", "rr": "Избыток заряда переполняет конденсатор (высокий subcooling) и может затапливать испаритель (низкий superheat) — картина перезаправки.", "qr": "Низкий superheat при высоком subcooling чаще всего указывает на:", "optsr": ["Разомкнутый контактор", "Перезаправку (слишком много хладагента)", "Грязный фильтр", "Недозаправку"]}, {"id": 157, "sec": "TR", "q": "A TXV that is 'hunting' (bulb signal unstable) typically causes:", "opts": ["Superheat that swings up and down erratically", "High voltage", "Steady superheat", "No effect on superheat"], "correct": 0, "re": "A hunting TXV over- and under-feeds the evaporator, causing superheat to oscillate; causes include a loose/poorly insulated sensing bulb or wrong valve size.", "rr": "«Охотящийся» TXV то переподаёт, то недоподаёт в испаритель, и superheat колеблется; причины — слабо закреплённая/плохо изолированная колба или неверный размер клапана.", "qr": "TXV, который «охотится» (нестабильный сигнал колбы), обычно вызывает:", "optsr": ["Superheat, который беспорядочно скачет вверх-вниз", "Высокое напряжение", "Стабильный superheat", "Никакого влияния на superheat"]}, {"id": 158, "sec": "TR", "q": "A compressor that hums and trips on overload but won't start, with the windings reading good, often has a failed:", "opts": ["Thermostat", "Start/run capacitor", "Reversing valve", "Filter drier"], "correct": 1, "re": "A weak or failed capacitor robs the motor of starting torque; the compressor draws locked-rotor amps and trips. Verify capacitor microfarads before condemning the compressor.", "rr": "Слабый или отказавший конденсатор лишает двигатель пускового момента; компрессор тянет ток заторможенного ротора и выбивает. Проверьте микрофарады конденсатора, прежде чем менять компрессор.", "qr": "Компрессор гудит и выбивает по перегрузке, но не запускается, при этом обмотки в норме — часто неисправен:", "optsr": ["Термостат", "Пусковой/рабочий конденсатор", "Реверс-клапан", "Фильтр-осушитель"]}, {"id": 159, "sec": "TR", "q": "A run capacitor is tested by:", "opts": ["Checking refrigerant", "Reading the voltage only", "Smelling it", "Measuring its capacitance (µF) against the rated value"], "correct": 3, "re": "With the cap discharged and disconnected, a meter on capacitance compares actual µF to the rating; out-of-tolerance or bulged caps must be replaced.", "rr": "Разрядив и отключив конденсатор, мультиметром в режиме ёмкости сравнивают реальные µF с номиналом; вне допуска или вздутый — под замену.", "qr": "Рабочий конденсатор проверяют:", "optsr": ["Проверкой хладагента", "Только измерением напряжения", "По запаху", "Измерением ёмкости (µF) и сравнением с номиналом"]}, {"id": 160, "sec": "TR", "q": "Pitted, burned contactor points are best addressed by:", "opts": ["Filing them smooth", "Increasing airflow", "Replacing the contactor", "Adding refrigerant"], "correct": 2, "re": "Filing contacts removes plating and worsens arcing; a pitted contactor should be replaced to ensure reliable, low-resistance switching.", "rr": "Опиливание снимает покрытие и усиливает искрение; изъеденный контактор меняют для надёжной коммутации с малым сопротивлением.", "qr": "Подгоревшие, изъеденные контакты контактора правильнее всего:", "optsr": ["Зачистить напильником", "Увеличить расход воздуха", "Заменить контактор", "Добавить хладагент"]}, {"id": 161, "sec": "TR", "q": "To diagnose a suspected grounded compressor motor, the technician measures resistance from the C, S, and R terminals to:", "opts": ["The thermostat", "Ground/chassis (any continuity to ground indicates a grounded winding)", "The refrigerant", "The duct"], "correct": 1, "re": "Common-Start-Run windings should read continuity and roughly C-R + C-S = S-R; any winding-to-ground continuity means a grounded (shorted-to-case) compressor that must be replaced.", "rr": "Обмотки Common-Start-Run должны иметь проводимость и примерно C-R + C-S = S-R; любая проводимость обмотки на землю означает пробитый на корпус компрессор — под замену.", "qr": "Чтобы диагностировать предполагаемый пробой обмотки компрессора на корпус, техник измеряет сопротивление от клемм C, S, R к:", "optsr": ["Термостату", "Земле/корпусу (любая проводимость на землю = пробой обмотки)", "Хладагенту", "Воздуховоду"]}, {"id": 162, "sec": "TR", "q": "Abnormally high head (discharge) pressure is commonly caused by:", "opts": ["Clean coil", "A dirty condenser coil, overcharge, or non-condensables", "Low ambient only", "Low refrigerant"], "correct": 1, "re": "Restricted condenser heat rejection (dirty coil, failed fan, overcharge, or air/non-condensables in the system) raises head pressure.", "rr": "Ухудшение теплоотвода конденсатора (грязная батарея, отказ вентилятора, перезаправка или воздух/неконденсируемые в системе) поднимает давление нагнетания.", "qr": "Аномально высокое давление нагнетания (head) обычно вызвано:", "optsr": ["Чистым конденсатором", "Грязным конденсатором, перезаправкой или неконденсируемыми", "Только низкой наружной температурой", "Недостатком хладагента"]}, {"id": 163, "sec": "TR", "q": "A gas furnace lights then shuts off after a few seconds ('flame proving' fault). The most likely cause is a:", "opts": ["Dirty or failed flame sensor", "Low refrigerant", "Oversized duct", "Bad SEER rating"], "correct": 0, "re": "If the flame sensor can't prove flame (dirty, cracked, or misaligned), the control closes the gas valve for safety — flame lights then drops out.", "rr": "Если датчик пламени не подтверждает пламя (загрязнён, треснул или смещён), плата закрывает газовый клапан для безопасности — пламя вспыхивает и гаснет.", "qr": "Газовая печь зажигается, затем гаснет через несколько секунд (ошибка контроля пламени). Наиболее вероятная причина:", "optsr": ["Грязный или неисправный датчик пламени (flame sensor)", "Недостаток хладагента", "Завышенный дакт", "Плохой SEER"]}, {"id": 164, "sec": "TR", "q": "The flame-sensor (flame-rectification) signal is measured in:", "opts": ["Microns", "Pounds", "Volts AC", "Microamps (µA) DC"], "correct": 3, "re": "A clean flame sensor passes a small DC current (microamps) by rectification; a low microamp reading indicates a dirty sensor or weak flame.", "rr": "Чистый датчик пламени проводит малый постоянный ток (микроамперы) за счёт ректификации; низкий µA — загрязнение датчика или слабое пламя.", "qr": "Сигнал датчика пламени (flame rectification) измеряется в:", "optsr": ["Микронах", "Фунтах", "Вольтах переменного тока", "Микроамперах (µA) постоянного тока"]}, {"id": 165, "sec": "TR", "q": "A furnace that short-cycles on the high-limit switch usually has:", "opts": ["A clean filter", "Insufficient airflow (overheating heat exchanger)", "Low gas pressure only", "Too much airflow"], "correct": 1, "re": "Restricted airflow (dirty filter/coil, blocked ducts, weak blower) lets the heat exchanger overheat, tripping the limit and short-cycling the burner.", "rr": "Ограниченный расход (грязный фильтр/испаритель, забитые дакты, слабый вентилятор) перегревает теплообменник, лимит срабатывает и горелка циклит.", "qr": "Печь, циклящая по верхнему лимиту (high-limit), обычно имеет:", "optsr": ["Чистый фильтр", "Недостаточный расход воздуха (перегрев теплообменника)", "Только низкое давление газа", "Слишком большой расход воздуха"]}, {"id": 166, "sec": "TR", "q": "A cracked heat exchanger is a safety concern because it can:", "opts": ["Increase airflow", "Save gas", "Allow combustion products (CO) to mix with supply air", "Lower the SEER"], "correct": 2, "re": "A crack can leak carbon monoxide and flue gases into the conditioned airstream — a life-safety hazard requiring shutdown until repaired/replaced.", "rr": "Трещина может пропускать угарный газ и дымовые газы в приточный воздух — угроза жизни; до ремонта/замены оборудование выводят из работы.", "qr": "Трещина в теплообменнике опасна, потому что может:", "optsr": ["Увеличить расход воздуха", "Экономить газ", "Допустить смешивание продуктов сгорания (CO) с приточным воздухом", "Снизить SEER"]}, {"id": 167, "sec": "TR", "q": "A heat pump that blows cold air in heating mode and never warms up may have a:", "opts": ["High SEER", "Stuck reversing valve (still in cooling)", "Clogged condensate drain", "Dirty filter only"], "correct": 1, "re": "If the reversing valve fails to shift (or its solenoid/wiring fails), the unit stays in cooling during a heat call, delivering cold air.", "rr": "Если реверс-клапан не переключается (или отказали соленоид/проводка), блок остаётся в охлаждении при запросе нагрева и дует холодным.", "qr": "Тепловой насос дует холодным в режиме нагрева и не прогревается — возможна:", "optsr": ["Высокий SEER", "Заклинивший реверс-клапан (остался в охлаждении)", "Засорённая дренажная линия", "Только грязный фильтр"]}, {"id": 168, "sec": "TR", "q": "In heating mode, a heat pump's outdoor coil acts as the:", "opts": ["Condenser", "Filter", "Metering device", "Evaporator (absorbing heat from outdoor air)"], "correct": 3, "re": "In heating the refrigerant flow reverses: the outdoor coil absorbs heat (evaporator) and the indoor coil rejects it (condenser).", "rr": "В нагреве поток реверсируется: наружный змеевик поглощает тепло (испаритель), а внутренний отдаёт его (конденсатор).", "qr": "В режиме нагрева наружный змеевик теплового насоса работает как:", "optsr": ["Конденсатор", "Фильтр", "Дозатор", "Испаритель (забирает тепло из наружного воздуха)"]}, {"id": 169, "sec": "TR", "q": "A compressor drawing locked-rotor amps (LRA) continuously will:", "opts": ["Run efficiently", "Overheat and trip its overload/breaker", "Improve subcooling", "Lower head pressure"], "correct": 1, "re": "Continuous LRA means the rotor isn't turning (seized, no start torque, low voltage); the motor overheats and the overload or breaker trips.", "rr": "Постоянный LRA означает, что ротор не вращается (заклинил, нет пускового момента, низкое напряжение); двигатель перегревается, и срабатывает защита или автомат.", "qr": "Компрессор, постоянно потребляющий ток заторможенного ротора (LRA):", "optsr": ["Работает эффективно", "Перегревается и выбивает защиту/автомат", "Улучшает subcooling", "Снижает давление нагнетания"]}, {"id": 170, "sec": "TR", "q": "A refrigerant restriction (e.g., a clogged filter drier) typically shows:", "opts": ["A temperature drop and frost at the restriction with low evaporator pressure", "Equal pressures", "High subcooling everywhere", "No symptoms"], "correct": 0, "re": "Flow restriction causes a pressure/temperature drop across the blockage (often frost there), starving the evaporator and lowering its pressure.", "rr": "Засор даёт перепад давления/температуры на месте сужения (часто иней там), обедняя испаритель и снижая его давление.", "qr": "Засор в контуре хладагента (например забитый фильтр-осушитель) обычно проявляется:", "optsr": ["Перепадом температуры и инеем на засоре при низком давлении испарителя", "Равными давлениями", "Высоким subcooling везде", "Без симптомов"]}, {"id": 171, "sec": "TR", "q": "To find a small refrigerant leak, the most precise method among these is:", "opts": ["Guessing", "An electronic leak detector or UV dye, confirmed with bubbles", "Adding more charge", "Listening only"], "correct": 1, "re": "Electronic detectors and UV dye (plus soap bubbles for confirmation) pinpoint small leaks; a nitrogen standing-pressure test confirms tightness.", "rr": "Электронные детекторы и УФ-краситель (плюс мыльные пузыри для подтверждения) точно находят малые утечки; азотная опрессовка под давлением подтверждает герметичность.", "qr": "Чтобы найти небольшую утечку хладагента, наиболее точный из методов:", "optsr": ["Догадка", "Электронный течеискатель или УФ-краситель, подтверждённый пузырьками", "Добавить ещё заправки", "Только на слух"]}, {"id": 172, "sec": "TR", "q": "A blower motor running but moving little air, with high static pressure, suggests:", "opts": ["High SEER", "Refrigerant leak", "Low gas pressure", "A duct/coil/filter restriction or a slipping/failing blower wheel"], "correct": 3, "re": "High static with low airflow points to restriction (dirty filter/coil, undersized or blocked ducts) or a degraded blower wheel/belt.", "rr": "Высокое статическое при малом расходе — это сужение (грязный фильтр/испаритель, узкие или забитые дакты) либо изношенное колесо/ремень вентилятора.", "qr": "Вентилятор крутится, но воздуха мало, при высоком статическом давлении — это указывает на:", "optsr": ["Высокий SEER", "Утечку хладагента", "Низкое давление газа", "Засор дакта/испарителя/фильтра или проскальзывающее/изношенное колесо вентилятора"]}, {"id": 173, "sec": "TR", "q": "Routine maintenance to maintain capacity and efficiency includes:", "opts": ["Cleaning coils, replacing filters, and checking airflow/charge", "Adding refrigerant every visit", "Disabling safeties", "Removing the disconnect"], "correct": 0, "re": "Clean coils and filters, verified airflow, correct charge, tight electrical connections, and clear condensate drains keep the system efficient and reliable.", "rr": "Чистые батареи и фильтры, проверенный расход, правильная заправка, затянутые электроконтакты и свободные дренажи держат систему эффективной и надёжной.", "qr": "Регулярное обслуживание для сохранения производительности и КПД включает:", "optsr": ["Чистку батарей, замену фильтров и проверку расхода/заправки", "Добавление хладагента каждый визит", "Отключение защит", "Снятие разъединителя"]}, {"id": 174, "sec": "TR", "q": "Adding refrigerant to a system without finding the leak is:", "opts": ["Required by EPA", "Improper — the leak must be found and repaired (and venting is illegal)", "Faster and recommended", "Best practice"], "correct": 1, "re": "'Topping off' a leaking system wastes refrigerant, harms the environment, and violates good practice/EPA rules — locate and repair the leak.", "rr": "«Долив» в текущую систему расходует хладагент, вредит экологии и нарушает правила/EPA — утечку находят и устраняют.", "qr": "Доливать хладагент, не найдя утечку, —", "optsr": ["Требование EPA", "Неправильно — утечку нужно найти и устранить (стравливание запрещено)", "Быстрее и рекомендуется", "Лучшая практика"]}, {"id": 175, "sec": "TR", "q": "A capacitor must be discharged before testing/handling because it:", "opts": ["Is always safe", "Holds refrigerant", "Can store a dangerous electrical charge even when power is off", "Contains gas"], "correct": 2, "re": "Run/start capacitors store energy; touching terminals can deliver a shock. Discharge through a proper resistor before handling.", "rr": "Рабочие/пусковые конденсаторы хранят энергию; касание клемм может ударить током. Разряжайте через подходящий резистор перед работой.", "qr": "Конденсатор нужно разрядить перед проверкой/работой, потому что он:", "optsr": ["Всегда безопасен", "Содержит хладагент", "Может хранить опасный электрозаряд даже при снятом питании", "Содержит газ"]}, {"id": 176, "sec": "TR", "q": "Low suction pressure with normal-to-high superheat in cooling often points to:", "opts": ["Dirty condenser only", "Overcharge", "High voltage", "Low charge or restricted liquid line / low airflow"], "correct": 3, "re": "Starved evaporator from low charge, a liquid-line restriction, or low indoor airflow lowers suction pressure and raises superheat.", "rr": "Обеднённый испаритель из-за недозаправки, засора жидкостной линии или малого внутреннего расхода снижает давление всасывания и повышает superheat.", "qr": "Низкое давление всасывания при нормальном-высоком superheat в охлаждении часто указывает на:", "optsr": ["Только грязный конденсатор", "Перезаправку", "Высокое напряжение", "Недозаправку, засор жидкостной линии или низкий расход воздуха"]}, {"id": 177, "sec": "TR", "q": "A contactor coil that won't pull in, with 24 V present at the coil, indicates:", "opts": ["Good coil", "Refrigerant leak", "Dirty filter", "An open (burned-out) coil — replace the contactor"], "correct": 3, "re": "If rated control voltage is present but the contactor doesn't energize, the coil is open/failed and the contactor must be replaced.", "rr": "Если номинальное управляющее напряжение есть, а контактор не срабатывает — катушка в обрыве/отказала, контактор меняют.", "qr": "Катушка контактора не притягивается при наличии 24 В на ней — это указывает на:", "optsr": ["Исправную катушку", "Утечку хладагента", "Грязный фильтр", "Обрыв (перегорела) катушки — заменить контактор"]}, {"id": 178, "sec": "TR", "q": "An evaporator coil that is clean but the system still ices up, with correct charge, suggests checking the:", "opts": ["Gas valve", "Reversing valve", "Indoor airflow (blower speed, duct restriction)", "Flame sensor"], "correct": 2, "re": "With good charge and a clean coil, persistent icing usually traces to low airflow — wrong blower tap/speed, restricted return, or blocked ducts.", "rr": "При верной заправке и чистом испарителе устойчивое обмерзание обычно из-за малого расхода — неверная скорость вентилятора, забитая обратка или дакты.", "qr": "Испаритель чист, заправка верна, но система всё равно обмерзает — стоит проверить:", "optsr": ["Газовый клапан", "Реверс-клапан", "Внутренний расход воздуха (скорость вентилятора, засор дакта)", "Датчик пламени"]}, {"id": 179, "sec": "Safety & Field Practices", "q": "Under EPA Section 608, intentionally venting most refrigerants during service is:", "opts": ["Prohibited", "Only allowed indoors", "Allowed if small", "Required"], "correct": 0, "re": "Venting CFC, HCFC, HFC and their substitutes is illegal; refrigerant must be recovered. Only de minimis releases during normal recovery/loop-back are tolerated.", "rr": "Стравливание CFC, HCFC, HFC и их заменителей незаконно; хладагент откачивают. Допускаются лишь de minimis выбросы при штатной откачке/прокачке.", "qr": "Согласно EPA Section 608, намеренное стравливание большинства хладагентов при обслуживании:", "optsr": ["Запрещено", "Разрешено только внутри помещений", "Разрешено, если немного", "Обязательно"]}, {"id": 180, "sec": "Safety & Field Practices", "q": "EPA Section 608 certification 'Type II' covers technicians working on:", "opts": ["Only auto AC", "Small appliances", "Disposal only", "High-pressure appliances (e.g., split AC, heat pumps)"], "correct": 3, "re": "Type I = small appliances; Type II = high-pressure systems; Type III = low-pressure; Universal = all. Most HVAC field work needs Type II or Universal.", "rr": "Type I — малые приборы; Type II — высоконапорные системы; Type III — низконапорные; Universal — все. Большинству HVAC-работ нужен Type II или Universal.", "qr": "Сертификат EPA Section 608 «Type II» охватывает техников, работающих с:", "optsr": ["Только авто-кондиционерами", "Малыми приборами", "Только утилизацией", "Высоконапорным оборудованием (сплит-системы, тепловые насосы)"]}, {"id": 181, "sec": "Safety & Field Practices", "q": "A disposable (non-refillable) refrigerant cylinder must never be:", "opts": ["Kept below 125°F", "Stored upright", "Recycled when empty", "Refilled"], "correct": 3, "re": "Refilling a DOT disposable cylinder is illegal and dangerous (overpressure/rupture risk); recover into refillable, DOT-rated recovery cylinders only.", "rr": "Перезаправка одноразового DOT-баллона незаконна и опасна (риск перенаддува/разрыва); откачивают только в перезаправляемые recovery-баллоны с допуском DOT.", "qr": "Одноразовый (не перезаправляемый) баллон хладагента нельзя:", "optsr": ["Держать ниже 125°F", "Хранить вертикально", "Сдавать пустым в переработку", "Перезаправлять"]}, {"id": 182, "sec": "Safety & Field Practices", "q": "A recovery cylinder should be filled to no more than ___ of its capacity to allow for liquid expansion:", "opts": ["80%", "50%", "100%", "95%"], "correct": 0, "re": "The 80% fill rule leaves vapor space for thermal expansion of liquid refrigerant, preventing hydrostatic overpressure as temperature rises.", "rr": "Правило 80% оставляет паровое пространство для теплового расширения жидкого хладагента, предотвращая гидростатический перенаддув при росте температуры.", "qr": "Recovery-баллон заполняют не более чем на ___ ёмкости, чтобы оставить место для расширения жидкости:", "optsr": ["80%", "50%", "100%", "95%"]}, {"id": 183, "sec": "Safety & Field Practices", "q": "Refrigerant cylinders should be stored:", "opts": ["Near open flame", "In a cool, ventilated area away from heat, secured upright", "On a hot roof in summer", "Next to a furnace"], "correct": 1, "re": "Heat raises cylinder pressure dangerously; store in a cool, well-ventilated place, secured from falling, away from ignition sources.", "rr": "Жар опасно повышает давление в баллоне; хранят в прохладном, хорошо проветриваемом месте, закреплёнными от падения, вдали от источников возгорания.", "qr": "Баллоны с хладагентом следует хранить:", "optsr": ["У открытого огня", "В прохладном проветриваемом месте, вдали от тепла, закреплёнными вертикально", "На горячей крыше летом", "Рядом с печью"]}, {"id": 184, "sec": "Safety & Field Practices", "q": "A2L refrigerants (e.g., R-32, R-454B) differ from older HFCs in that they are:", "opts": ["Inert like nitrogen", "Mildly flammable, requiring leak detection and charge limits", "Non-toxic and non-flammable", "Heavier than mercury"], "correct": 1, "re": "A2L refrigerants are lower-GWP but mildly flammable; equipment uses leak detection, ventilation interlocks, and charge limits per code (UL 60335-2-40).", "rr": "A2L имеют ниже GWP, но слабогорючи; оборудование использует детекцию утечки, вентиляционные блокировки и лимиты заправки по нормам (UL 60335-2-40).", "qr": "Хладагенты A2L (например R-32, R-454B) отличаются от старых HFC тем, что они:", "optsr": ["Инертны как азот", "Слабогорючи, требуют контроля утечки и лимитов заправки", "Нетоксичны и негорючи", "Тяжелее ртути"]}, {"id": 185, "sec": "Safety & Field Practices", "q": "Before working inside an electrical panel on equipment, the technician must:", "opts": ["Lock out and tag out (LOTO) the disconnect and verify zero voltage", "Increase the breaker size", "Add refrigerant", "Open the gas valve"], "correct": 0, "re": "LOTO de-energizes the circuit, locks the disconnect, tags it, and a meter verifies zero voltage before work — preventing electrocution from unexpected startup.", "rr": "LOTO обесточивает цепь, блокирует и маркирует разъединитель, а мультиметр подтверждает отсутствие напряжения до работы — защита от поражения при внезапном пуске.", "qr": "Перед работой внутри электрощита оборудования техник обязан:", "optsr": ["Выполнить LOTO разъединителя и проверить отсутствие напряжения", "Увеличить номинал автомата", "Добавить хладагент", "Открыть газовый клапан"]}, {"id": 186, "sec": "Safety & Field Practices", "q": "A refrigerant leak in a low, poorly ventilated space (basement or pit) is dangerous mainly because most refrigerant vapors are:", "opts": ["Safe to breathe", "Flammable like gasoline", "Heavier than air and collect low, displacing oxygen", "Lighter than air and rise out"], "correct": 2, "re": "Most refrigerant vapors are denser than air, so they pool in low areas and can displace oxygen, causing asphyxiation. Ventilate low spaces and monitor oxygen before entry.", "rr": "Пары большинства хладагентов плотнее воздуха, скапливаются в низких зонах и вытесняют кислород, вызывая удушье. Проветривайте низкие помещения и контролируйте кислород перед входом.", "qr": "Утечка хладагента в низком, плохо проветриваемом помещении (подвал, приямок) опасна главным образом потому, что пары большинства хладагентов:", "optsr": ["Безопасны для дыхания", "Горючи как бензин", "Тяжелее воздуха, скапливаются внизу и вытесняют кислород", "Легче воздуха и уходят вверх"]}, {"id": 187, "sec": "Safety & Field Practices", "q": "Fall protection is generally required on a roof or elevated work surface in construction when working at heights above:", "opts": ["2 feet", "20 feet", "6 feet (general construction trigger)", "No requirement"], "correct": 2, "re": "OSHA construction fall-protection generally triggers at 6 feet; Cal/OSHA and the work type may impose additional requirements — use guardrails, PFAS, or covers.", "rr": "Защита от падения в строительстве OSHA обычно срабатывает на 6 футах; Cal/OSHA и вид работ могут добавлять требования — ограждения, страховочные системы, перекрытия.", "qr": "Защита от падения на крыше или возвышении в строительстве обычно требуется при работе на высоте выше:", "optsr": ["2 футов", "20 футов", "6 футов (общий триггер в строительстве)", "Не требуется"]}, {"id": 188, "sec": "Safety & Field Practices", "q": "When entering an attic or vault that may have a hazardous atmosphere, the technician should treat it as a:", "opts": ["Refrigerant storage", "Break room", "Normal room", "Possible confined space requiring evaluation/permit"], "correct": 3, "re": "Spaces with limited entry/exit and potential hazardous atmosphere are confined spaces; evaluate, ventilate, test air, and follow permit procedures.", "rr": "Пространства с ограниченным входом/выходом и возможной опасной атмосферой — замкнутые; оценивают, вентилируют, проверяют воздух и соблюдают процедуры допуска.", "qr": "Входя на чердак или в приямок с возможной опасной атмосферой, техник должен рассматривать его как:", "optsr": ["Склад хладагента", "Комнату отдыха", "Обычную комнату", "Возможное замкнутое пространство, требующее оценки/допуска"]}, {"id": 189, "sec": "Safety & Field Practices", "q": "A Class C fire extinguisher is rated for fires involving:", "opts": ["Combustible metals", "Wood and paper", "Cooking oils", "Energized electrical equipment"], "correct": 3, "re": "Class A = ordinary combustibles, B = flammable liquids, C = energized electrical, D = metals, K = cooking media. Use Class C (or ABC) near live electrical.", "rr": "Класс A — обычные горючие, B — горючие жидкости, C — электрика под напряжением, D — металлы, K — кулинарные среды. У живой электрики применяют C (или ABC).", "qr": "Огнетушитель класса C предназначен для пожаров с участием:", "optsr": ["Горючих металлов", "Дерева и бумаги", "Кулинарных масел", "Электрооборудования под напряжением"]}, {"id": 190, "sec": "Safety & Field Practices", "q": "Nitrogen used for pressure testing is dangerous in a confined space mainly because it can:", "opts": ["Catch fire", "Freeze the pipes", "Explode", "Displace oxygen and cause asphyxiation"], "correct": 3, "re": "Nitrogen is inert but displaces oxygen; a leak in an enclosed space can lower O₂ to suffocating levels without warning. Ventilate and monitor.", "rr": "Азот инертен, но вытесняет кислород; утечка в закрытом помещении может снизить O₂ до удушающего уровня без предупреждения. Вентилируйте и контролируйте.", "qr": "Азот для опрессовки опасен в замкнутом пространстве главным образом тем, что может:", "optsr": ["Воспламениться", "Заморозить трубы", "Взорваться", "Вытеснить кислород и вызвать удушье"]}, {"id": 191, "sec": "Safety & Field Practices", "q": "A regulator must always be used on a nitrogen cylinder because cylinder pressure can exceed:", "opts": ["2000 psig (far above system test pressure)", "14 psig", "50 psig", "100 psig"], "correct": 0, "re": "Full nitrogen cylinders hold ~2000+ psig; without a regulator that pressure can rupture lines/components. Set the regulator to the required test pressure.", "rr": "Полный азотный баллон держит ~2000+ psig; без редуктора это давление разорвёт линии/компоненты. Редуктор выставляют на нужное испытательное давление.", "qr": "На азотном баллоне всегда ставят редуктор, потому что давление в баллоне может превышать:", "optsr": ["2000 psig (намного выше испытательного)", "14 psig", "50 psig", "100 psig"]}, {"id": 192, "sec": "Safety & Field Practices", "q": "Carbon monoxide (CO) is hazardous because it:", "opts": ["Only affects equipment", "Is heavier than refrigerant", "Has a strong odor", "Is colorless and odorless and binds hemoglobin, blocking oxygen"], "correct": 3, "re": "CO is an odorless, colorless gas that binds to hemoglobin far more readily than oxygen, causing poisoning; combustion safety checks and CO alarms are essential.", "rr": "CO — газ без запаха и цвета, связывается с гемоглобином гораздо охотнее кислорода, вызывая отравление; проверки горения и CO-сигнализаторы обязательны.", "qr": "Угарный газ (CO) опасен тем, что он:", "optsr": ["Влияет только на оборудование", "Тяжелее хладагента", "Имеет резкий запах", "Бесцветен и без запаха, связывает гемоглобин, блокируя кислород"]}, {"id": 193, "sec": "Safety & Field Practices", "q": "When brazing, eye protection (shaded glasses) is needed because the flame produces:", "opts": ["Static electricity", "Bright light and the work involves hot metal/flux spatter", "Cold", "Refrigerant"], "correct": 1, "re": "Brazing flames are intense; shaded safety glasses protect against glare, UV/IR, and flux/metal spatter, while gloves protect from burns.", "rr": "Пламя пайки интенсивно; затемнённые защитные очки защищают от блеска, УФ/ИК и брызг флюса/металла, а перчатки — от ожогов.", "qr": "При пайке нужна защита глаз (затемнённые очки), потому что пламя даёт:", "optsr": ["Статическое электричество", "Яркий свет, и работа связана с горячим металлом/брызгами флюса", "Холод", "Хладагент"]}, {"id": 194, "sec": "Safety & Field Practices", "q": "A 'worst-case depressurization' test on a combustion appliance checks for:", "opts": ["Flue-gas spillage/backdrafting when exhaust fans depressurize the space", "SEER", "Refrigerant leaks", "Duct size"], "correct": 0, "re": "Running exhaust fans can depressurize a house and cause an atmospheric appliance to backdraft CO indoors; the test verifies safe venting under worst case.", "rr": "Работа вытяжек может создать разрежение в доме и вызвать обратную тягу CO внутрь у атмосферного прибора; тест подтверждает безопасное дымоудаление в худшем случае.", "qr": "Тест «worst-case depressurization» на топливном приборе проверяет:", "optsr": ["Обратную тягу/выход дымовых газов при разрежении вытяжкой", "SEER", "Утечки хладагента", "Размер дакта"]}, {"id": 195, "sec": "Safety & Field Practices", "q": "Personal protective equipment (PPE) for electrical work near live parts includes:", "opts": ["Nothing", "Only a hard hat", "Insulated gloves/tools and appropriate arc-rated protection", "Refrigerant goggles"], "correct": 2, "re": "Live electrical work requires insulated tools/gloves, eye protection, and arc-rated PPE matched to the hazard; de-energizing first is always preferred.", "rr": "Работы под напряжением требуют изолированного инструмента/перчаток, защиты глаз и СИЗ с дуговым рейтингом по уровню риска; предпочтительнее сначала обесточить.", "qr": "Средства индивидуальной защиты (СИЗ) для электроработ у частей под напряжением включают:", "optsr": ["Ничего", "Только каску", "Изолированные перчатки/инструмент и защиту с дуговым рейтингом", "Только очки от хладагента"]}, {"id": 196, "sec": "Safety & Field Practices", "q": "A GFCI receptacle protects a worker by:", "opts": ["Boosting amperage", "Tripping quickly when it detects current leakage to ground", "Adding refrigerant", "Increasing voltage"], "correct": 1, "re": "A GFCI senses an imbalance between hot and neutral (leakage to ground, e.g., through a person) and trips in milliseconds to prevent electrocution.", "rr": "GFCI улавливает дисбаланс между фазой и нейтралью (утечку на землю, например через человека) и отключается за миллисекунды, предотвращая поражение.", "qr": "Розетка GFCI защищает работника тем, что:", "optsr": ["Повышает силу тока", "Быстро отключается при обнаружении утечки тока на землю", "Добавляет хладагент", "Повышает напряжение"]}, {"id": 197, "sec": "Safety & Field Practices", "q": "The Safety Data Sheet (SDS) for a refrigerant or chemical provides:", "opts": ["Hazards, handling, first aid, and PPE information", "The price", "The duct size", "The SEER rating"], "correct": 0, "re": "An SDS lists physical/health hazards, safe handling and storage, exposure controls/PPE, first-aid, and spill response — required to be accessible on the job.", "rr": "SDS перечисляет физические/санитарные опасности, безопасное обращение и хранение, меры защиты/СИЗ, первую помощь и действия при проливе — должен быть доступен на объекте.", "qr": "Паспорт безопасности (SDS) на хладагент или химикат содержит:", "optsr": ["Опасности, обращение, первую помощь и сведения о СИЗ", "Цену", "Размер дакта", "Рейтинг SEER"]}, {"id": 198, "sec": "Safety & Field Practices", "q": "Ladders used to access rooftop equipment must be:", "opts": ["Rated for the load and set at a safe angle, extended above the roof edge", "Made of aluminum near power lines", "Any length, leaned at any angle", "Left unsecured"], "correct": 0, "re": "Use a duty-rated ladder at ~4:1 angle, extended ~3 ft above the landing, secured; avoid metal ladders near electrical lines.", "rr": "Используйте лестницу под нагрузку под углом ~4:1, с выступом ~3 фута над площадкой, закреплённую; избегайте металлических лестниц у электролиний.", "qr": "Лестницы для доступа к оборудованию на крыше должны быть:", "optsr": ["Рассчитаны на нагрузку, под безопасным углом, выступать над краем крыши", "Алюминиевыми у ЛЭП", "Любой длины и под любым углом", "Незакреплёнными"]}, {"id": 199, "sec": "Safety & Field Practices", "q": "Proper lifting technique to avoid back injury when moving equipment is to:", "opts": ["Lift with the legs, keep the load close, avoid twisting", "Bend at the waist and twist", "Use the fastest motion", "Always lift alone"], "correct": 0, "re": "Bend the knees, keep the back straight and load near the body, and pivot the feet instead of twisting; get help or use equipment for heavy units.", "rr": "Сгибайте колени, держите спину прямо и груз близко к телу, поворачивайтесь стопами, а не скручиванием; для тяжёлого зовите помощь или используйте технику.", "qr": "Правильная техника подъёма для защиты спины при перемещении оборудования —", "optsr": ["Поднимать ногами, держать груз близко, не скручиваться", "Согнуться в пояснице и скручиваться", "Двигаться максимально быстро", "Всегда поднимать в одиночку"]}, {"id": 200, "sec": "Safety & Field Practices", "q": "Before reconnecting power and leaving a job, the technician should confirm all safety devices (limits, pressure switches, flame sensor) are:", "opts": ["Removed", "Bypassed for reliability", "Painted", "Functional and not jumpered/defeated"], "correct": 3, "re": "Never leave safety controls jumpered or disabled; verify all limits, pressure switches, float switches, and flame proving operate so the system fails safe.", "rr": "Никогда не оставляйте защиты зашунтированными или отключёнными; проверьте, что все лимиты, реле давления, поплавковые выключатели и контроль пламени работают, чтобы система отказывала безопасно.", "qr": "Перед подачей питания и завершением работы техник должен убедиться, что все защитные устройства (лимиты, реле давления, датчик пламени):", "optsr": ["Сняты", "Зашунтированы для надёжности", "Покрашены", "Исправны и не зашунтированы/не отключены"]}, {"id": 201, "sec": "Principles & Load Calculations", "q": "One ton of refrigeration is equal to:", "opts": ["100,000 BTU/h", "1,000 BTU/h", "500 watts", "12,000 BTU/h"], "correct": 3, "re": "A ton of refrigeration = 12,000 BTU/h, the rate to melt one ton of ice in 24 hours (288,000 BTU ÷ 24 h).", "rr": "Тонна холода = 12 000 BTU/ч — скорость плавления одной тонны льда за 24 часа (288 000 BTU ÷ 24 ч).", "qr": "Одна тонна холода (ton of refrigeration) равна:", "optsr": ["100 000 BTU/ч", "1 000 BTU/ч", "500 ватт", "12 000 BTU/ч"]}, {"id": 202, "sec": "Principles & Load Calculations", "q": "Latent heat of vaporization is the heat absorbed when a substance:", "opts": ["Loses pressure", "Freezes", "Rises in temperature", "Changes from liquid to vapor with no temperature change"], "correct": 3, "re": "Latent heat changes state (liquid↔vapor) at constant temperature; this phase change in the evaporator/condenser is how refrigeration moves heat.", "rr": "Latent heat меняет состояние (жидкость↔пар) при постоянной температуре; этот фазовый переход в испарителе/конденсаторе и переносит тепло.", "qr": "Скрытая теплота парообразования (latent heat) — это тепло, поглощаемое при:", "optsr": ["Падении давления", "Замерзании", "Росте температуры", "Переходе жидкости в пар без изменения температуры"]}, {"id": 203, "sec": "Principles & Load Calculations", "q": "In the basic refrigeration cycle, the component that raises refrigerant pressure and temperature is the:", "opts": ["Metering device", "Condenser", "Compressor", "Evaporator"], "correct": 2, "re": "The compressor raises the low-pressure vapor to high pressure/temperature so it can reject heat in the condenser.", "rr": "Компрессор поднимает пар низкого давления до высокого давления/температуры, чтобы тот отдал тепло в конденсаторе.", "qr": "В базовом холодильном цикле компонент, повышающий давление и температуру хладагента, — это:", "optsr": ["Дозатор", "Конденсатор", "Компрессор", "Испаритель"]}, {"id": 204, "sec": "Principles & Load Calculations", "q": "The metering device (e.g., TXV or piston) in the cycle:", "opts": ["Compresses vapor", "Drops pressure and meters liquid into the evaporator", "Adds heat", "Stores oil"], "correct": 1, "re": "The metering device creates the pressure drop between high and low sides and controls liquid refrigerant flow into the evaporator.", "rr": "Дозатор создаёт перепад давления между высокой и низкой сторонами и регулирует подачу жидкого хладагента в испаритель.", "qr": "Дозатор (TXV или piston) в цикле:", "optsr": ["Сжимает пар", "Снижает давление и дозирует жидкость в испаритель", "Добавляет тепло", "Хранит масло"]}, {"id": 205, "sec": "Principles & Load Calculations", "q": "In a cooling system, the evaporator:", "opts": ["Raises pressure", "Absorbs heat from the indoor air", "Stores liquid", "Rejects heat to outdoors"], "correct": 1, "re": "The evaporator absorbs indoor heat as refrigerant boils to vapor; the condenser rejects that heat outdoors.", "rr": "Испаритель поглощает тепло помещения, пока хладагент кипит в пар; конденсатор отдаёт это тепло наружу.", "qr": "В системе охлаждения испаритель:", "optsr": ["Повышает давление", "Поглощает тепло из внутреннего воздуха", "Хранит жидкость", "Отдаёт тепло наружу"]}, {"id": 206, "sec": "Principles & Load Calculations", "q": "The compression ratio of a refrigeration compressor is the ratio of:", "opts": ["Absolute discharge pressure to absolute suction pressure", "Suction to discharge temperature", "CFM to tonnage", "Voltage to amperage"], "correct": 0, "re": "Compression ratio = absolute discharge pressure / absolute suction pressure (psia, not psig). A higher ratio lowers volumetric efficiency and raises discharge temperature.", "rr": "Compression ratio = абсолютное давление нагнетания / абсолютное давление всасывания (psia, не psig). Выше степень - ниже объёмный КПД и выше температура нагнетания.", "qr": "Степень сжатия (compression ratio) холодильного компрессора - это отношение:", "optsr": ["Абсолютного давления нагнетания к абсолютному давлению всасывания", "Температуры всасывания к нагнетанию", "CFM к тоннажу", "Напряжения к току"]}, {"id": 207, "sec": "Principles & Load Calculations", "q": "In a refrigeration system, the high side (discharge side) includes the components between the:", "opts": ["Two service valves only", "Thermostat and the fuse", "Compressor discharge and the metering device", "Evaporator inlet and compressor inlet"], "correct": 2, "re": "The high (discharge) side runs from the compressor outlet through the condenser to the metering device; the low (suction) side runs from the metering-device outlet through the evaporator back to the compressor.", "rr": "Сторона высокого (нагнетания) идёт от выхода компрессора через конденсатор до дозатора; сторона низкого (всасывания) - от выхода дозатора через испаритель обратно к компрессору.", "qr": "В холодильной системе сторона высокого давления (high side) включает компоненты между:", "optsr": ["Только двумя сервисными вентилями", "Термостатом и предохранителем", "Нагнетанием компрессора и дозатором", "Входом испарителя и входом компрессора"]}, {"id": 208, "sec": "Principles & Load Calculations", "q": "Compared with R-22, R-410A operates at:", "opts": ["Significantly higher pressures", "Identical pressures", "No pressure", "Much lower pressures"], "correct": 0, "re": "R-410A runs roughly 50–70% higher pressures than R-22, so it requires equipment, gauges, and components rated for the higher pressure.", "rr": "R-410A работает примерно на 50–70% выше по давлению, чем R-22, поэтому нужны оборудование, манометры и компоненты под более высокое давление.", "qr": "По сравнению с R-22, R-410A работает при:", "optsr": ["Значительно более высоком давлении", "Точно таком же давлении", "Без давления", "Гораздо более низком давлении"]}, {"id": 209, "sec": "Principles & Load Calculations", "q": "A zeotropic refrigerant blend (e.g., R-407C) exhibits 'temperature glide,' which means:", "opts": ["It has one boiling point", "Its components boil/condense over a range of temperatures", "It is an azeotrope", "It cannot be used"], "correct": 1, "re": "Zeotropic blends change phase over a temperature range (glide); to avoid fractionation they are charged as liquid, and glide is accounted for in superheat/subcooling.", "rr": "Зеотропные смеси меняют фазу в диапазоне температур (glide); чтобы избежать фракционирования, их заправляют жидкостью, а glide учитывают в superheat/subcooling.", "qr": "Зеотропная смесь хладагента (например R-407C) имеет «температурный глайд», то есть:", "optsr": ["Одну точку кипения", "Её компоненты кипят/конденсируются в диапазоне температур", "Это азеотроп", "Её нельзя применять"]}, {"id": 210, "sec": "Principles & Load Calculations", "q": "POE (polyolester) oil is required with which refrigerants?", "opts": ["R-22 (mineral oil)", "HFCs such as R-410A", "Only ammonia", "No refrigerant needs oil"], "correct": 1, "re": "HFC systems (R-410A, R-407C) use POE oil; R-22 used mineral oil. POE is hygroscopic, so keep it sealed and evacuate well.", "rr": "Системы HFC (R-410A, R-407C) используют POE; R-22 — минеральное масло. POE гигроскопично, держите его закрытым и тщательно вакуумируйте.", "qr": "Масло POE (polyolester) требуется с какими хладагентами?", "optsr": ["R-22 (минеральное масло)", "HFC, например R-410A", "Только с аммиаком", "Хладагенту масло не нужно"]}, {"id": 211, "sec": "Principles & Load Calculations", "q": "The R-value of insulation is a measure of its:", "opts": ["Weight", "Thermal resistance (higher = better insulator)", "Cost", "Color"], "correct": 1, "re": "R-value quantifies resistance to heat flow; higher R means less heat transfer. U-value (overall conductance) is its reciprocal.", "rr": "R-value — сопротивление тепловому потоку; больше R = меньше теплопередача. U-value (общая проводимость) — обратная величина.", "qr": "R-value изоляции — это мера её:", "optsr": ["Веса", "Термического сопротивления (больше = лучше изолятор)", "Стоимости", "Цвета"]}, {"id": 212, "sec": "Principles & Load Calculations", "q": "Ohm's law states that voltage equals:", "opts": ["Power × time", "Current ÷ resistance", "Resistance ÷ current", "Current × resistance (V = I × R)"], "correct": 3, "re": "Ohm's law: V = I × R. It lets technicians calculate any one value (voltage, current, resistance) from the other two.", "rr": "Закон Ома: V = I × R. Позволяет вычислить любую из величин (напряжение, ток, сопротивление) по двум другим.", "qr": "Закон Ома гласит, что напряжение равно:", "optsr": ["Мощность × время", "Ток ÷ сопротивление", "Сопротивление ÷ ток", "Ток × сопротивление (V = I × R)"]}, {"id": 213, "sec": "Principles & Load Calculations", "q": "For a resistive load, electrical power in watts equals:", "opts": ["Volts × amps", "Volts ÷ amps", "Amps ÷ ohms", "Volts × ohms"], "correct": 0, "re": "Power (W) = volts × amps (P = V × I) for resistive loads; this is used to size circuits and estimate electric-heat consumption.", "rr": "Мощность (Вт) = вольты × амперы (P = V × I) для резистивной нагрузки; используется для подбора цепей и оценки потребления электронагрева.", "qr": "Для резистивной нагрузки электрическая мощность в ваттах равна:", "optsr": ["Вольты × амперы", "Вольты ÷ амперы", "Амперы ÷ омы", "Вольты × омы"]}, {"id": 214, "sec": "Principles & Load Calculations", "q": "The approximate heating value of natural gas is about:", "opts": ["100 BTU per cubic foot", "1,000 BTU per cubic foot", "1,000,000 BTU per cubic foot", "10 BTU per cubic foot"], "correct": 1, "re": "Natural gas is roughly 1,000 BTU per cubic foot; this is used with metered gas flow to find a furnace's input rate.", "rr": "Природный газ — примерно 1 000 BTU на куб. фут; вместе с замером расхода газа даёт входную мощность печи.", "qr": "Примерная теплотворность природного газа составляет около:", "optsr": ["100 BTU на куб. фут", "1 000 BTU на куб. фут", "1 000 000 BTU на куб. фут", "10 BTU на куб. фут"]}, {"id": 215, "sec": "Principles & Load Calculations", "q": "'Clocking the gas meter' lets a technician determine a furnace's:", "opts": ["Duct size", "SEER", "Input BTU/h (firing rate)", "Refrigerant charge"], "correct": 2, "re": "Timing the gas meter dial gives cubic feet per hour; multiplied by the heating value (~1,000 BTU/cf) it yields the input firing rate.", "rr": "Замер времени по диску счётчика даёт куб. футы в час; умножив на теплотворность (~1 000 BTU/cf), получают входную мощность горения.", "qr": "«Clocking the gas meter» (хронометраж счётчика газа) позволяет определить:", "optsr": ["Размер дакта", "SEER", "Входную мощность BTU/ч (firing rate)", "Заправку хладагентом"]}, {"id": 216, "sec": "Principles & Load Calculations", "q": "The temperature rise across a gas furnace must fall within the range:", "opts": ["Set by the thermostat", "Always 20°F", "Listed on the furnace rating plate", "Always 100°F"], "correct": 2, "re": "Each furnace lists an allowable temperature-rise range on its rating plate; airflow is adjusted so the measured rise (return-to-supply) stays within it.", "rr": "У каждой печи на шильдике указан допустимый диапазон temperature rise; расход воздуха подбирают так, чтобы измеренный подъём (обратка→подача) был в нём.", "qr": "Температурный подъём (temperature rise) через газовую печь должен укладываться в диапазон:", "optsr": ["Заданный термостатом", "Всегда 20°F", "Указанный на шильдике печи", "Всегда 100°F"]}, {"id": 217, "sec": "Principles & Load Calculations", "q": "Gas-furnace airflow can be calculated from the formula CFM = output BTU/h ÷ (1.08 × ___):", "opts": ["Temperature rise", "Static pressure", "Superheat", "Voltage"], "correct": 0, "re": "Rearranging Q = 1.08 × CFM × ΔT gives CFM = output ÷ (1.08 × temperature rise) — a field check of blower airflow on a furnace.", "rr": "Преобразуя Q = 1.08 × CFM × ΔT, получаем CFM = output ÷ (1.08 × temperature rise) — полевая проверка расхода вентилятора на печи.", "qr": "Расход воздуха печи можно найти по формуле CFM = output BTU/ч ÷ (1.08 × ___):", "optsr": ["Температурный подъём", "Статическое давление", "Superheat", "Напряжение"]}, {"id": 218, "sec": "Principles & Load Calculations", "q": "According to the fan laws, airflow (CFM) varies:", "opts": ["Not at all with RPM", "Inversely with RPM", "Directly (linearly) with blower RPM", "With the square of blower RPM"], "correct": 2, "re": "CFM is directly proportional to RPM; static pressure varies with RPM squared; horsepower varies with RPM cubed.", "rr": "CFM прямо пропорционален RPM; статическое давление — квадрату RPM; мощность — кубу RPM.", "qr": "Согласно законам вентилятора, расход (CFM) изменяется:", "optsr": ["Никак с оборотами", "Обратно оборотам", "Прямо (линейно) с оборотами вентилятора", "Пропорционально квадрату оборотов"]}, {"id": 219, "sec": "Principles & Load Calculations", "q": "By the fan laws, static pressure varies with:", "opts": ["RPM", "The cube of RPM", "The square root of RPM", "The square of RPM"], "correct": 3, "re": "Static pressure rises with the square of speed, and required horsepower with the cube — why small speed increases sharply raise power and noise.", "rr": "Статическое давление растёт с квадратом скорости, а потребная мощность — с кубом; поэтому малый рост оборотов резко повышает мощность и шум.", "qr": "По законам вентилятора статическое давление изменяется с:", "optsr": ["Оборотами", "Кубом оборотов", "Корнем из оборотов", "Квадратом оборотов"]}, {"id": 220, "sec": "Principles & Load Calculations", "q": "Air velocity in a duct equals airflow (CFM) divided by:", "opts": ["The voltage", "The duct length", "The duct cross-sectional area (sq ft)", "The static pressure"], "correct": 2, "re": "Velocity (fpm) = CFM ÷ area (sq ft). Excessive velocity causes noise; too low causes poor air distribution.", "rr": "Скорость (fpm) = CFM ÷ площадь (кв. футы). Избыточная скорость даёт шум; слишком малая — плохое распределение воздуха.", "qr": "Скорость воздуха в воздуховоде равна расходу (CFM), делённому на:", "optsr": ["Напряжение", "Длину дакта", "Площадь поперечного сечения дакта (кв. футы)", "Статическое давление"]}, {"id": 221, "sec": "Principles & Load Calculations", "q": "Three-phase power is commonly used for larger HVAC motors because it:", "opts": ["Requires no protection", "Is cheaper to install everywhere", "Delivers smoother power, allowing smaller, more efficient motors", "Uses one wire"], "correct": 2, "re": "Three-phase delivers more constant power, so motors are smaller, run cooler/more efficiently, and start without start components.", "rr": "Трёхфазное даёт более постоянную мощность, поэтому двигатели меньше, работают холоднее/эффективнее и стартуют без пусковых элементов.", "qr": "Трёхфазное питание часто применяют для крупных HVAC-двигателей, потому что оно:", "optsr": ["Не требует защиты", "Везде дешевле в монтаже", "Даёт более ровную мощность — двигатели меньше и эффективнее", "Использует один провод"]}, {"id": 222, "sec": "Principles & Load Calculations", "q": "An 'equivalent round' duct dimension is used to:", "opts": ["Convert a rectangular duct to the round size with equal friction/airflow", "Set the thermostat", "Measure refrigerant", "Size the breaker"], "correct": 0, "re": "Friction charts are based on round duct; the equivalent-round value lets you size rectangular ducts to the same friction loss for a given airflow.", "rr": "Таблицы трения построены для круглого дакта; эквивалентно-круглое значение позволяет подобрать прямоугольный дакт под то же трение при заданном расходе.", "qr": "Размер «эквивалентного круглого» воздуховода используется для:", "optsr": ["Перевода прямоугольного дакта в круглый с равным трением/расходом", "Настройки термостата", "Замера хладагента", "Подбора автомата"]}, {"id": 223, "sec": "Principles & Load Calculations", "q": "An undersized return-air system will typically cause:", "opts": ["Lower energy use", "High static pressure and reduced airflow (starved blower)", "More cooling capacity", "Lower static pressure"], "correct": 1, "re": "Too little return area raises return-side static, starving the blower; airflow drops, harming capacity and risking coil freeze or furnace limit trips.", "rr": "Малая площадь обратки повышает статическое на обратной стороне, обедняя вентилятор; расход падает, страдает производительность, риск обмерзания или срабатывания лимита печи.", "qr": "Заниженная система обратного воздуха обычно вызывает:", "optsr": ["Меньше энергопотребления", "Высокое статическое и сниженный расход (обеднённый вентилятор)", "Больше холодопроизводительности", "Снижение статического давления"]}, {"id": 224, "sec": "Principles & Load Calculations", "q": "In estimating, 'margin' differs from 'markup' in that margin is profit expressed as a percentage of:", "opts": ["Labor only", "The selling price", "Material only", "Cost"], "correct": 1, "re": "Margin = profit ÷ selling price; markup = profit ÷ cost. The same dollar profit is a smaller margin % than markup %, a common pricing error.", "rr": "Margin = прибыль ÷ цена продажи; markup = прибыль ÷ себестоимость. Та же сумма прибыли даёт меньший % margin, чем % markup — частая ошибка ценообразования.", "qr": "В сметах «margin» отличается от «markup» тем, что margin — это прибыль в процентах от:", "optsr": ["Только труда", "Цены продажи", "Только материала", "Себестоимости"]}, {"id": 225, "sec": "Principles & Load Calculations", "q": "A change order is used to:", "opts": ["Schedule an inspection", "Order refrigerant", "Document added/changed scope and its cost beyond the original contract", "Cancel the license"], "correct": 2, "re": "A written change order records work added or changed after the contract, with the agreed price and signatures — protecting both parties.", "rr": "Письменный change order фиксирует добавленную или изменённую после договора работу с согласованной ценой и подписями — защита обеих сторон.", "qr": "Change order (изменение к договору) служит для:", "optsr": ["Назначения инспекции", "Заказа хладагента", "Фиксации добавленного/изменённого объёма и его стоимости сверх договора", "Аннулирования лицензии"]}, {"id": 226, "sec": "Fabrication & Installation", "q": "A 45° SAE flare connection is used to:", "opts": ["Seal ductwork", "Braze copper to steel", "Connect gas vents", "Make a mechanical, gasket-free seal on soft copper (mini-splits, valves)"], "correct": 3, "re": "A properly made 45° flare seats metal-to-metal under the flare nut, giving a serviceable refrigerant connection without brazing.", "rr": "Правильный flare 45° садится металл-по-металлу под накидной гайкой, давая обслуживаемое холодильное соединение без пайки.", "qr": "Развальцовка 45° SAE (flare) применяется для:", "optsr": ["Герметизации воздуховодов", "Пайки меди к стали", "Соединения газовых дымоходов", "Механического соединения мягкой меди без прокладки (мини-сплиты, вентили)"]}, {"id": 227, "sec": "Fabrication & Installation", "q": "After cutting copper tubing, the technician should ream/deburr the end to:", "opts": ["Harden the copper", "Add flux", "Remove burrs that cause turbulence and debris in the system", "Increase diameter"], "correct": 2, "re": "Burrs restrict flow, create turbulence, and can break loose to foul metering devices; ream the inside and deburr before assembly.", "rr": "Заусенцы сужают поток, создают турбулентность и могут отколоться, засоряя дозаторы; снимайте внутренний заусенец и грат перед сборкой.", "qr": "После резки медной трубы конец нужно развернуть/снять заусенцы (ream/deburr), чтобы:", "optsr": ["Закалить медь", "Добавить флюс", "Убрать заусенцы, дающие турбулентность и мусор в системе", "Увеличить диаметр"]}, {"id": 228, "sec": "Fabrication & Installation", "q": "Among silver brazing alloys, those with higher silver content generally:", "opts": ["Require no heat", "Are weaker", "Flow at lower temperatures", "Cannot join copper"], "correct": 2, "re": "Higher-silver alloys melt/flow at lower temperatures and wet well, useful on dissimilar metals; lower-silver BCuP is common copper-to-copper.", "rr": "Сплавы с бо́льшим серебром плавятся/текут при более низкой температуре и хорошо смачивают; полезны на разнородных металлах; BCuP с меньшим серебром — типично медь-медь.", "qr": "Среди серебряных припоев сплавы с бо́льшим содержанием серебра обычно:", "optsr": ["Не требуют нагрева", "Слабее", "Текут при более низкой температуре", "Не соединяют медь"]}, {"id": 229, "sec": "Fabrication & Installation", "q": "Soft solder (e.g., 95/5) is acceptable for ___ but NOT for refrigerant joints:", "opts": ["Water/condensate lines", "Gas piping", "Electrical wire", "High-pressure refrigerant lines"], "correct": 0, "re": "Soft solder melts at low temperature and lacks the strength for refrigerant pressures; it's used on water/drain lines, while refrigerant joints are brazed.", "rr": "Мягкий припой плавится при низкой температуре и не выдерживает холодильных давлений; его применяют на водяных/дренажных линиях, а холодильные соединения паяют твёрдым припоем.", "qr": "Мягкий припой (например 95/5) допустим для ___, но НЕ для холодильных соединений:", "optsr": ["Водяных/дренажных линий", "Газовых труб", "Электропроводки", "Холодильных линий высокого давления"]}, {"id": 230, "sec": "Fabrication & Installation", "q": "Molten brazing alloy is drawn into a properly fitted joint by:", "opts": ["Refrigerant pressure", "Gravity only", "Electrical attraction", "Capillary action"], "correct": 3, "re": "Capillary action pulls the molten filler into the small, even gap between tube and fitting, so correct clearance and cleanliness are essential.", "rr": "Капиллярный эффект втягивает расплав в малый равномерный зазор между трубой и фитингом, поэтому важны правильный зазор и чистота.", "qr": "Расплавленный припой втягивается в правильно подогнанный стык за счёт:", "optsr": ["Давления хладагента", "Только силы тяжести", "Электрического притяжения", "Капиллярного эффекта"]}, {"id": 231, "sec": "Fabrication & Installation", "q": "Copper wire (60/75°C) ampacity is commonly: #14 = 15 A, #12 = 20 A, and #10 = ___:", "opts": ["10 A", "100 A", "50 A", "30 A"], "correct": 3, "re": "Common branch-circuit copper ampacities: 14 AWG=15 A, 12 AWG=20 A, 10 AWG=30 A, 8 AWG=40 A — always confirm with the code table and conditions.", "rr": "Типовая ампачность ответвлений (медь): 14 AWG=15 A, 12 AWG=20 A, 10 AWG=30 A, 8 AWG=40 A — всегда сверяйтесь с таблицей норм и условиями.", "qr": "Ампачность медного провода (60/75°C) обычно: #14 = 15 A, #12 = 20 A, а #10 = ___:", "optsr": ["10 A", "100 A", "50 A", "30 A"]}, {"id": 232, "sec": "Fabrication & Installation", "q": "The equipment grounding conductor's main purpose is to:", "opts": ["Increase voltage", "Provide a low-resistance fault path so the breaker trips on a ground fault", "Improve SEER", "Carry normal load current"], "correct": 1, "re": "The ground conductor gives fault current a safe path back to the source, tripping the overcurrent device and keeping enclosures from becoming energized.", "rr": "Заземляющий проводник даёт току КЗ безопасный путь к источнику, отключая защиту и не давая корпусам оказаться под напряжением.", "qr": "Главная задача защитного заземляющего проводника:", "optsr": ["Повысить напряжение", "Дать низкоомный путь тока КЗ, чтобы автомат отключился при замыкании на землю", "Улучшить SEER", "Нести нормальный рабочий ток"]}, {"id": 233, "sec": "Fabrication & Installation", "q": "A hard-start kit (start capacitor with a potential relay or PTCR) is added to:", "opts": ["Boost starting torque on a hard-starting compressor", "Remove refrigerant", "Lower the voltage", "Slow the compressor"], "correct": 0, "re": "A hard-start device gives extra starting torque (and quick disconnect after start) to help a compressor that struggles to start, e.g., under high head.", "rr": "Hard-start даёт дополнительный пусковой момент (и быстрое отключение после пуска), помогая компрессору, который трудно стартует, например при высоком напоре.", "qr": "Hard-start kit (пусковой конденсатор с потенциальным реле или PTCR) добавляют, чтобы:", "optsr": ["Повысить пусковой момент у тяжело пускающегося компрессора", "Удалить хладагент", "Снизить напряжение", "Замедлить компрессор"]}, {"id": 234, "sec": "Fabrication & Installation", "q": "A crankcase heater on a compressor is used to:", "opts": ["Cool the oil", "Increase head pressure", "Keep refrigerant from migrating/condensing into the compressor oil during the off cycle", "Add refrigerant"], "correct": 2, "re": "The crankcase heater keeps the oil warm so refrigerant doesn't condense into it during off cycles, preventing dilution and damaging slugging at startup.", "rr": "Подогреватель картера держит масло тёплым, чтобы хладагент не конденсировался в него при простое, предотвращая разбавление и опасный гидроудар при пуске.", "qr": "Подогреватель картера компрессора нужен, чтобы:", "optsr": ["Охлаждать масло", "Поднять давление нагнетания", "Не дать хладагенту мигрировать/конденсироваться в масло компрессора во время простоя", "Добавить хладагент"]}, {"id": 235, "sec": "Fabrication & Installation", "q": "Low-ambient head-pressure control (fan cycling or condenser flooding) is used so a system can:", "opts": ["Heat faster", "Save refrigerant", "Cool reliably in cold outdoor temperatures by keeping head pressure up", "Skip the metering device"], "correct": 2, "re": "In cold weather head pressure can fall too low for the metering device to feed properly; low-ambient controls maintain adequate head pressure for mechanical cooling.", "rr": "В холод давление нагнетания может упасть слишком низко для нормальной подачи дозатором; low-ambient контроль удерживает достаточный напор для механического охлаждения.", "qr": "Контроль давления нагнетания при низкой наружной температуре (fan cycling или затопление конденсатора) нужен, чтобы система могла:", "optsr": ["Быстрее греть", "Экономить хладагент", "Надёжно охлаждать в холод, удерживая давление нагнетания", "Обойтись без дозатора"]}, {"id": 236, "sec": "Fabrication & Installation", "q": "A sequencer in an electric-heat furnace is used to:", "opts": ["Meter refrigerant", "Open the gas valve", "Cool the coil", "Stagger the heating elements on/off to limit inrush current"], "correct": 3, "re": "Sequencers energize electric heat strips in steps, so they don't all draw inrush current at once — reducing electrical stress and flicker.", "rr": "Секвенсор включает ТЭНы ступенями, чтобы они не брали пусковой ток разом — снижая электрическую нагрузку и мерцание.", "qr": "Секвенсор в электропечи нужен, чтобы:", "optsr": ["Дозировать хладагент", "Открывать газовый клапан", "Охлаждать испаритель", "Поэтапно включать/выключать ТЭНы, ограничивая пусковой ток"]}, {"id": 237, "sec": "Fabrication & Installation", "q": "Gas piping is sized based on required CFH, pipe length, and:", "opts": ["SEER", "Duct gauge", "Allowable pressure drop (per sizing tables)", "Refrigerant type"], "correct": 2, "re": "Pipe-sizing tables use the demand (CFH), the longest length, and the allowable pressure drop to pick a diameter that delivers enough gas to all appliances.", "rr": "Таблицы подбора используют потребление (CFH), наибольшую длину и допустимый перепад давления, чтобы выбрать диаметр, дающий достаточно газа всем приборам.", "qr": "Газовые трубы подбирают по требуемому CFH, длине трубы и:", "optsr": ["SEER", "Толщине дакта", "Допустимому перепаду давления (по таблицам)", "Типу хладагента"]}, {"id": 238, "sec": "Fabrication & Installation", "q": "A sediment trap (drip leg) is installed near the gas valve to:", "opts": ["Vent flue gas", "Increase pressure", "Catch debris and moisture before it enters the gas valve", "Add air"], "correct": 2, "re": "The sediment trap collects rust, scale, and condensate so it doesn't reach and foul the gas valve/orifices.", "rr": "Грязевик собирает ржавчину, накипь и конденсат, чтобы они не попали в газовый клапан/жиклёры и не засорили их.", "qr": "Грязевик (sediment trap / drip leg) у газового клапана ставят, чтобы:", "optsr": ["Удалять дымовые газы", "Повысить давление", "Задержать мусор и влагу до входа в газовый клапан", "Добавлять воздух"]}, {"id": 239, "sec": "Fabrication & Installation", "q": "A manual gas shutoff valve must generally be installed:", "opts": ["Within 6 feet of the appliance and in the same room", "Inside the burner", "Anywhere in the house", "At the meter only"], "correct": 0, "re": "Code requires an accessible manual shutoff within about 6 ft of the appliance (same room) so gas can be quickly isolated for service.", "rr": "Нормы требуют доступный ручной запор примерно в 6 футах от прибора (в том же помещении), чтобы быстро перекрыть газ для обслуживания.", "qr": "Ручной газовый запорный вентиль обычно должен устанавливаться:", "optsr": ["В пределах 6 футов от прибора и в том же помещении", "Внутри горелки", "Где угодно в доме", "Только у счётчика"]}, {"id": 240, "sec": "Fabrication & Installation", "q": "A Type B (double-wall) gas vent must maintain its listed clearance to combustibles, typically:", "opts": ["0 inches", "36 inches", "12 inches", "About 1 inch"], "correct": 3, "re": "Type B vent is listed for about 1 in clearance to combustibles; single-wall connectors require much larger clearances — always follow the listing.", "rr": "Type B рассчитан примерно на 1 дюйм зазора до горючих; одностенные соединители требуют гораздо больших зазоров — всегда по листингу.", "qr": "Газовый дымоход Type B (двустенный) должен сохранять нормированный зазор до горючих, обычно:", "optsr": ["0 дюймов", "36 дюймов", "12 дюймов", "Около 1 дюйма"]}, {"id": 241, "sec": "Fabrication & Installation", "q": "A vent connector for an atmospheric appliance should slope:", "opts": ["Upward toward the chimney (e.g., ≥1/4 in per foot)", "Be perfectly level", "Loop downward", "Downward away from the chimney"], "correct": 0, "re": "An upward slope toward the chimney promotes natural draft and prevents flue-gas/condensate pooling that would block venting.", "rr": "Уклон вверх к дымоходу способствует естественной тяге и не даёт скапливаться дымовым газам/конденсату, что блокировало бы удаление.", "qr": "Соединительный дымоход атмосферного прибора должен иметь уклон:", "optsr": ["Вверх к дымоходу (например ≥1/4 дюйма на фут)", "Строго горизонтально", "Петлёй вниз", "Вниз от дымохода"]}, {"id": 242, "sec": "Fabrication & Installation", "q": "A Pittsburgh lock, drive cleats, and S-cleats are all used in:", "opts": ["Electrical conduit", "Refrigerant piping", "Sheet-metal duct seams and joints", "Gas venting"], "correct": 2, "re": "These are sheet-metal connections: the Pittsburgh lock forms a longitudinal seam, while drive and S cleats join duct sections transversely.", "rr": "Это соединения листового металла: Pittsburgh lock образует продольный шов, а drive- и S-cleats соединяют секции дакта поперечно.", "qr": "Pittsburgh lock, drive cleats и S-cleats применяются в:", "optsr": ["Электрических трубах", "Холодильных трубах", "Швах и стыках металлических воздуховодов", "Газовом дымоудалении"]}, {"id": 243, "sec": "Fabrication & Installation", "q": "A hot-surface igniter (HSI) is best checked by measuring its:", "opts": ["Voltage only", "Airflow", "Resistance (ohms) when cold, compared to spec", "Refrigerant charge"], "correct": 2, "re": "A cold-resistance (ohms) reading outside the manufacturer's range indicates a cracked or aged igniter; visually inspect for cracks too.", "rr": "Сопротивление в холодном состоянии вне диапазона производителя указывает на треснувший или состарившийся игнайтер; осмотрите и на трещины.", "qr": "Hot-surface igniter (HSI) лучше всего проверять, измеряя его:", "optsr": ["Только напряжение", "Расход воздуха", "Сопротивление (омы) в холодном состоянии и сравнивая со спецификацией", "Заправку хладагентом"]}, {"id": 244, "sec": "Fabrication & Installation", "q": "Combustion analysis at startup measures CO, stack temperature, and:", "opts": ["Voltage", "Oxygen/CO₂ in the flue gas", "Duct size", "SEER"], "correct": 1, "re": "A combustion analyzer reads O₂/CO₂, CO, and stack temperature to confirm complete, safe, efficient combustion and proper venting.", "rr": "Газоанализатор читает O₂/CO₂, CO и температуру отходящих газов, подтверждая полное, безопасное, эффективное сгорание и нормальное дымоудаление.", "qr": "Анализ горения при пуске измеряет CO, температуру дымовых газов и:", "optsr": ["Напряжение", "Кислород/CO₂ в дымовых газах", "Размер дакта", "SEER"]}, {"id": 245, "sec": "Fabrication & Installation", "q": "A flow hood (balometer) is used during startup to measure:", "opts": ["Flame temperature", "Airflow (CFM) at a register or grille", "Gas pressure", "Refrigerant pressure"], "correct": 1, "re": "A flow hood captures and reads the CFM delivered at a supply or return register, useful for air balancing and verifying design airflow.", "rr": "Flow hood накрывает решётку и считывает CFM на подаче или обратке — полезно для балансировки и проверки расчётного расхода.", "qr": "Flow hood (балометр) при пуске используют для измерения:", "optsr": ["Температуры пламени", "Расхода воздуха (CFM) на решётке", "Давления газа", "Давления хладагента"]}, {"id": 246, "sec": "Fabrication & Installation", "q": "When charging a ductless mini-split, the factory charge typically covers a set line length, and the tech must:", "opts": ["Use water", "Always remove refrigerant", "Skip evacuation", "Add refrigerant for line length beyond the included amount"], "correct": 3, "re": "Mini-splits ship pre-charged for a base line length (e.g., 15–25 ft); longer line sets require adding the per-foot amount from the install manual.", "rr": "Мини-сплиты заправлены на базовую длину линий (например 15–25 футов); более длинные требуют долива по норме на фут из инструкции.", "qr": "При заправке бесканального мини-сплита заводская заправка обычно рассчитана на заданную длину линий, и техник должен:", "optsr": ["Использовать воду", "Всегда удалять хладагент", "Пропустить вакуумирование", "Добавить хладагент за длину линий сверх включённой"]}, {"id": 247, "sec": "Fabrication & Installation", "q": "In a triple evacuation, dry nitrogen is introduced between vacuum pulls to:", "opts": ["Add refrigerant", "Pressurize for leak test", "Break the vacuum and help sweep out remaining moisture", "Cool the pump"], "correct": 2, "re": "Breaking vacuum with dry nitrogen dilutes and carries off residual moisture; repeating the pull/sweep reaches a dry system more reliably.", "rr": "Срыв вакуума сухим азотом разбавляет и уносит остаточную влагу; повтор откачки/продувки надёжнее доводит систему до сухого состояния.", "qr": "При тройном вакуумировании между откачками вводят сухой азот, чтобы:", "optsr": ["Добавить хладагент", "Опрессовать для теста утечки", "Сорвать вакуум и помочь вымести остаточную влагу", "Охладить насос"]}, {"id": 248, "sec": "Fabrication & Installation", "q": "For an accurate vacuum reading, the micron gauge should be placed:", "opts": ["On the system, as far from the pump as practical", "Inside the compressor", "At the vacuum pump inlet", "On the gas line"], "correct": 0, "re": "Reading at the pump shows the pump's vacuum, not the system's; mount the micron gauge on the system (e.g., opposite end) to confirm the whole system is evacuated.", "rr": "Измерение у насоса показывает вакуум насоса, а не системы; ставьте микронный датчик на систему (например на дальнем конце), чтобы подтвердить вакуум всей системы.", "qr": "Для точного измерения вакуума микронный вакуумметр следует ставить:", "optsr": ["На системе, как можно дальше от насоса", "Внутри компрессора", "На входе вакуумного насоса", "На газовой линии"]}, {"id": 249, "sec": "Fabrication & Installation", "q": "A flexible 'whip' (sealtight) conduit between the disconnect and condenser is used to:", "opts": ["Vent gas", "Drain condensate", "Allow for vibration/movement while protecting the wiring", "Carry refrigerant"], "correct": 2, "re": "The flexible whip protects branch-circuit conductors at the unit while allowing for vibration and slight movement of the outdoor equipment.", "rr": "Гибкий whip защищает проводники ответвления у блока, допуская вибрацию и небольшие перемещения наружного оборудования.", "qr": "Гибкий «whip» (sealtight) между разъединителем и конденсатором служит, чтобы:", "optsr": ["Удалять газ", "Сливать конденсат", "Допустить вибрацию/движение, защищая проводку", "Нести хладагент"]}, {"id": 250, "sec": "Fabrication & Installation", "q": "Condensate from a high-efficiency condensing furnace is mildly acidic, so a ___ is often required:", "opts": ["Bigger filter", "Larger gas line", "Condensate neutralizer", "Hard-start kit"], "correct": 2, "re": "Condensing-furnace condensate is acidic (low pH); a neutralizer kit protects metal drains and meets local discharge requirements.", "rr": "Конденсат конденсационной печи кислый (низкий pH); нейтрализатор защищает металлические дренажи и отвечает местным требованиям к сбросу.", "qr": "Конденсат высокоэффективной конденсационной печи слабокислый, поэтому часто требуется:", "optsr": ["Бо́льший фильтр", "Бо́льшая газовая линия", "Нейтрализатор конденсата", "Hard-start kit"]}, {"id": 251, "sec": "Fabrication & Installation", "q": "A condensate safety float switch is wired:", "opts": ["In parallel with line voltage", "To the compressor windings", "To the gas valve only", "In series with the control circuit to shut the unit off on high water"], "correct": 3, "re": "The float switch opens the 24 V control circuit when the pan/line backs up, stopping the system before water overflows and causes damage.", "rr": "Поплавок размыкает цепь управления 24 В при переполнении поддона/линии, останавливая систему до перелива воды и порчи.", "qr": "Поплавковый аварийный выключатель конденсата подключают:", "optsr": ["Параллельно линейному напряжению", "К обмоткам компрессора", "Только к газовому клапану", "Последовательно в цепь управления, чтобы отключить блок при высокой воде"]}, {"id": 252, "sec": "Fabrication & Installation", "q": "Service (king/queen) valves on a condenser are 'back-seated' to:", "opts": ["Isolate the gauge ports while leaving the system open to flow", "Pump the system down", "Vent refrigerant", "Add oil"], "correct": 0, "re": "Back-seating opens the system flow path and closes the service port; front-seating isolates the condenser (used in pump-down).", "rr": "Back-seat открывает путь потока системы и закрывает сервисный порт; front-seat изолирует конденсатор (используется при pump-down).", "qr": "Сервисные вентили (king/queen) конденсатора «back-seat» (заднее седло) ставят, чтобы:", "optsr": ["Изолировать сервисные порты, оставив систему открытой для потока", "Откачать систему (pump down)", "Стравить хладагент", "Добавить масло"]}, {"id": 253, "sec": "Fabrication & Installation", "q": "'Pumping down' a system stores the refrigerant in the:", "opts": ["Evaporator", "Compressor oil", "Suction line", "Condenser/receiver (by closing the liquid valve and running until low suction)"], "correct": 3, "re": "Closing the liquid-line (king) valve and running the compressor pulls refrigerant into the condenser/receiver, isolating the low side for service.", "rr": "Закрыв жидкостный (king) вентиль и запустив компрессор, хладагент собирают в конденсатор/ресивер, изолируя низкую сторону для обслуживания.", "qr": "«Pump down» системы хранит хладагент в:", "optsr": ["Испарителе", "Масле компрессора", "Всасывающей линии", "Конденсаторе/ресивере (закрыв жидкостный вентиль и работая до низкого всасывания)"]}, {"id": 254, "sec": "Fabrication & Installation", "q": "A liquid-line filter drier must be installed:", "opts": ["In any direction", "Only on the suction line", "Upside down", "With its arrow pointing in the direction of refrigerant flow (toward the metering device)"], "correct": 3, "re": "The drier's flow arrow must point toward the evaporator/metering device; reversed installation impairs filtering and drying.", "rr": "Стрелка осушителя должна указывать к испарителю/дозатору; установка наоборот ухудшает фильтрацию и осушку.", "qr": "Жидкостный фильтр-осушитель нужно устанавливать:", "optsr": ["В любом направлении", "Только на всасывающую линию", "Вверх ногами", "Стрелкой по направлению потока хладагента (к дозатору)"]}, {"id": 255, "sec": "TR", "q": "Moisture in a refrigeration system is harmful because it can:", "opts": ["Freeze at the metering device and form acids with the oil", "Lower head pressure", "Increase subcooling", "Improve cooling"], "correct": 0, "re": "Moisture can freeze at the metering device (intermittent restriction) and react with POE oil/refrigerant to form acids that corrode and cause burnout.", "rr": "Влага может замерзать у дозатора (периодический засор) и реагировать с POE-маслом/хладагентом, образуя кислоты, которые корродируют и ведут к выгоранию.", "qr": "Влага в холодильной системе вредна, потому что может:", "optsr": ["Замерзать у дозатора и образовывать кислоты с маслом", "Снижать давление нагнетания", "Повышать subcooling", "Улучшить охлаждение"]}, {"id": 256, "sec": "TR", "q": "Non-condensable gases (such as air) in a system cause:", "opts": ["Head pressure higher than normal for the ambient/condensing temperature", "Better efficiency", "Low superheat", "Low head pressure"], "correct": 0, "re": "Air doesn't condense, so it occupies condenser volume and raises head pressure above what the ambient temperature alone would produce.", "rr": "Воздух не конденсируется, занимает объём конденсатора и поднимает давление нагнетания выше, чем дала бы одна наружная температура.", "qr": "Неконденсируемые газы (например воздух) в системе вызывают:", "optsr": ["Давление нагнетания выше нормы для данной наружной/конденсационной температуры", "Лучшую эффективность", "Низкий superheat", "Низкое давление нагнетания"]}, {"id": 257, "sec": "TR", "q": "Bubbles in the liquid-line sight glass (flash gas) usually indicate:", "opts": ["Low subcooling — undercharge or a restriction", "Overcharge", "High airflow", "A clean filter"], "correct": 0, "re": "Flash gas means the liquid isn't fully subcooled; common causes are undercharge or a liquid-line restriction (e.g., clogged drier).", "rr": "Flash gas означает, что жидкость недостаточно переохлаждена; частые причины — недозаправка или засор жидкостной линии (например забитый осушитель).", "qr": "Пузыри в смотровом стекле жидкостной линии (flash gas) обычно указывают на:", "optsr": ["Низкий subcooling — недозаправку или засор", "Перезаправку", "Высокий расход воздуха", "Чистый фильтр"]}, {"id": 258, "sec": "TR", "q": "A TXV stuck closed (or with a lost bulb charge) produces:", "opts": ["No change", "High superheat, low suction, low capacity", "Overcharge symptoms", "Low superheat, high suction"], "correct": 1, "re": "A closed/under-feeding TXV starves the evaporator: superheat climbs, suction pressure drops, and capacity falls.", "rr": "Закрытый/недоподающий TXV обедняет испаритель: superheat растёт, давление всасывания падает, производительность снижается.", "qr": "TXV, заклинивший закрытым (или с потерей заряда колбы), даёт:", "optsr": ["Без изменений", "Высокий superheat, низкое всасывание, малую производительность", "Симптомы перезаправки", "Низкий superheat, высокое всасывание"]}, {"id": 259, "sec": "TR", "q": "A TXV stuck open (overfeeding) produces:", "opts": ["Low suction", "Low superheat, high suction, and risk of liquid floodback", "High superheat", "No symptoms"], "correct": 1, "re": "An overfeeding valve floods the evaporator: superheat falls toward zero, suction rises, and liquid can return to the compressor (slugging risk).", "rr": "Переподающий клапан затапливает испаритель: superheat падает к нулю, всасывание растёт, жидкость может вернуться в компрессор (риск гидроудара).", "qr": "TXV, заклинивший открытым (переподаёт), даёт:", "optsr": ["Низкое всасывание", "Низкий superheat, высокое всасывание и риск возврата жидкости", "Высокий superheat", "Без симптомов"]}, {"id": 260, "sec": "TR", "q": "Liquid refrigerant returning to the compressor (floodback/slugging) is dangerous because liquid:", "opts": ["Improves lubrication", "Lowers amps", "Does not compress and can break valves/bearings", "Compresses easily"], "correct": 2, "re": "Liquid is essentially incompressible; slugging hammers the valves and washes oil from bearings, causing mechanical failure.", "rr": "Жидкость практически несжимаема; гидроудар бьёт по клапанам и смывает масло с подшипников, вызывая механический отказ.", "qr": "Возврат жидкого хладагента в компрессор (floodback/гидроудар) опасен тем, что жидкость:", "optsr": ["Улучшает смазку", "Снижает ток", "Не сжимается и может разрушить клапаны/подшипники", "Легко сжимается"]}, {"id": 261, "sec": "TR", "q": "On a single-phase compressor, the highest resistance reading is normally between:", "opts": ["Start and Run terminals", "Terminal and ground", "Common and Run", "Common and Start"], "correct": 0, "re": "C-R is lowest, C-S higher, and S-R is the sum (highest). Continuity to the shell/ground indicates a grounded (failed) compressor.", "rr": "C-R наименьшее, C-S больше, а S-R — сумма (наибольшее). Проводимость на корпус/землю указывает на пробитый (неисправный) компрессор.", "qr": "У однофазного компрессора наибольшее сопротивление обычно между:", "optsr": ["Клеммами Start и Run", "Клеммой и землёй", "Common и Run", "Common и Start"]}, {"id": 262, "sec": "TR", "q": "A compressor winding that reads infinite (OL) resistance indicates:", "opts": ["A good winding", "A grounded winding", "An open winding (or open internal overload)", "A shorted winding"], "correct": 2, "re": "Infinite resistance means the circuit is broken — an open winding or an open internal thermal overload (may reset when cooled).", "rr": "Бесконечное сопротивление = разрыв цепи — обрыв обмотки или разомкнутая внутренняя тепловая защита (может вернуться при остывании).", "qr": "Обмотка компрессора с бесконечным (OL) сопротивлением указывает на:", "optsr": ["Исправную обмотку", "Пробой обмотки", "Обрыв обмотки (или разомкнутую внутреннюю защиту)", "Замкнутую обмотку"]}, {"id": 263, "sec": "TR", "q": "A three-phase motor that loses one phase ('single-phasing') will typically:", "opts": ["Speed up", "Run cooler", "Overheat, hum, and trip on overload", "Improve efficiency"], "correct": 2, "re": "With one phase lost, the motor can't develop normal torque; current rises in the remaining windings and it overheats/trips. Check fuses, contacts, and supply.", "rr": "С потерей фазы двигатель не развивает нормальный момент; ток в оставшихся обмотках растёт, он перегревается/выбивает. Проверьте предохранители, контакты, питание.", "qr": "Трёхфазный двигатель, потерявший одну фазу («single-phasing»), обычно:", "optsr": ["Ускоряется", "Работает холоднее", "Перегревается, гудит и выбивает по перегрузке", "Повышает КПД"]}, {"id": 264, "sec": "TR", "q": "A compressor with worn/leaking valves typically shows:", "opts": ["Low suction, high head", "Normal performance", "Reduced capacity with high suction and low discharge pressure", "High subcooling"], "correct": 2, "re": "Internal valve leakage lets gas recirculate, so the compressor can't build normal discharge or pull down suction — capacity drops despite running.", "rr": "Внутренняя утечка через клапаны даёт рециркуляцию газа: компрессор не создаёт нормальное нагнетание и не опускает всасывание — производительность падает при работе.", "qr": "Компрессор с изношенными/негерметичными клапанами обычно показывает:", "optsr": ["Низкое всасывание, высокий напор", "Нормальную работу", "Снижение производительности при высоком всасывании и низком нагнетании", "Высокий subcooling"]}, {"id": 265, "sec": "TR", "q": "Before condemning an ECM blower motor, the technician should first check:", "opts": ["The gas pressure", "The condensate trap", "The refrigerant charge", "Supply power, the control/PWM signal, and connections/programming"], "correct": 3, "re": "ECM modules are often blamed wrongly; verify line/low-voltage power, the thermostat/board demand signal, motor harness, and proper programming first.", "rr": "ECM-модули часто винят зря; сначала проверьте питание (линия/низкое напряжение), сигнал запроса от термостата/платы, разъёмы и правильную программу.", "qr": "Прежде чем менять ECM-двигатель вентилятора, техник сначала проверяет:", "optsr": ["Давление газа", "Сифон конденсата", "Заправку хладагентом", "Питание, управляющий/PWM-сигнал и соединения/программирование"]}, {"id": 266, "sec": "TR", "q": "A gas furnace whose pressure switch won't close after the inducer starts will:", "opts": ["Overheat", "Fire normally", "Cool the house", "Fail to ignite (no proof of draft)"], "correct": 3, "re": "The pressure switch must prove inducer draft before ignition; if it won't close (weak inducer, blocked flue/condensate, cracked hose), the sequence halts safely.", "rr": "Реле давления должно подтвердить тягу инжектора до розжига; если оно не замкнётся (слабый инжектор, забитый дымоход/конденсат, треснувший шланг), последовательность безопасно останавливается.", "qr": "Газовая печь, у которой реле давления не замыкается после старта инжектора, будет:", "optsr": ["Перегреваться", "Зажигаться нормально", "Охлаждать дом", "Не зажигаться (нет подтверждения тяги)"]}, {"id": 267, "sec": "TR", "q": "Delayed ignition causing a small 'puff' or rollout at the burners is often due to:", "opts": ["Too much airflow", "High SEER", "Dirty burners, low gas pressure, or a weak ignition source", "Overcharge"], "correct": 2, "re": "When gas accumulates before igniting, it lights with a puff; causes include dirty/clogged burners, low manifold pressure, or a weak igniter/flame path.", "rr": "Когда газ накапливается до воспламенения, он зажигается с хлопком; причины — грязные/забитые горелки, низкое давление на манифольде или слабый розжиг.", "qr": "Запоздалый розжиг с лёгким «хлопком» или выбросом пламени у горелок часто из-за:", "optsr": ["Слишком большого расхода воздуха", "Высокого SEER", "Грязных горелок, низкого давления газа или слабого источника розжига", "Перезаправки"]}, {"id": 268, "sec": "TR", "q": "No 24 V at the gas valve during a heat call (with a good valve) points to a problem:", "opts": ["In the condenser", "Upstream in the control circuit (board, limit, flame sense, transformer)", "In the refrigerant circuit", "In the duct"], "correct": 1, "re": "If the valve coil is good but receives no 24 V on a call, trace upstream — open limit/rollout, failed board, no flame proof, or transformer/fuse issue.", "rr": "Если катушка клапана цела, но 24 В при запросе нет — ищите выше: разомкнутый лимит/rollout, отказ платы, нет подтверждения пламени, или трансформатор/предохранитель.", "qr": "Отсутствие 24 В на газовом клапане при запросе тепла (клапан исправен) указывает на проблему:", "optsr": ["В конденсаторе", "Выше по цепи управления (плата, лимит, контроль пламени, трансформатор)", "В контуре хладагента", "В воздуховоде"]}, {"id": 269, "sec": "TR", "q": "In cooling, low suction pressure together with high head pressure most likely indicates:", "opts": ["Low load", "Dirty filter only", "Overcharge", "A restriction in the liquid line or metering device"], "correct": 3, "re": "A restriction backs up refrigerant (high head) while starving the evaporator (low suction); look for a plugged drier or stuck metering device.", "rr": "Засор подпирает хладагент (высокий напор), обедняя испаритель (низкое всасывание); ищите забитый осушитель или заклинивший дозатор.", "qr": "В охлаждении низкое давление всасывания вместе с высоким давлением нагнетания скорее всего указывает на:", "optsr": ["Малую нагрузку", "Только грязный фильтр", "Перезаправку", "Засор в жидкостной линии или дозаторе"]}, {"id": 270, "sec": "TR", "q": "In cooling, high suction pressure together with high head pressure suggests:", "opts": ["Low airflow at evaporator", "A closed TXV", "Undercharge or restriction", "Overcharge, a dirty/blocked condenser, or excessive load"], "correct": 3, "re": "Both pressures high points to too much refrigerant, poor condenser heat rejection (dirty coil/failed fan), or a very high load.", "rr": "Оба давления высокие — это избыток хладагента, плохой теплоотвод конденсатора (грязная батарея/отказ вентилятора) или очень высокая нагрузка.", "qr": "В охлаждении высокое всасывание вместе с высоким нагнетанием указывает на:", "optsr": ["Низкий расход у испарителя", "Закрытый TXV", "Недозаправку или засор", "Перезаправку, грязный/заблокированный конденсатор или избыточную нагрузку"]}, {"id": 271, "sec": "TR", "q": "In cooling, high suction pressure with low head pressure most often indicates:", "opts": ["Overcharge", "An inefficient compressor (worn valves)", "Dirty condenser", "A restriction"], "correct": 1, "re": "When the compressor can't pump effectively, suction stays high and head stays low — classic worn-valve/inefficient compressor signature.", "rr": "Когда компрессор плохо качает, всасывание остаётся высоким, а нагнетание низким — классическая картина изношенных клапанов/неэффективного компрессора.", "qr": "В охлаждении высокое всасывание при низком нагнетании чаще всего указывает на:", "optsr": ["Перезаправку", "Неэффективный компрессор (изношенные клапаны)", "Грязный конденсатор", "Засор"]}, {"id": 272, "sec": "TR", "q": "A reversing valve that buzzes but won't shift may be caused by:", "opts": ["A clean filter", "Low refrigerant charge (insufficient pressure differential) or a failed solenoid", "A new thermostat", "High airflow"], "correct": 1, "re": "The valve needs adequate pressure difference to shift; low charge or a failed solenoid coil/stuck slide can leave it buzzing without changing modes.", "rr": "Клапану нужен достаточный перепад давления для переключения; малая заправка или отказ катушки соленоида/заклинивший золотник оставляют его гудящим без смены режима.", "qr": "Реверс-клапан, который гудит, но не переключается, может быть из-за:", "optsr": ["Чистого фильтра", "Малой заправки (недостаточный перепад давления) или отказа соленоида", "Нового термостата", "Высокого расхода воздуха"]}, {"id": 273, "sec": "TR", "q": "A heat pump low on charge in heating mode typically shows:", "opts": ["No symptoms", "High head only", "High suction, high capacity", "Low suction pressure, reduced heating capacity, and possible outdoor-coil icing"], "correct": 3, "re": "Undercharge in heating starves the outdoor (evaporator) coil: low suction, weak heat output, and abnormal frosting/icing.", "rr": "Недозаправка в нагреве обедняет наружный (испарительный) змеевик: низкое всасывание, слабый нагрев и ненормальное инееобразование/обмерзание.", "qr": "Тепловой насос с недостатком заправки в режиме нагрева обычно показывает:", "optsr": ["Без симптомов", "Только высокий напор", "Высокое всасывание, высокую отдачу", "Низкое давление всасывания, сниженную теплоотдачу и возможное обмерзание наружного змеевика"]}, {"id": 274, "sec": "TR", "q": "A repeatedly blown 24 V control (low-voltage) fuse most often indicates:", "opts": ["A short to ground in the thermostat/control wiring", "High head pressure", "A dirty filter", "A refrigerant leak"], "correct": 0, "re": "A grounded/shorted low-voltage wire (e.g., a chafed thermostat cable) draws excess current and blows the control fuse; inspect and isolate the wiring.", "rr": "Замкнутый на землю низковольтный провод (например протёртый кабель термостата) тянет лишний ток и жжёт предохранитель управления; осмотрите и изолируйте проводку.", "qr": "Постоянно перегорающий управляющий предохранитель 24 В (низкое напряжение) чаще всего указывает на:", "optsr": ["Замыкание на землю в проводке термостата/управления", "Высокий напор", "Грязный фильтр", "Утечку хладагента"]}, {"id": 275, "sec": "TR", "q": "A dirty condenser coil in cooling typically causes:", "opts": ["High head pressure, high discharge temperature, and higher amp draw", "Better efficiency", "Low head pressure", "Low suction only"], "correct": 0, "re": "Restricted condenser airflow reduces heat rejection, raising head pressure, discharge temperature, and current — with poor cooling and possible high-pressure trips.", "rr": "Ухудшённый обдув конденсатора снижает теплоотвод, поднимая напор, температуру нагнетания и ток — плохое охлаждение и возможные срабатывания по высокому давлению.", "qr": "Грязный конденсатор в охлаждении обычно вызывает:", "optsr": ["Высокий напор, высокую температуру нагнетания и больший ток", "Лучшую эффективность", "Низкое давление нагнетания", "Только низкое всасывание"]}, {"id": 276, "sec": "TR", "q": "After thawing a frozen evaporator coil, the technician must:", "opts": ["Find and correct the cause (low airflow or low charge) before returning to service", "Replace the compressor", "Immediately recharge", "Add oil"], "correct": 0, "re": "Thawing only restores flow temporarily; unless the airflow restriction or undercharge is corrected, the coil will freeze again.", "rr": "Разморозка лишь временно восстанавливает поток; без устранения сужения расхода или недозаправки змеевик обмёрзнет снова.", "qr": "После разморозки обмёрзшего испарителя техник обязан:", "optsr": ["Найти и устранить причину (низкий расход или недозаправка) до возврата в работу", "Заменить компрессор", "Сразу дозаправить", "Добавить масло"]}, {"id": 277, "sec": "TR", "q": "Contactor chatter (rapid pull-in/drop-out) is commonly caused by:", "opts": ["High SEER", "Overcharge", "Low control voltage or a weak transformer/loose connection", "Dirty condenser"], "correct": 2, "re": "If the coil can't hold in (low 24 V, weak transformer, loose/high-resistance connection), the contactor chatters; correct the control voltage/connection.", "rr": "Если катушка не удерживается (низкие 24 В, слабый трансформатор, слабый/высокоомный контакт), контактор дребезжит; исправьте управляющее напряжение/контакт.", "qr": "Дребезг контактора (быстрое включение/отпускание) обычно вызван:", "optsr": ["Высоким SEER", "Перезаправкой", "Низким управляющим напряжением или слабым трансформатором/слабым контактом", "Грязным конденсатором"]}, {"id": 278, "sec": "TR", "q": "A standing-pressure leak test (with dry nitrogen) confirms tightness by:", "opts": ["Pressurizing and watching for a pressure drop over time (temperature-corrected)", "Pulling a vacuum", "Adding refrigerant", "Measuring superheat"], "correct": 0, "re": "After pressurizing with nitrogen, a held pressure (accounting for temperature change) indicates no leak; a drop reveals one to locate with soap/detector.", "rr": "После опрессовки азотом удержание давления (с учётом изменения температуры) означает отсутствие утечки; падение выявляет её — ищут мылом/детектором.", "qr": "Опрессовка под стоячим давлением (сухим азотом) подтверждает герметичность путём:", "optsr": ["Подачи давления и наблюдения за его падением во времени (с поправкой на температуру)", "Создания вакуума", "Добавления хладагента", "Измерения superheat"]}, {"id": 279, "sec": "Safety & Field Practices", "q": "Cal/OSHA (Title 8) requires every employer to establish a written:", "opts": ["Marketing plan", "Injury and Illness Prevention Program (IIPP)", "SEER report", "Refrigerant log only"], "correct": 1, "re": "California employers must have a written IIPP covering hazard identification, training, inspections, and correction of unsafe conditions.", "rr": "Работодатели Калифорнии обязаны иметь письменную IIPP, охватывающую выявление опасностей, обучение, инспекции и устранение небезопасных условий.", "qr": "Cal/OSHA (Title 8) требует от каждого работодателя иметь письменную:", "optsr": ["Маркетинговый план", "Программу предотвращения травм и заболеваний (IIPP)", "Отчётность по SEER", "Только журнал хладагента"]}, {"id": 280, "sec": "Safety & Field Practices", "q": "The Hazard Communication standard (GHS) requires that hazardous chemicals on a jobsite have:", "opts": ["No labeling", "A patent", "Proper labels and accessible Safety Data Sheets (SDS)", "Only a price tag"], "correct": 2, "re": "HazCom/GHS requires standardized labels and SDS so workers know the hazards, safe handling, and first aid for chemicals they may contact.", "rr": "HazCom/GHS требует стандартные этикетки и SDS, чтобы работники знали опасности, безопасное обращение и первую помощь для химикатов, с которыми контактируют.", "qr": "Стандарт информирования об опасностях (GHS) требует, чтобы опасные химикаты на объекте имели:", "optsr": ["Без маркировки", "Патент", "Правильные этикетки и доступные паспорта безопасности (SDS)", "Только ценник"]}, {"id": 281, "sec": "Safety & Field Practices", "q": "Under EPA rules, recovered refrigerant that will be reused by a different owner must generally be:", "opts": ["Vented", "Reclaimed to purity standards (or recycled on-site for the same owner)", "Burned", "Mixed with oil"], "correct": 1, "re": "Refrigerant changing ownership must be reclaimed to AHRI-700 purity by a certified reclaimer; on-site recycling is limited to the same owner's equipment.", "rr": "Хладагент, меняющий владельца, должен быть восстановлен до чистоты AHRI-700 сертифицированным реклаймером; переработка на месте — только для оборудования того же владельца.", "qr": "По правилам EPA, откачанный хладагент для повторного использования другим владельцем обычно должен быть:", "optsr": ["Стравлен", "Восстановлен до стандартов чистоты (или переработан на месте для того же владельца)", "Сожжён", "Смешан с маслом"]}, {"id": 282, "sec": "Safety & Field Practices", "q": "Oxygen must never be used to pressurize a refrigeration system because:", "opts": ["It can react explosively with compressor oil", "It is too heavy", "It is too expensive", "It freezes the lines"], "correct": 0, "re": "Oxygen under pressure can combust violently with hydrocarbon oils; only dry nitrogen is used for pressure/leak testing.", "rr": "Кислород под давлением может бурно воспламениться с углеводородными маслами; для опрессовки/поиска утечек применяют только сухой азот.", "qr": "Кислород нельзя применять для опрессовки холодильной системы, потому что он:", "optsr": ["Может взрывоопасно реагировать с маслом компрессора", "Слишком тяжёл", "Слишком дорог", "Замораживает линии"]}, {"id": 283, "sec": "Safety & Field Practices", "q": "An appliance with a known cracked heat exchanger should be:", "opts": ["Left as-is", "Run at higher gas pressure", "Shut down and red-tagged until repaired/replaced", "Run with more airflow"], "correct": 2, "re": "A cracked heat exchanger can leak CO into supply air; the appliance must be shut off (red-tagged) until the heat exchanger is repaired or replaced.", "rr": "Треснувший теплообменник может пропускать CO в приточный воздух; прибор выключают (red-tag) до ремонта или замены теплообменника.", "qr": "Прибор с заведомо треснувшим теплообменником следует:", "optsr": ["Оставить как есть", "Запускать на повышенном давлении газа", "Выключить и пометить red-tag до ремонта/замены", "Запускать с бо́льшим расходом воздуха"]}, {"id": 284, "sec": "Safety & Field Practices", "q": "A CO alarm and combustion test protect occupants because carbon monoxide poisoning first causes:", "opts": ["Skin rash", "Improved breathing", "Loud noise", "Headache, nausea, and dizziness (often mistaken for flu)"], "correct": 3, "re": "Early CO symptoms are headache, nausea, dizziness, and fatigue; because CO is odorless, alarms and combustion testing are essential safeguards.", "rr": "Ранние симптомы CO — головная боль, тошнота, головокружение, усталость; поскольку CO без запаха, сигнализаторы и анализ горения — ключевая защита.", "qr": "CO-сигнализатор и анализ горения защищают жильцов, потому что отравление угарным газом сначала вызывает:", "optsr": ["Сыпь", "Улучшение дыхания", "Громкий шум", "Головную боль, тошноту и головокружение (часто принимают за грипп)"]}, {"id": 285, "sec": "Safety & Field Practices", "q": "Pipe or duct insulation in a building constructed before about 1980 may contain asbestos, so the technician should:", "opts": ["Cut it freely", "Vacuum it with a shop vac", "Burn it off", "Not disturb it and use a certified abatement contractor if removal is needed"], "correct": 3, "re": "Disturbing asbestos releases hazardous fibers; suspect materials in older buildings should be left intact and handled only by certified abatement professionals.", "rr": "Повреждение асбеста высвобождает опасные волокна; подозрительные материалы в старых зданиях не трогают, удаляют только сертифицированные специалисты по abatement.", "qr": "Изоляция труб или воздуховодов в здании постройки примерно до 1980 года может содержать асбест, поэтому техник должен:", "optsr": ["Свободно резать её", "Пропылесосить обычным пылесосом", "Выжечь её", "Не трогать её и при необходимости удаления привлечь сертифицированного abatement-подрядчика"]}, {"id": 286, "sec": "Safety & Field Practices", "q": "After a chemical splash to the eyes, an emergency eyewash should flush the eyes for at least about:", "opts": ["1 minute", "15 minutes", "No flushing needed", "10 seconds"], "correct": 1, "re": "Standard practice is flushing affected eyes/skin for ~15 minutes and seeking medical care; check the chemical's SDS for specifics.", "rr": "Стандарт — промывать поражённые глаза/кожу около 15 минут и обратиться за медпомощью; уточняйте по SDS химиката.", "qr": "После попадания химиката в глаза аварийный душ для глаз должен промывать их не менее примерно:", "optsr": ["1 минуты", "15 минут", "Промывание не нужно", "10 секунд"]}, {"id": 287, "sec": "Safety & Field Practices", "q": "The 'PASS' method for using a portable fire extinguisher stands for:", "opts": ["Push, Add, Stop, Spray", "Pull, Aim, Squeeze, Sweep", "Press, Alarm, Shut, Step", "Pump, Adjust, Set, Slide"], "correct": 1, "re": "PASS = Pull the pin, Aim at the base of the fire, Squeeze the handle, Sweep side to side — only on a small, contained fire with an exit behind you.", "rr": "PASS = выдернуть чеку (Pull), навести на основание огня (Aim), нажать рычаг (Squeeze), водить из стороны в сторону (Sweep) — только на малый очаг при наличии выхода за спиной.", "qr": "Метод «PASS» при использовании переносного огнетушителя означает:", "optsr": ["Push, Add, Stop, Spray", "Pull, Aim, Squeeze, Sweep (выдернуть, навести, нажать, водить)", "Press, Alarm, Shut, Step", "Pump, Adjust, Set, Slide"]}, {"id": 288, "sec": "Safety & Field Practices", "q": "Performing hot work (brazing/cutting) near combustibles requires:", "opts": ["No precautions", "More refrigerant", "Higher voltage", "A fire watch and an extinguisher present, with combustibles cleared/protected"], "correct": 3, "re": "Hot work needs the area cleared or shielded, an extinguisher at hand, and a fire watch during and after the work to catch smoldering ignition.", "rr": "Огневые работы требуют убрать/закрыть горючие, держать огнетушитель под рукой и обеспечить пожарное наблюдение во время и после работ для перехвата тления.", "qr": "Огневые работы (пайка/резка) рядом с горючими требуют:", "optsr": ["Никаких мер", "Больше хладагента", "Более высокого напряжения", "Пожарного наблюдателя и огнетушителя рядом, с уборкой/защитой горючих"]}, {"id": 289, "sec": "Safety & Field Practices", "q": "Lockout/tagout is applied to a blower or rotating equipment before service to:", "opts": ["Lower static pressure", "Prevent unexpected start-up that could injure the technician", "Add refrigerant", "Increase airflow"], "correct": 1, "re": "LOTO de-energizes and secures the equipment so it can't start unexpectedly (e.g., on a thermostat call) while hands are near moving parts.", "rr": "LOTO обесточивает и блокирует оборудование, чтобы оно не запустилось внезапно (например по запросу термостата), когда руки рядом с движущимися частями.", "qr": "Lockout/tagout применяют к вентилятору или вращающемуся оборудованию перед обслуживанием, чтобы:", "optsr": ["Снизить статическое давление", "Предотвратить внезапный пуск, который может травмировать техника", "Добавить хладагент", "Увеличить расход воздуха"]}, {"id": 290, "sec": "Safety & Field Practices", "q": "Belt and pulley guards on air handlers are required to:", "opts": ["Prevent entanglement and contact injuries from moving parts", "Hold refrigerant", "Reduce voltage", "Improve airflow"], "correct": 0, "re": "Machine guarding keeps hands, clothing, and tools out of rotating belts/pulleys; never operate equipment with guards removed.", "rr": "Защитные ограждения держат руки, одежду и инструмент вдали от вращающихся ремней/шкивов; не работайте со снятыми ограждениями.", "qr": "Ограждения ремней и шкивов на воздухообрабатывающих агрегатах нужны, чтобы:", "optsr": ["Предотвратить затягивание и травмы от движущихся частей", "Удерживать хладагент", "Снизить напряжение", "Улучшить расход воздуха"]}, {"id": 291, "sec": "Safety & Field Practices", "q": "When testing the atmosphere of a confined space, the correct order to test for is:", "opts": ["Toxics, then oxygen, then flammables", "Oxygen first, then flammable gases, then toxics", "Order does not matter", "Flammables first, then oxygen"], "correct": 1, "re": "Test oxygen first (so flammable/toxic readings are valid), then flammable gases, then toxic gases — before entry and continuously as required.", "rr": "Сначала кислород (чтобы показания горючих/токсичных были корректны), затем горючие газы, затем токсичные — до входа и далее по требованию.", "qr": "При проверке атмосферы замкнутого пространства правильный порядок проверки:", "optsr": ["Токсичные, затем кислород, затем горючие", "Сначала кислород, затем горючие газы, затем токсичные", "Порядок не важен", "Сначала горючие, затем кислород"]}, {"id": 292, "sec": "Safety & Field Practices", "q": "In permit-required confined-space entry, the attendant's role is to:", "opts": ["Run the compressor", "Enter and work alongside", "Remain outside, monitor conditions, and maintain communication with the entrant", "Test the refrigerant"], "correct": 2, "re": "The attendant stays outside, watches for hazards, keeps communication, and initiates rescue procedures — never entering to attempt rescue alone.", "rr": "Наблюдатель остаётся снаружи, следит за опасностями, держит связь и инициирует спасательные процедуры — не входит сам для спасения.", "qr": "При входе в замкнутое пространство по допуску роль наблюдателя (attendant):", "optsr": ["Запускать компрессор", "Войти и работать рядом", "Оставаться снаружи, контролировать условия и поддерживать связь со входящим", "Проверять хладагент"]}, {"id": 293, "sec": "Safety & Field Practices", "q": "Extension cords used for power tools on a jobsite must be:", "opts": ["Rated for the load and inspected for damage; GFCI-protected outdoors/wet areas", "Run through water", "Daisy-chained for length", "Spliced with tape"], "correct": 0, "re": "Use undamaged, properly rated cords, avoid daisy-chaining, and provide GFCI protection in wet/outdoor locations to prevent shock and fire.", "rr": "Используйте неповреждённые удлинители нужного номинала, не соединяйте цепочкой и обеспечьте GFCI во влажных/уличных зонах для защиты от удара и пожара.", "qr": "Удлинители для электроинструмента на объекте должны быть:", "optsr": ["Рассчитаны на нагрузку и проверены на повреждения; с GFCI на улице/во влажных зонах", "Проложены через воду", "Соединены цепочкой для длины", "Срощены изолентой"]}, {"id": 294, "sec": "Safety & Field Practices", "q": "For energized electrical work that cannot be avoided, NFPA 70E requires:", "opts": ["No special gear", "Maintaining arc-flash boundaries and wearing arc-rated PPE", "Only cotton gloves", "Working faster"], "correct": 1, "re": "When de-energizing isn't feasible, 70E requires risk assessment, approach/arc-flash boundaries, and arc-rated PPE matched to the incident energy.", "rr": "Когда обесточить нельзя, 70E требует оценку риска, границы приближения/дугового разряда и СИЗ с дуговым рейтингом под энергию дуги.", "qr": "Для неизбежных работ под напряжением NFPA 70E требует:", "optsr": ["Никакого спецснаряжения", "Соблюдения границ дугового разряда и СИЗ с дуговым рейтингом", "Только хлопковых перчаток", "Работать быстрее"]}, {"id": 295, "sec": "Safety & Field Practices", "q": "Breathing a high concentration of refrigerant vapor in an enclosed area is dangerous because it can cause:", "opts": ["Dizziness, oxygen deprivation, and even cardiac sensitization", "Better cooling", "A pleasant odor", "Improved alertness"], "correct": 0, "re": "High refrigerant concentrations displace oxygen and can sensitize the heart to arrhythmia; leave the area, ventilate, and never work in an unventilated leak.", "rr": "Высокие концентрации хладагента вытесняют кислород и могут сенсибилизировать сердце к аритмии; покиньте зону, проветрите и не работайте в непроветриваемой утечке.", "qr": "Вдыхание высокой концентрации паров хладагента в закрытом помещении опасно, потому что может вызвать:", "optsr": ["Головокружение, кислородное голодание и даже сердечную сенсибилизацию", "Лучшее охлаждение", "Приятный запах", "Повышение бдительности"]}, {"id": 296, "sec": "Safety & Field Practices", "q": "Before disassembling a unit, capacitors should be discharged because they:", "opts": ["Can store a dangerous electrical charge after power is removed", "Hold refrigerant", "Are always safe to touch", "Contain oil"], "correct": 0, "re": "Run/start capacitors retain a charge that can shock; discharge through a proper resistor (not a direct short) before handling terminals.", "rr": "Рабочие/пусковые конденсаторы хранят заряд, способный ударить током; разряжайте через подходящий резистор (не прямым замыканием) до работы с клеммами.", "qr": "Перед разборкой блока конденсаторы нужно разрядить, потому что они:", "optsr": ["Могут хранить опасный электрозаряд после снятия питания", "Содержат хладагент", "Всегда безопасны для касания", "Содержат масло"]}, {"id": 297, "sec": "Safety & Field Practices", "q": "A respirator used for a dust or vapor hazard must be:", "opts": ["Made of cloth only", "Optional in all cases", "Selected for the specific hazard and properly fit-tested", "Any mask"], "correct": 2, "re": "Respiratory protection must match the contaminant (e.g., N95 vs cartridge), and tight-fitting respirators require fit testing and a written program.", "rr": "Респираторная защита должна соответствовать загрязнителю (например N95 или с картриджем), а плотноприлегающие респираторы требуют fit-test и письменной программы.", "qr": "Респиратор для защиты от пыли или паров должен быть:", "optsr": ["Только тканевым", "Необязателен во всех случаях", "Подобран под конкретную опасность и правильно подогнан (fit-test)", "Любой маской"]}, {"id": 298, "sec": "Safety & Field Practices", "q": "Working from an aerial lift or scaffold requires:", "opts": ["Only one worker without checks", "Removing guardrails", "No training", "Fall protection and trained/authorized operation"], "correct": 3, "re": "Aerial lifts and scaffolds require trained operators, inspections, fall protection (e.g., harness in a boom lift), and adherence to capacity limits.", "rr": "Автовышки и леса требуют обученных операторов, проверок, защиты от падения (например страховку в стреловом подъёмнике) и соблюдения лимитов нагрузки.", "qr": "Работа с автовышки или строительных лесов требует:", "optsr": ["Одного работника без проверок", "Снятия ограждений", "Без обучения", "Защиты от падения и обученной/допущенной эксплуатации"]}, {"id": 299, "sec": "Safety & Field Practices", "q": "To blow debris out of a line or component, a technician should use:", "opts": ["Pure oxygen", "System refrigerant vented to atmosphere", "Compressed acetylene", "Dry nitrogen (never refrigerant or oxygen)"], "correct": 3, "re": "Use regulated dry nitrogen for purging/blowing lines; venting refrigerant is illegal and oxygen is dangerously reactive with oils.", "rr": "Для продувки/выдувания линий применяют сухой азот через редуктор; стравливание хладагента незаконно, а кислород опасно реагирует с маслами.", "qr": "Чтобы выдуть мусор из линии или компонента, техник должен использовать:", "optsr": ["Чистый кислород", "Хладагент системы, стравленный в атмосферу", "Сжатый ацетилен", "Сухой азот (никогда хладагент или кислород)"]}, {"id": 300, "sec": "Safety & Field Practices", "q": "If a safety control (limit, pressure switch, rollout) keeps tripping, the technician should:", "opts": ["Jumper it out and continue", "Remove the control", "Increase the gas pressure", "Find and correct the underlying cause, never bypass the safety"], "correct": 3, "re": "Repeated trips signal a real hazard (overheating, blocked flue, high pressure); diagnose and fix the cause — bypassing a safety can cause fire, CO, or equipment damage.", "rr": "Повторные срабатывания сигналят о реальной опасности (перегрев, забитый дымоход, высокое давление); диагностируйте и устраните причину — обход защиты грозит пожаром, CO или поломкой.", "qr": "Если защитный орган (лимит, реле давления, rollout) постоянно срабатывает, техник должен:", "optsr": ["Зашунтировать его и продолжить", "Снять орган управления", "Повысить давление газа", "Найти и устранить первопричину, никогда не обходя защиту"]}, {"id": 301, "sec": "Principles & Load Calculations", "q": "Heat transfer by direct contact between molecules of a solid is called:", "opts": ["Infiltration", "Radiation", "Conduction", "Convection"], "correct": 2, "re": "Conduction is heat moving through a material by molecular contact; convection moves heat by fluid motion; radiation transfers heat as electromagnetic waves with no medium.", "rr": "Conduction - тепло идёт через материал контактом молекул; convection - движением жидкости/газа; radiation - электромагнитными волнами без среды.", "qr": "Передача тепла прямым контактом молекул в твёрдом теле называется:", "optsr": ["Инфильтрация", "Излучение", "Теплопроводность (conduction)", "Конвекция"]}, {"id": 302, "sec": "Principles & Load Calculations", "q": "The total-heat (enthalpy) formula for an air-conditioning load uses the constant:", "opts": ["1.08", "0.68", "4.5", "3.41"], "correct": 2, "re": "Total heat (BTU/h) = 4.5 x CFM x change in enthalpy (delta-h, BTU/lb). 1.08 is sensible, 0.68 is latent, 3.41 converts watts to BTU/h.", "rr": "Полное тепло (BTU/ч) = 4.5 x CFM x изменение enthalpy (delta-h, BTU/фунт). 1.08 - явное, 0.68 - скрытое, 3.41 - перевод ватт в BTU/ч.", "qr": "Формула полного тепла (enthalpy) для нагрузки кондиционирования использует коэффициент:", "optsr": ["1.08", "0.68", "4.5", "3.41"]}, {"id": 303, "sec": "Principles & Load Calculations", "q": "The latent-heat load formula uses the constant 0.68 multiplied by CFM and the change in:", "opts": ["Voltage", "Grains of moisture (humidity ratio)", "Dry-bulb temperature", "Velocity"], "correct": 1, "re": "Latent heat (BTU/h) = 0.68 x CFM x change in grains of moisture per pound of air. It accounts for moisture (latent) removal, not temperature change.", "rr": "Latent (BTU/ч) = 0.68 x CFM x изменение гран влаги на фунт воздуха. Учитывает удаление влаги (latent), а не изменение температуры.", "qr": "Формула скрытой (latent) нагрузки использует коэффициент 0.68, умноженный на CFM и изменение:", "optsr": ["Напряжения", "Граны влаги (humidity ratio)", "Температуры по сухому термометру", "Скорости"]}, {"id": 304, "sec": "Principles & Load Calculations", "q": "The U-factor of a building assembly is related to its R-value by:", "opts": ["U = R + 1", "U = R", "U = 1 / R", "U = R squared"], "correct": 2, "re": "U-factor is the reciprocal of total R-value (U = 1/R). A higher R means a lower U, meaning less heat transfer through the assembly.", "rr": "U-фактор - обратная величина суммарного R-value (U = 1/R). Больше R - меньше U, то есть меньше теплопередача через конструкцию.", "qr": "U-фактор конструкции связан с её R-value как:", "optsr": ["U = R + 1", "U = R", "U = 1 / R", "U = R в квадрате"]}, {"id": 305, "sec": "Principles & Load Calculations", "q": "The Solar Heat Gain Coefficient (SHGC) of a window describes:", "opts": ["The fraction of solar radiation it admits as heat", "Its color only", "Its weight", "Its thickness"], "correct": 0, "re": "SHGC is the fraction of incident solar energy transmitted as heat; a lower SHGC reduces cooling load from sunlit glass.", "rr": "SHGC - доля падающей солнечной энергии, пропущенной как тепло; меньший SHGC снижает охлаждающую нагрузку от освещённого солнцем стекла.", "qr": "Коэффициент солнечного теплопритока (SHGC) окна описывает:", "optsr": ["Долю солнечной радиации, пропускаемую как тепло", "Только цвет", "Его вес", "Его толщину"]}, {"id": 306, "sec": "Principles & Load Calculations", "q": "To convert an electrical lighting load in watts to heat gain in BTU/h, multiply watts by:", "opts": ["1.08", "4.5", "3.41", "0.293"], "correct": 2, "re": "1 watt = 3.41 BTU/h. Lighting and plug loads add sensible heat to the cooling calculation at this conversion.", "rr": "1 ватт = 3.41 BTU/ч. Освещение и розеточная нагрузка добавляют явное тепло в расчёт охлаждения по этому коэффициенту.", "qr": "Чтобы перевести электрическую нагрузку освещения из ватт в теплоприток BTU/ч, умножьте ватты на:", "optsr": ["1.08", "4.5", "3.41", "0.293"]}, {"id": 307, "sec": "Principles & Load Calculations", "q": "In a load calculation, each occupant is typically counted as contributing:", "opts": ["Only latent heat", "No heat", "Only sensible heat", "Both sensible and latent heat"], "correct": 3, "re": "People add sensible heat (body warmth) and latent heat (respiration/perspiration); Manual J tables give per-person values by activity level.", "rr": "Люди добавляют явное тепло (тепло тела) и скрытое (дыхание/потоотделение); таблицы Manual J дают значения на человека по уровню активности.", "qr": "В расчёте нагрузки каждый человек обычно учитывается как источник:", "optsr": ["Только скрытого тепла", "Никакого тепла", "Только явного тепла", "И явного, и скрытого тепла"]}, {"id": 308, "sec": "Principles & Load Calculations", "q": "Air changes per hour (ACH) is a way to express:", "opts": ["Compressor speed", "The infiltration/ventilation rate of a space", "Duct gauge", "Refrigerant flow"], "correct": 1, "re": "ACH = how many times the air volume of a space is replaced per hour; it is used to estimate infiltration and ventilation loads.", "rr": "ACH - сколько раз объём воздуха помещения сменяется за час; используется для оценки нагрузок инфильтрации и вентиляции.", "qr": "Воздухообмен в час (ACH) - способ выразить:", "optsr": ["Скорость компрессора", "Кратность инфильтрации/вентиляции помещения", "Толщину дакта", "Поток хладагента"]}, {"id": 309, "sec": "Principles & Load Calculations", "q": "In a duct system, total pressure equals static pressure plus:", "opts": ["Atmospheric pressure", "Gas pressure", "Velocity pressure", "Refrigerant pressure"], "correct": 2, "re": "Total pressure = static pressure + velocity pressure. Static acts in all directions; velocity pressure relates to air movement (and is always positive in the flow direction).", "rr": "Полное давление = статическое + скоростное. Статическое действует во все стороны; velocity pressure связано с движением воздуха (всегда положительно по потоку).", "qr": "В системе воздуховодов полное давление равно статическому давлению плюс:", "optsr": ["Атмосферное давление", "Давление газа", "Скоростное давление (velocity pressure)", "Давление хладагента"]}, {"id": 310, "sec": "Principles & Load Calculations", "q": "A high duct aspect ratio (very wide and flat rectangular duct) generally:", "opts": ["Eliminates the need for sealing", "Has no effect", "Increases friction loss and material/cost for the same area", "Reduces friction"], "correct": 2, "re": "For equal cross-sectional area, a high aspect ratio increases surface area and friction, raising static pressure and sheet-metal cost; near-square ducts are more efficient.", "rr": "При равной площади сечения высокое соотношение сторон увеличивает площадь поверхности и трение, поднимая статическое давление и стоимость металла; близкие к квадрату дакты эффективнее.", "qr": "Высокое соотношение сторон воздуховода (очень широкий плоский прямоугольный) обычно:", "optsr": ["Убирает необходимость герметизации", "Не влияет", "Повышает потери на трение и расход/стоимость материала при той же площади", "Снижает трение"]}, {"id": 311, "sec": "Principles & Load Calculations", "q": "Manual T (ACCA) addresses the selection and location of:", "opts": ["Air distribution devices (registers, grilles, diffusers)", "Gas piping", "Compressors", "Refrigerant"], "correct": 0, "re": "Manual T covers air-distribution: selecting supply registers/diffusers and return grilles for proper throw, spread, and noise (NC) at the design airflow.", "rr": "Manual T - о воздухораспределении: подбор приточных решёток/диффузоров и обратных решёток по дальнобойности, рассеиванию и шуму (NC) при расчётном расходе.", "qr": "Manual T (ACCA) рассматривает подбор и расположение:", "optsr": ["Воздухораспределителей (решёток, диффузоров)", "Газовых труб", "Компрессоров", "Хладагента"]}, {"id": 312, "sec": "Principles & Load Calculations", "q": "A duct-leakage test reported as 'CFM25' measures leakage at a reference pressure of:", "opts": ["25 microns", "25 inches WC", "25 Pascals", "25 psig"], "correct": 2, "re": "Duct leakage is measured with the system pressurized to 25 Pascals; CFM25 is the leakage airflow at that reference, used for code/HERS verification.", "rr": "Утечку воздуховодов измеряют при давлении системы 25 паскалей; CFM25 - расход утечки при этом эталоне, используется для проверки по нормам/HERS.", "qr": "Тест герметичности воздуховодов с результатом 'CFM25' измеряет утечку при эталонном давлении:", "optsr": ["25 микрон", "25 дюймов WC", "25 паскалей", "25 psig"]}, {"id": 313, "sec": "Principles & Load Calculations", "q": "An extended-plenum duct system differs from a radial system in that it:", "opts": ["Has no trunk", "Uses a main trunk of constant size with branch takeoffs", "Cannot be used in homes", "Needs no registers"], "correct": 1, "re": "An extended plenum uses a constant-size main trunk feeding branch runs; a reducing-plenum trunk steps down in size; radial systems run branches directly from the air handler.", "rr": "Extended plenum - магистральный ствол постоянного сечения с ответвлениями; reducing-plenum ствол сужается; радиальная - ветви идут прямо от воздухообрабатывающего блока.", "qr": "Система с расширенным плёнумом отличается от радиальной тем, что:", "optsr": ["Не имеет ствола", "Использует магистральный ствол постоянного сечения с ответвлениями", "Непригодна для домов", "Не нуждается в решётках"]}, {"id": 314, "sec": "Principles & Load Calculations", "q": "Equivalent length (EL) of a duct fitting is used in design to:", "opts": ["Measure refrigerant", "Set the gas pressure", "Account for the fitting's friction as an added length of straight duct", "Size the breaker"], "correct": 2, "re": "Each elbow, takeoff, or boot adds resistance equal to a length of straight duct; total effective length = measured straight length + sum of fitting equivalent lengths.", "rr": "Каждое колено, врезка или башмак добавляют сопротивление, равное длине прямого дакта; полная эффективная длина = измеренная прямая + сумма эквив. длин фитингов.", "qr": "Эквивалентная длина (EL) фитинга воздуховода в проектировании нужна, чтобы:", "optsr": ["Измерить хладагент", "Задать давление газа", "Учесть трение фитинга как добавочную длину прямого дакта", "Подобрать автомат"]}, {"id": 315, "sec": "Principles & Load Calculations", "q": "In California, a permitted residential changeout commonly triggers Title 24 HERS verification of:", "opts": ["The TikTok account", "The thermostat brand", "Refrigerant charge, airflow, and duct leakage", "Paint color"], "correct": 2, "re": "California's Energy Code (Title 24) often requires an independent HERS rater to verify refrigerant charge/fan airflow and duct leakage on alterations, depending on the measure.", "rr": "Энергокодекс Калифорнии (Title 24) часто требует независимого HERS-оценщика для проверки заправки/расхода вентилятора и утечки воздуховодов при переделках, в зависимости от меры.", "qr": "В Калифорнии замена по разрешению на жильё обычно влечёт HERS-проверку по Title 24 для:", "optsr": ["Аккаунта TikTok", "Бренда термостата", "Заправки хладагентом, расхода воздуха и утечки воздуховодов", "Цвета краски"]}, {"id": 316, "sec": "Principles & Load Calculations", "q": "'Diversity' in a commercial load calculation accounts for the fact that:", "opts": ["All loads peak at once", "Ducts leak", "Refrigerant varies", "Not all loads (people, lights, equipment) peak simultaneously"], "correct": 3, "re": "Diversity reduces the calculated peak because occupancy, lighting, and equipment loads rarely all reach maximum at the same moment, avoiding oversizing.", "rr": "Diversity снижает расчётный пик, т.к. заполненность, освещение и оборудование редко достигают максимума одновременно, что предотвращает завышение.", "qr": "'Диверсификация' (diversity) в коммерческом расчёте нагрузки учитывает, что:", "optsr": ["Все нагрузки пикуют одновременно", "Дакты текут", "Хладагент меняется", "Не все нагрузки (люди, свет, оборудование) пикуют одновременно"]}, {"id": 317, "sec": "Principles & Load Calculations", "q": "A 'square-foot per ton' rule of thumb for sizing AC is:", "opts": ["Used for gas sizing", "A rough estimate that often oversizes equipment", "Required by code", "More accurate than Manual J"], "correct": 1, "re": "Rules of thumb (e.g., 500-600 sq ft/ton) ignore insulation, windows, and orientation and usually oversize; a Manual J calculation is the correct method.", "rr": "Эмпирические правила (например 500-600 кв.фт/тонна) игнорируют утепление, окна и ориентацию и обычно завышают; правильный метод - расчёт Manual J.", "qr": "Эмпирическое правило 'квадратных футов на тонну' для подбора AC:", "optsr": ["Применяется для подбора газа", "Грубая оценка, часто завышающая оборудование", "Требуется нормами", "Точнее, чем Manual J"]}, {"id": 318, "sec": "Principles & Load Calculations", "q": "To achieve a 40% gross margin, a job with $600 cost must be priced at:", "opts": ["$660", "$840", "$1000", "$960"], "correct": 2, "re": "Margin is profit as a percent of price: price = cost / (1 - margin) = 600 / 0.60 = $1000. (A 40% markup on cost would only be $840.)", "rr": "Маржа - прибыль в процентах от цены: цена = себестоимость / (1 - маржа) = 600 / 0.60 = $1000. (Наценка 40% на себестоимость дала бы лишь $840.)", "qr": "Чтобы получить 40% валовой маржи, работа стоимостью $600 должна продаваться за:", "optsr": ["$660", "$840", "$1000", "$960"]}, {"id": 319, "sec": "Principles & Load Calculations", "q": "Labor burden added to a worker's base wage includes:", "opts": ["Payroll taxes, workers' comp, and benefits", "Permit fees", "Material cost", "Only the hourly wage"], "correct": 0, "re": "Labor burden is the extra cost above wages - employer payroll taxes, workers' compensation, insurance, and benefits - and must be in the estimated labor rate.", "rr": "Labor burden - дополнительные затраты сверх зарплаты: налоги работодателя с ФОТ, страхование от травм, страховка и льготы - и должны входить в расчётную ставку труда.", "qr": "Трудовая надбавка (labor burden) сверх базовой зарплаты работника включает:", "optsr": ["Налоги с ФОТ, workers' comp и льготы", "Пошлины за разрешение", "Стоимость материала", "Только почасовую оплату"]}, {"id": 320, "sec": "Principles & Load Calculations", "q": "A flue/chimney for an atmospheric appliance is sized primarily on the appliance input (BTU/h) and the:", "opts": ["Vent height and connector configuration", "Refrigerant type", "Duct color", "Wire size"], "correct": 0, "re": "Venting tables size the flue from total input, vent height, lateral length, and number of connectors so the appliance vents safely (per the venting tables/code).", "rr": "Таблицы дымоудаления подбирают дымоход по суммарному input, высоте, длине горизонтали и числу соединителей, чтобы прибор безопасно вентилировался (по таблицам/нормам).", "qr": "Дымоход для атмосферного прибора подбирается прежде всего по входной мощности прибора (BTU/ч) и:", "optsr": ["Высоте дымохода и конфигурации соединителя", "Типу хладагента", "Цвету дакта", "Сечению провода"]}, {"id": 321, "sec": "Principles & Load Calculations", "q": "The 'design temperature' used for sizing should come from:", "opts": ["Published ASHRAE/Manual J design data for the location", "A guess", "The thermostat setting", "The hottest/coldest day ever recorded"], "correct": 0, "re": "Use the location's published 1%/99% ASHRAE design temperatures (in Manual J), not record extremes, to avoid chronic oversizing.", "rr": "Используйте опубликованные расчётные температуры 1%/99% ASHRAE для местности (в Manual J), а не рекорды, чтобы не завышать систему хронически.", "qr": "'Расчётная температура' для подбора должна браться из:", "optsr": ["Опубликованных расчётных данных ASHRAE/Manual J для местности", "Догадки", "Уставки термостата", "Самого жаркого/холодного дня в истории"]}, {"id": 322, "sec": "Principles & Load Calculations", "q": "Required ventilation (outdoor) air for a commercial space is generally based on occupancy and:", "opts": ["Floor area / use category per code (e.g., ASHRAE 62.1)", "Refrigerant charge", "Compressor size", "Duct color"], "correct": 0, "re": "ASHRAE 62.1 sets outdoor-air rates from people (cfm/person) plus area (cfm/sq ft) by occupancy category to maintain indoor air quality.", "rr": "ASHRAE 62.1 задаёт расход наружного воздуха от людей (cfm/чел) плюс площади (cfm/кв.фт) по категории помещения для качества воздуха.", "qr": "Требуемый объём наружного (вентиляционного) воздуха для коммерческого помещения обычно зависит от заполненности и:", "optsr": ["Площади / категории использования по нормам (например ASHRAE 62.1)", "Заправки хладагентом", "Размера компрессора", "Цвета дакта"]}, {"id": 323, "sec": "Principles & Load Calculations", "q": "Heating degree days (HDD) are used to estimate:", "opts": ["Seasonal heating energy use", "Duct size", "Peak cooling load", "Refrigerant charge"], "correct": 0, "re": "Degree days sum how far daily average temperatures fall below a base (e.g., 65F); HDD estimates seasonal heating energy/fuel use, not peak sizing.", "rr": "Градусо-сутки суммируют, насколько средние дневные температуры ниже базовой (например 65F); HDD оценивает сезонный расход энергии/топлива на отопление, а не пиковый подбор.", "qr": "Градусо-сутки отопления (HDD) применяют для оценки:", "optsr": ["Сезонного расхода энергии на отопление", "Размера дакта", "Пиковой охлаждающей нагрузки", "Заправки хладагентом"]}, {"id": 324, "sec": "Principles & Load Calculations", "q": "When two stages of cooling are specified, the equipment selection should ensure the first stage:", "opts": ["Handles part-load conditions efficiently for better comfort/humidity control", "Meets the entire peak load", "Runs only in winter", "Is oversized"], "correct": 0, "re": "Two-stage (or variable) equipment runs at low capacity most of the time, improving runtime, dehumidification, and comfort; full capacity is reserved for design extremes.", "rr": "Двухступенчатое (или инверторное) оборудование большую часть времени работает на низкой мощности, улучшая длительность работы, осушение и комфорт; полная мощность - для расчётных экстремумов.", "qr": "Когда задано двухступенчатое охлаждение, подбор оборудования должен обеспечить, чтобы первая ступень:", "optsr": ["Эффективно работала при частичной нагрузке ради комфорта/влажности", "Покрывала всю пиковую нагрузку", "Работала только зимой", "Была завышена"]}, {"id": 325, "sec": "Principles & Load Calculations", "q": "A reducing-trunk (reducing-plenum) duct design keeps air velocity more constant by:", "opts": ["Adding refrigerant", "Keeping the trunk one size", "Stepping the trunk down in size after branch takeoffs", "Removing all branches"], "correct": 2, "re": "As branches remove air, a reducing trunk steps down in size to maintain velocity and balanced static pressure along the run.", "rr": "Поскольку ветви отбирают воздух, сужающийся ствол ступенчато уменьшается в размере, удерживая скорость и сбалансированное статическое давление вдоль трассы.", "qr": "Проект с сужающимся стволом (reducing-plenum) поддерживает скорость воздуха более постоянной за счёт:", "optsr": ["Добавления хладагента", "Сохранения одного размера ствола", "Ступенчатого сужения ствола после ответвлений", "Удаления всех ветвей"]}, {"id": 326, "sec": "Fabrication & Installation", "q": "For a long line set, the liquid line is sized smaller than the suction line mainly to:", "opts": ["Save money only", "Reduce subcooling", "Maintain refrigerant velocity and minimize charge in the liquid line", "Increase noise"], "correct": 2, "re": "Liquid refrigerant is dense, so a smaller liquid line keeps velocity adequate and limits the added charge; the suction (vapor) line is larger to limit pressure drop.", "rr": "Жидкий хладагент плотный, поэтому меньшая жидкостная линия держит достаточную скорость и ограничивает добавочный заряд; всасывающая (паровая) больше для снижения перепада давления.", "qr": "На длинной трассе жидкостную линию делают меньше всасывающей главным образом чтобы:", "optsr": ["Только сэкономить", "Снизить subcooling", "Сохранить скорость хладагента и уменьшить заряд в жидкостной линии", "Увеличить шум"]}, {"id": 327, "sec": "Fabrication & Installation", "q": "When the line set exceeds the factory-charge length, the technician must:", "opts": ["Add nitrogen", "Add refrigerant per the manufacturer's per-foot adjustment", "Ignore it", "Remove refrigerant"], "correct": 1, "re": "Manufacturers pre-charge for a set line length; beyond it, add refrigerant by the specified amount per additional foot of liquid line.", "rr": "Производитель заправляет под заданную длину; сверх неё добавляют хладагент по указанной норме на каждый дополнительный фут жидкостной линии.", "qr": "Когда длина трассы превышает заводскую заправку, техник должен:", "optsr": ["Добавить азот", "Добавить хладагент по поправке производителя на фут", "Игнорировать", "Убрать хладагент"]}, {"id": 328, "sec": "Fabrication & Installation", "q": "Charging by weight (using a scale) is the most accurate method when:", "opts": ["Doing a quick check", "Topping off a leak", "Guessing", "Installing a system with a known total charge or a mini-split"], "correct": 3, "re": "Weigh-in charging to the nameplate total (adjusted for line length) is most accurate on evacuated systems and ductless installs where the full charge is known.", "rr": "Заправка по весу до полного значения с шильдика (с поправкой на длину) наиболее точна на отвакуумированных системах и ductless-монтаже, где полный заряд известен.", "qr": "Заправка по весу (по весам) наиболее точна, когда:", "optsr": ["Делают быструю проверку", "Доливают в текущую систему", "Гадают", "Ставят систему с известным полным зарядом или мини-сплит"]}, {"id": 329, "sec": "Fabrication & Installation", "q": "Removing the Schrader valve cores during evacuation:", "opts": ["Adds moisture", "Slows evacuation", "Is never allowed", "Speeds evacuation by removing a flow restriction"], "correct": 3, "re": "Schrader cores restrict conductance; using a core-removal tool greatly speeds deep evacuation. Reinstall cores before charging.", "rr": "Золотники Schrader ограничивают проводимость; инструмент для их съёма заметно ускоряет глубокое вакуумирование. Перед заправкой золотники ставят обратно.", "qr": "Снятие золотников Schrader при вакуумировании:", "optsr": ["Добавляет влагу", "Замедляет откачку", "Запрещено", "Ускоряет откачку, убирая сужение потока"]}, {"id": 330, "sec": "Fabrication & Installation", "q": "Vacuum-pump oil should be changed:", "opts": ["Only when it leaks", "Never", "Regularly, because moisture/contaminants degrade it and reduce vacuum depth", "Only yearly regardless"], "correct": 2, "re": "Contaminated pump oil cannot reach a deep vacuum; change it frequently (especially after wet systems) to keep the pump pulling below 500 microns.", "rr": "Загрязнённое масло насоса не даёт глубокого вакуума; меняйте часто (особенно после влажных систем), чтобы насос тянул ниже 500 микрон.", "qr": "Масло вакуумного насоса следует менять:", "optsr": ["Только при течи", "Никогда", "Регулярно, т.к. влага/загрязнения ухудшают его и снижают глубину вакуума", "Только раз в год независимо ни от чего"]}, {"id": 331, "sec": "Fabrication & Installation", "q": "A typical leak-test (standing) pressure for an R-410A system using dry nitrogen is in the range of about:", "opts": ["2000 psig", "0 psig", "Several hundred psig per the equipment's test rating", "10-15 psig"], "correct": 2, "re": "Pressure-test with dry nitrogen to the manufacturer's specified test pressure (often a few hundred psig for R-410A equipment); never exceed component ratings, and never use oxygen.", "rr": "Опрессовку ведут сухим азотом до указанного производителем давления (часто несколько сотен psig для R-410A); не превышайте рейтинги компонентов и не применяйте кислород.", "qr": "Типовое испытательное (на удержание) давление для системы R-410A сухим азотом находится в диапазоне около:", "optsr": ["2000 psig", "0 psig", "Несколько сотен psig по испытательному рейтингу оборудования", "10-15 psig"]}, {"id": 332, "sec": "Fabrication & Installation", "q": "Brazing copper to a steel or brass component (dissimilar metals) requires:", "opts": ["No flux ever", "Plain water", "A silver alloy (BAg) with the proper flux", "Soft solder only"], "correct": 2, "re": "Copper-to-steel/brass joints need flux and a silver-bearing (BAg) filler; self-fluxing BCuP is only for copper-to-copper.", "rr": "Стыки медь-сталь/латунь требуют флюс и припой с серебром (BAg); самофлюсующийся BCuP - только для медь-медь.", "qr": "Пайка меди к стальному или латунному компоненту (разнородные металлы) требует:", "optsr": ["Без флюса вообще", "Простой воды", "Серебряного сплава (BAg) с подходящим флюсом", "Только мягкого припоя"]}, {"id": 333, "sec": "Fabrication & Installation", "q": "Vibration-isolation pads are placed under an outdoor condenser to:", "opts": ["Increase airflow", "Add refrigerant", "Reduce transmitted noise/vibration and protect the slab/connections", "Raise the SEER"], "correct": 2, "re": "Isolation pads dampen compressor vibration, lowering noise and reducing fatigue on line connections and the mounting surface.", "rr": "Изоляционные подушки гасят вибрацию компрессора, снижая шум и усталостную нагрузку на соединения линий и опорную поверхность.", "qr": "Виброизолирующие подушки ставят под наружный конденсатор, чтобы:", "optsr": ["Увеличить расход воздуха", "Добавить хладагент", "Снизить передаваемый шум/вибрацию и защитить площадку/соединения", "Поднять SEER"]}, {"id": 334, "sec": "Fabrication & Installation", "q": "An auxiliary (secondary) drain pan under an attic air handler is required to:", "opts": ["Improve airflow", "Support the unit", "Hold refrigerant", "Catch condensate overflow and protect the ceiling below"], "correct": 3, "re": "Equipment above a finished space needs a secondary pan (with its own drain or float switch) to catch overflow if the primary drain clogs.", "rr": "Оборудование над жилым помещением требует вторичный поддон (со своим дренажом или поплавковым выключателем), чтобы поймать перелив при засоре основного дренажа.", "qr": "Вспомогательный (вторичный) дренажный поддон под чердачным воздухообрабатывающим блоком нужен, чтобы:", "optsr": ["Улучшить расход воздуха", "Поддерживать блок", "Хранить хладагент", "Ловить перелив конденсата и защитить потолок снизу"]}, {"id": 335, "sec": "Fabrication & Installation", "q": "A thermostat should be located:", "opts": ["Above a heat source", "On an interior wall away from drafts, supply registers, and sunlight", "On an exterior wall in direct sun", "Inside a closet"], "correct": 1, "re": "Mount the thermostat about 5 ft up on an interior wall in a representative location, away from drafts, supply air, sun, and heat sources, for accurate sensing.", "rr": "Термостат ставят примерно на высоте 5 футов на внутренней стене в репрезентативном месте, вдали от сквозняков, приточного воздуха, солнца и источников тепла - для точного измерения.", "qr": "Термостат следует размещать:", "optsr": ["Над источником тепла", "На внутренней стене вдали от сквозняков, приточных решёток и солнца", "На наружной стене под прямым солнцем", "Внутри шкафа"]}, {"id": 336, "sec": "Fabrication & Installation", "q": "A modern Wi-Fi/smart thermostat usually requires a 'C' wire to:", "opts": ["Provide continuous 24 V common for power", "Call for heat", "Open the gas valve", "Run the compressor"], "correct": 0, "re": "Smart thermostats draw continuous power; the C (common) wire completes the 24 V circuit so the thermostat runs without 'power stealing' that can cause faults.", "rr": "Умные термостаты потребляют постоянное питание; провод C (общий) замыкает цепь 24 В, чтобы термостат работал без 'воровства питания', вызывающего сбои.", "qr": "Современный Wi-Fi/умный термостат обычно требует провод 'C', чтобы:", "optsr": ["Обеспечить постоянный общий 24 В для питания", "Вызвать нагрев", "Открыть газовый клапан", "Запустить компрессор"]}, {"id": 337, "sec": "Fabrication & Installation", "q": "On a heat-pump thermostat, the 'E' terminal controls:", "opts": ["Evaporator fan", "Emergency (auxiliary) heat", "Economizer", "Exhaust"], "correct": 1, "re": "E energizes emergency heat (typically electric strips) directly, bypassing the compressor - used if the heat pump fails or in emergency-heat mode.", "rr": "E напрямую запитывает аварийный нагрев (обычно ТЭНы) в обход компрессора - используется при отказе насоса или в режиме emergency heat.", "qr": "На термостате теплового насоса клемма 'E' управляет:", "optsr": ["Вентилятором испарителя", "Аварийным (auxiliary) нагревом", "Экономайзером", "Вытяжкой"]}, {"id": 338, "sec": "Fabrication & Installation", "q": "Adequate service clearance around an outdoor condenser is needed to:", "opts": ["Reduce wire size", "Allow airflow across the coil and room to service the unit", "Hold refrigerant", "Increase SEER rating"], "correct": 1, "re": "Manufacturers specify minimum clearances so the condenser gets adequate airflow (preventing high head pressure) and the unit can be serviced safely.", "rr": "Производитель задаёт минимальные зазоры, чтобы конденсатор получал достаточный обдув (без высокого давления нагнетания) и блок можно было безопасно обслуживать.", "qr": "Достаточный сервисный зазор вокруг наружного конденсатора нужен, чтобы:", "optsr": ["Уменьшить сечение провода", "Обеспечить обдув батареи и место для обслуживания блока", "Хранить хладагент", "Повысить рейтинг SEER"]}, {"id": 339, "sec": "Fabrication & Installation", "q": "Blower speed taps are often set differently for heating and cooling because:", "opts": ["Refrigerant differs", "The thermostat requires it", "Voltage changes", "Cooling needs higher airflow per ton and heating needs a proper temperature rise"], "correct": 3, "re": "Cooling typically uses ~400 CFM/ton; heating airflow is set to keep the furnace temperature rise within the rated range - so the taps usually differ.", "rr": "Охлаждение обычно использует ~400 CFM/тонна; расход на нагреве задают так, чтобы temperature rise печи был в номинальном диапазоне - поэтому скорости обычно разные.", "qr": "Скорости вентилятора часто настраивают по-разному для нагрева и охлаждения, потому что:", "optsr": ["Хладагент другой", "Этого требует термостат", "Меняется напряжение", "Охлаждению нужен больший расход на тонну, а нагреву - правильный temperature rise"]}, {"id": 340, "sec": "Fabrication & Installation", "q": "Converting a furnace from natural gas to LP (propane) requires:", "opts": ["No changes", "Adding refrigerant", "Changing the burner orifices and adjusting gas pressure per the kit", "Replacing the blower"], "correct": 2, "re": "LP has higher heating value and pressure, so a conversion kit with smaller orifices/spuds and a manifold-pressure adjustment is required; never run a gas-mismatched furnace.", "rr": "У LP выше теплотворность и давление, поэтому нужен комплект с меньшими жиклёрами и настройкой давления на манифольде; печь с несоответствующим газом эксплуатировать нельзя.", "qr": "Перевод печи с природного газа на LP (пропан) требует:", "optsr": ["Без изменений", "Добавления хладагента", "Замены жиклёров горелки и настройки давления газа по комплекту", "Замены вентилятора"]}, {"id": 341, "sec": "Fabrication & Installation", "q": "Combustion-air openings to the outdoors for a furnace in a confined space are sized based on:", "opts": ["The duct color", "Refrigerant charge", "The total input BTU/h and the method (direct/indirect) per code", "The SEER"], "correct": 2, "re": "Code sizes combustion-air openings/ducts from total appliance input and whether air comes from inside, outside, or via ducts - ensuring complete combustion.", "rr": "Нормы подбирают отверстия/каналы воздуха горения по суммарному input прибора и тому, откуда берётся воздух (изнутри, снаружи, по каналам) - для полного сгорания.", "qr": "Отверстия для воздуха горения наружу для печи в тесном помещении подбирают по:", "optsr": ["Цвету дакта", "Заправке хладагентом", "Суммарному input BTU/ч и методу (прямой/непрямой) по нормам", "SEER"]}, {"id": 342, "sec": "Fabrication & Installation", "q": "When making a flare on a mini-split, using a torque wrench to the specified value prevents:", "opts": ["High SEER", "Low voltage", "Under- or over-tightening that causes leaks or cracked flares", "Excess airflow"], "correct": 2, "re": "Mini-split flare nuts have specified torque values; too loose leaks, too tight cracks the flare. A torque wrench ensures a reliable, leak-free joint.", "rr": "Гайки flare на мини-сплитах имеют заданный момент; слабо - течёт, сильно - трескается раздача. Динамометрический ключ обеспечивает надёжный герметичный стык.", "qr": "При раздаче (flare) на мини-сплите динамометрический ключ на заданное значение предотвращает:", "optsr": ["Высокий SEER", "Низкое напряжение", "Недо- или перетяжку, ведущую к утечкам или трещинам раздачи", "Избыточный расход воздуха"]}, {"id": 343, "sec": "Fabrication & Installation", "q": "Closed-cell refrigerant line insulation should be:", "opts": ["Removed in summer", "Replaced with tape only", "Sealed at seams/ends to prevent condensation under the insulation", "Left with open seams"], "correct": 2, "re": "Unsealed seams let humid air reach the cold line, causing hidden condensation, dripping, and corrosion; glue/seal all joints and ends.", "rr": "Негерметичные швы пропускают влажный воздух к холодной линии, вызывая скрытый конденсат, капель и коррозию; клейте/герметизируйте все стыки и торцы.", "qr": "Закрытопористую изоляцию линий хладагента следует:", "optsr": ["Снимать летом", "Заменять только лентой", "Герметизировать по швам/торцам, чтобы не было конденсата под изоляцией", "Оставлять с открытыми швами"]}, {"id": 344, "sec": "Fabrication & Installation", "q": "A 125 V service receptacle is commonly required near rooftop/attic HVAC equipment to:", "opts": ["Charge refrigerant", "Power the compressor", "Replace the disconnect", "Provide convenience power for service tools"], "correct": 3, "re": "Electrical code requires a service receptacle within a set distance of the equipment so technicians can power tools and lights for maintenance.", "rr": "Электрические нормы требуют сервисную розетку в пределах заданного расстояния от оборудования, чтобы техники могли питать инструмент и свет при обслуживании.", "qr": "Сервисная розетка 125 В обычно требуется рядом с HVAC-оборудованием на крыше/чердаке, чтобы:", "optsr": ["Заправлять хладагент", "Питать компрессор", "Заменить разъединитель", "Обеспечить вспомогательное питание для сервисного инструмента"]}, {"id": 345, "sec": "Fabrication & Installation", "q": "At startup of a cooling system, a normal indoor temperature split (return vs supply dry-bulb) is about:", "opts": ["Zero", "16-22 F", "40-50 F", "2-5 F"], "correct": 1, "re": "A properly charged system with correct airflow usually shows ~16-22 F drop across the evaporator (varies with indoor wet-bulb); too small or too large signals airflow/charge issues.", "rr": "Правильно заправленная система с верным расходом обычно даёт перепад ~16-22 F на испарителе (зависит от indoor wet-bulb); слишком малый или большой - сигнал проблем расхода/заправки.", "qr": "При запуске охлаждения нормальный внутренний temperature split (обратка против подачи по сухому термометру) составляет около:", "optsr": ["Ноль", "16-22 F", "40-50 F", "2-5 F"]}, {"id": 346, "sec": "Fabrication & Installation", "q": "A condensate pump is used when:", "opts": ["The system is heating only", "There is no condensate", "The equipment is below the drain and condensate must be lifted", "The drain can slope to gravity"], "correct": 2, "re": "When gravity drainage is impossible (basement/below-grade), a condensate pump lifts the water to a drain; it usually has a safety switch to stop the system if it fails.", "rr": "Когда самотёк невозможен (подвал/ниже уровня), конденсатный насос поднимает воду к дренажу; обычно имеет защитный выключатель для останова системы при отказе.", "qr": "Конденсатный насос применяют, когда:", "optsr": ["Система только на нагрев", "Конденсата нет", "Оборудование ниже дренажа и конденсат нужно поднимать", "Дренаж можно вести самотёком"]}, {"id": 347, "sec": "Fabrication & Installation", "q": "A 'whip' (liquid-tight flexible conduit) at the condenser is used so that:", "opts": ["The unit gets more refrigerant", "The SEER increases", "Vibration is not transmitted to rigid conduit and connections flex safely", "The gas line is shorter"], "correct": 2, "re": "A short liquid-tight flex whip absorbs compressor vibration and allows a flexible, weatherproof connection between the disconnect and the unit.", "rr": "Короткая герметичная гибкая подводка гасит вибрацию компрессора и обеспечивает гибкое, влагозащищённое соединение между разъединителем и блоком.", "qr": "Гибкая герметичная подводка ('whip') у конденсатора нужна, чтобы:", "optsr": ["Блок получил больше хладагента", "Вырос SEER", "Вибрация не передавалась на жёсткую трубу и соединение гибко/безопасно работало", "Газовая линия была короче"]}, {"id": 348, "sec": "Fabrication & Installation", "q": "Supporting refrigerant line sets at proper intervals prevents:", "opts": ["High SEER", "Excess subcooling", "Low voltage", "Sagging, stress on joints, and chafing/vibration damage"], "correct": 3, "re": "Unsupported lines sag and vibrate, stressing brazed joints and chafing through insulation; secure them at regular intervals and where they penetrate walls.", "rr": "Неподдержанные линии провисают и вибрируют, нагружая паяные стыки и протирая изоляцию; крепите их через равные интервалы и в местах прохода через стены.", "qr": "Поддержка линий хладагента через нужные интервалы предотвращает:", "optsr": ["Высокий SEER", "Избыточный subcooling", "Низкое напряжение", "Провисание, нагрузку на стыки и истирание/виброповреждение"]}, {"id": 349, "sec": "Fabrication & Installation", "q": "Before energizing a newly installed system, the installer should verify line voltage is:", "opts": ["Always 480 V", "Any value", "Within the unit's rated voltage range on the data plate", "Below 24 V"], "correct": 2, "re": "Operating outside the rated voltage range (e.g., low voltage) causes overheating and component failure; verify supply voltage matches the nameplate before startup.", "rr": "Работа вне номинального диапазона (например низкое напряжение) вызывает перегрев и отказ компонентов; сверьте напряжение питания с шильдиком до запуска.", "qr": "Перед подачей питания на новый монтаж установщик должен убедиться, что линейное напряжение:", "optsr": ["Всегда 480 В", "Любое", "В пределах номинального диапазона блока на шильдике", "Ниже 24 В"]}, {"id": 350, "sec": "Fabrication & Installation", "q": "When installing flexible duct, the inner liner should be:", "opts": ["Filled with refrigerant", "Cut shorter than needed", "Left loose and kinked", "Stretched taut and connected/sealed to the collar, with the insulation/jacket secured"], "correct": 3, "re": "Pull the inner core tight onto the collar, secure with a clamp/strap, seal it, then pull the insulation and vapor jacket over and band them - avoiding compression and leaks.", "rr": "Натяните внутренний рукав на патрубок, закрепите хомутом/стяжкой, загерметизируйте, затем натяните изоляцию и пароизоляционную оболочку и обвяжите - избегая сжатия и утечек.", "qr": "При монтаже гибкого воздуховода внутренний рукав должен быть:", "optsr": ["Заполнен хладагентом", "Обрезан короче нужного", "Оставлен свободным и заломленным", "Натянут и подсоединён/загерметизирован к патрубку, с закреплением изоляции/оболочки"]}, {"id": 351, "sec": "Fabrication & Installation", "q": "A reversing valve on a heat pump is energized by:", "opts": ["A 24 V solenoid coil", "Line voltage compressor power", "Refrigerant pressure only", "The gas valve"], "correct": 0, "re": "The reversing valve's pilot is shifted by a 24 V solenoid coil; the main valve is moved by refrigerant pressure differential once the pilot ports switch.", "rr": "Пилот реверс-клапана переключается соленоидной катушкой 24 В; основной клапан сдвигается перепадом давления хладагента после переключения пилотных каналов.", "qr": "Реверс-клапан теплового насоса запитывается:", "optsr": ["Соленоидной катушкой 24 В", "Сетевым питанием компрессора", "Только давлением хладагента", "Газовым клапаном"]}, {"id": 352, "sec": "Fabrication & Installation", "q": "After brazing in a new filter drier, it should be installed with the arrow:", "opts": ["It does not matter", "Pointing against flow", "Sideways", "Pointing in the direction of refrigerant flow"], "correct": 3, "re": "The drier's arrow must point in the direction of flow (usually liquid line toward the metering device) so it filters and dries correctly.", "rr": "Стрелка осушителя должна указывать по потоку (обычно по жидкостной линии к дозатору), чтобы он правильно фильтровал и осушал.", "qr": "После впайки нового фильтра-осушителя его стрелка должна указывать:", "optsr": ["Неважно", "Против потока", "Вбок", "В направлении потока хладагента"]}, {"id": 353, "sec": "Fabrication & Installation", "q": "When two indoor coils share a heat-pump outdoor unit are not involved, a properly sized suction line on a tall riser may use a double riser to:", "opts": ["Add refrigerant", "Increase noise", "Maintain oil return at both full and reduced capacity", "Lower the SEER"], "correct": 2, "re": "On modulating systems with tall risers, a double (large + small) suction riser keeps velocity high enough for oil return at part load while limiting pressure drop at full load.", "rr": "На модулируемых системах с высокими стояками двойной (большой + малый) всасывающий стояк держит достаточную скорость для возврата масла при частичной нагрузке, ограничивая перепад на полной.", "qr": "На высоком стояке всасывающей линии правильно подобранный двойной стояк применяют, чтобы:", "optsr": ["Добавить хладагент", "Увеличить шум", "Сохранить возврат масла и на полной, и на сниженной мощности", "Снизить SEER"]}, {"id": 354, "sec": "Fabrication & Installation", "q": "Documenting startup readings (pressures, temps, superheat/subcool, static, amps) is important because it:", "opts": ["Is illegal", "Wastes time", "Verifies correct operation and provides a baseline for future service", "Voids the warranty"], "correct": 2, "re": "A commissioning record proves the system was set up correctly and gives a reference for diagnosing future problems and for warranty/HERS documentation.", "rr": "Пусконаладочный протокол доказывает, что система настроена верно, и даёт точку отсчёта для диагностики будущих проблем и для гарантии/HERS-документации.", "qr": "Документирование пусковых показаний (давления, температуры, superheat/subcool, статическое, токи) важно, потому что:", "optsr": ["Незаконно", "Это трата времени", "Подтверждает правильную работу и даёт базовую точку для будущего сервиса", "Аннулирует гарантию"]}, {"id": 355, "sec": "TR", "q": "A cooling system with a very small temperature split (e.g., 8 F) and normal pressures most likely has:", "opts": ["A stuck reversing valve", "Excessive airflow or a humidity-load condition", "A cracked heat exchanger", "Low charge"], "correct": 1, "re": "Too much airflow (or very high latent load) reduces the dry-bulb split; check blower speed and conditions before assuming a refrigerant problem.", "rr": "Слишком большой расход (или очень высокая latent-нагрузка) уменьшает перепад по сухому термометру; проверьте скорость вентилятора и условия, прежде чем винить хладагент.", "qr": "Система охлаждения с очень малым temperature split (например 8 F) и нормальными давлениями скорее всего имеет:", "optsr": ["Заклинивший реверс-клапан", "Избыточный расход воздуха или условие высокой влажностной нагрузки", "Трещину теплообменника", "Недозаправку"]}, {"id": 356, "sec": "TR", "q": "A condenser fan motor that fails (stops) while the compressor runs will cause:", "opts": ["Rapidly rising head pressure and a high-pressure trip", "More subcooling", "Lower amps", "Low head pressure"], "correct": 0, "re": "With no condenser airflow, heat cannot be rejected, so head pressure climbs fast and the high-pressure switch trips (or the compressor overheats). Check the fan motor and its capacitor.", "rr": "Без обдува конденсатора тепло не отводится, давление нагнетания быстро растёт, и срабатывает реле высокого давления (или перегревается компрессор). Проверьте мотор вентилятора и его конденсатор.", "qr": "Отказ (остановка) вентилятора конденсатора при работающем компрессоре вызывает:", "optsr": ["Быстро растущее давление нагнетания и срабатывание защиты по высокому давлению", "Больше subcooling", "Меньший ток", "Низкое давление нагнетания"]}, {"id": 357, "sec": "TR", "q": "A single run capacitor serving both the compressor and condenser fan is a 'dual run' capacitor; its three terminals are labeled:", "opts": ["C (common), HERM, FAN", "L1, L2, L3", "R, S, T", "Y, G, W"], "correct": 0, "re": "A dual-run capacitor has a common (C) terminal plus HERM (compressor) and FAN terminals; a weak section causes that motor to struggle or overheat.", "rr": "Dual-run конденсатор имеет общую (C) клемму плюс HERM (компрессор) и FAN; слабая секция заставляет соответствующий мотор тяжело работать или перегреваться.", "qr": "Один рабочий конденсатор, обслуживающий и компрессор, и вентилятор - это 'dual run' конденсатор; его три клеммы маркированы:", "optsr": ["C (общий), HERM, FAN", "L1, L2, L3", "R, S, T", "Y, G, W"]}, {"id": 358, "sec": "TR", "q": "An ECM blower that won't run but has correct line voltage and a valid thermostat call should be checked for:", "opts": ["The low-voltage control signal and module connector before condemning the motor", "Gas pressure", "Refrigerant level", "Duct color"], "correct": 0, "re": "ECM motors need a proper control signal at the module; verify the 24 V/PWM command and connections - a missing signal mimics a failed motor.", "rr": "ECM-моторам нужен корректный управляющий сигнал на модуле; проверьте команду 24 В/PWM и соединения - отсутствие сигнала имитирует отказ мотора.", "qr": "ECM-вентилятор не крутится при верном линейном напряжении и корректном запросе термостата - проверяют:", "optsr": ["Низковольтный управляющий сигнал и разъём модуля до замены мотора", "Давление газа", "Уровень хладагента", "Цвет дакта"]}, {"id": 359, "sec": "TR", "q": "A furnace flame-rollout switch that has tripped usually indicates:", "opts": ["Too much airflow", "A dirty filter only", "High refrigerant", "Blocked heat exchanger or flue causing flame to roll out of the burner box"], "correct": 3, "re": "Rollout trips when flames spill from the burners (blocked HX passages, restricted venting, or poor combustion air); find and fix the cause - do not just reset.", "rr": "Rollout срабатывает, когда пламя выходит из горелок (засор каналов HX, ограниченное дымоудаление или плохой воздух горения); найдите и устраните причину - не просто сбрасывайте.", "qr": "Сработавший flame-rollout switch печи обычно указывает на:", "optsr": ["Слишком большой расход воздуха", "Только грязный фильтр", "Избыток хладагента", "Засор теплообменника или дымохода, из-за чего пламя выбрасывается из горелочной камеры"]}, {"id": 360, "sec": "TR", "q": "A defrost board stuck so the heat pump stays in defrost too long will cause:", "opts": ["Lower head pressure", "No effect", "Cold air in heating and wasted energy as it keeps reversing to cooling", "Higher heating capacity"], "correct": 2, "re": "A failed defrost sensor/board can over-defrost, repeatedly reversing to cooling and running the aux heat, lowering efficiency and comfort.", "rr": "Неисправный датчик/плата разморозки может пере-размораживать, постоянно реверсируя в охлаждение и гоняя aux-нагрев, снижая КПД и комфорт.", "qr": "Зависшая плата разморозки, из-за которой тепловой насос слишком долго в defrost, вызывает:", "optsr": ["Меньшее давление нагнетания", "Никакого эффекта", "Холодный воздух в нагреве и перерасход энергии из-за постоянного реверса в охлаждение", "Большую теплопроизводительность"]}, {"id": 361, "sec": "TR", "q": "After a compressor burnout, the system must be cleaned up, typically by installing a:", "opts": ["New thermostat", "Suction-line (and liquid-line) acid-removal filter drier and following burnout procedure", "Bigger duct", "Larger condenser"], "correct": 1, "re": "A burnout leaves acid and contaminants; install suction and liquid acid-cleanup driers, monitor/replace them, and test for acid until the system is clean.", "rr": "Выгорание оставляет кислоту и загрязнения; ставят кислотные осушители на всасывание и жидкостную линию, контролируют/меняют их и проверяют на кислоту, пока система не чистая.", "qr": "После выгорания компрессора систему нужно очистить, обычно установив:", "optsr": ["Новый термостат", "Кислотопоглощающий фильтр-осушитель на всасывании (и жидкостной линии) по процедуре burnout", "Больший дакт", "Больший конденсатор"]}, {"id": 362, "sec": "TR", "q": "A contactor whose contacts have welded closed will cause:", "opts": ["A blown fuse only", "Low refrigerant", "The unit to keep running even when the thermostat is satisfied", "The unit to never start"], "correct": 2, "re": "Welded contacts keep the high-voltage circuit closed, so the compressor/condenser runs continuously regardless of the control call - replace the contactor.", "rr": "Приварившиеся контакты держат силовую цепь замкнутой, поэтому компрессор/конденсатор работает непрерывно независимо от запроса - контактор меняют.", "qr": "Контактор с приварившимися контактами вызывает:", "optsr": ["Только перегорание предохранителя", "Недозаправку", "Что блок продолжает работать, даже когда термостат удовлетворён", "Что блок никогда не запустится"]}, {"id": 363, "sec": "TR", "q": "Frost forming on the suction line all the way back to the compressor usually indicates:", "opts": ["Liquid floodback (low superheat) returning to the compressor", "A dirty filter", "Overheating", "High head pressure"], "correct": 0, "re": "Suction frost to the compressor signals very low superheat/floodback - causes include overcharge, a flooding TXV, or low load/airflow; correct before the compressor is damaged.", "rr": "Иней до компрессора - сигнал очень низкого superheat/floodback; причины - перезаправка, переподающий TXV или малая нагрузка/расход; устраните до повреждения компрессора.", "qr": "Иней на всасывающей линии вплоть до компрессора обычно указывает на:", "optsr": ["Возврат жидкости (низкий superheat) в компрессор", "Грязный фильтр", "Перегрев", "Высокое давление нагнетания"]}, {"id": 364, "sec": "TR", "q": "On a three-phase compressor, a significant voltage imbalance between legs (over ~2%) can cause:", "opts": ["Excess current and motor overheating", "Better efficiency", "Lower head pressure", "More subcooling"], "correct": 0, "re": "Voltage imbalance produces a much larger current imbalance and motor heating; investigate supply connections/utility, since prolonged imbalance shortens motor life.", "rr": "Дисбаланс напряжения даёт куда больший дисбаланс тока и нагрев двигателя; проверьте соединения питания/сеть, т.к. длительный дисбаланс сокращает ресурс мотора.", "qr": "На трёхфазном компрессоре значительный дисбаланс напряжения между фазами (более ~2%) может вызвать:", "optsr": ["Избыточный ток и перегрев двигателя", "Лучший КПД", "Меньшее давление нагнетания", "Больше subcooling"]}, {"id": 365, "sec": "TR", "q": "A megohmmeter (insulation tester) is used on a compressor motor to:", "opts": ["Measure refrigerant", "Detect breakdown of winding insulation to ground (motor 'meggering')", "Check superheat", "Set gas pressure"], "correct": 1, "re": "A megger applies high DC voltage to read winding-to-ground insulation resistance in megohms; a low/declining value warns of impending motor failure.", "rr": "Меггер подаёт высокое постоянное напряжение и измеряет сопротивление изоляции обмотка-земля в мегаомах; низкое/падающее значение предупреждает о скором отказе мотора.", "qr": "Мегаомметр (тестер изоляции) применяют на двигателе компрессора, чтобы:", "optsr": ["Измерить хладагент", "Выявить пробой изоляции обмотки на землю ('меггеровка' мотора)", "Проверить superheat", "Задать давление газа"]}, {"id": 366, "sec": "TR", "q": "A blower runs but the gas furnace produces no heat. The first things to check include:", "opts": ["Gas supply, ignition sequence, and flame proving", "Subcooling", "Duct color", "Refrigerant charge"], "correct": 0, "re": "No heat with a running blower points to the gas/ignition side: gas valve, igniter/pilot, flame sensor, limits, and the control board sequence - not the refrigerant circuit.", "rr": "Нет тепла при работающем вентиляторе - это газ/розжиг: газовый клапан, игнайтер/пилот, датчик пламени, лимиты и последовательность платы - не контур хладагента.", "qr": "Вентилятор работает, но газовая печь не греет. В первую очередь проверяют:", "optsr": ["Подачу газа, последовательность розжига и контроль пламени", "Subcooling", "Цвет дакта", "Заправку хладагентом"]}, {"id": 367, "sec": "TR", "q": "A capacitor that tests well below its rated microfarads will cause a motor to:", "opts": ["Start hard, run hot, and draw high amps (or fail to start)", "Increase SEER", "Lower head pressure", "Run cooler"], "correct": 0, "re": "A weak capacitor reduces motor torque and phase shift, so the motor runs hot and over-amps; replace with the exact rated uF and voltage or higher voltage rating.", "rr": "Слабый конденсатор уменьшает момент и фазовый сдвиг, мотор греется и перегружается по току; меняют на точный номинал uF и то же или большее напряжение.", "qr": "Конденсатор, показывающий заметно ниже номинальных микрофарад, заставит мотор:", "optsr": ["Тяжело пускаться, греться и тянуть высокий ток (или не пускаться)", "Повысить SEER", "Снизить давление нагнетания", "Работать холоднее"]}, {"id": 368, "sec": "TR", "q": "A repeatedly tripping high-limit on a furnace, with a clean filter and open registers, may indicate:", "opts": ["A failing blower motor/capacitor or a closed/blocked duct reducing airflow", "A stuck reversing valve", "Low subcooling", "Overcharge"], "correct": 0, "re": "If filters and registers are fine, low airflow may come from a weak blower (motor/cap), slipped belt, or blocked ducting - all overheat the heat exchanger and trip the limit.", "rr": "Если фильтры и решётки в порядке, малый расход может быть от слабого вентилятора (мотор/конденсатор), проскользнувшего ремня или забитого дакта - всё перегревает теплообменник и выбивает лимит.", "qr": "Многократное срабатывание верхнего лимита печи при чистом фильтре и открытых решётках может указывать на:", "optsr": ["Слабый мотор/конденсатор вентилятора или закрытый/забитый дакт, снижающий расход", "Заклинивший реверс-клапан", "Низкий subcooling", "Перезаправку"]}, {"id": 369, "sec": "TR", "q": "To distinguish a low refrigerant charge from a restricted metering device, the technician compares:", "opts": ["Superheat, subcooling, and pressures together against expected values", "Only the voltage", "The duct gauge", "The thermostat brand"], "correct": 0, "re": "Low charge shows high superheat AND low subcooling; a liquid-line restriction often shows high subcooling upstream with low evaporator pressure - reading the full set distinguishes them.", "rr": "Недозаправка даёт высокий superheat И низкий subcooling; засор жидкостной линии часто даёт высокий subcooling до засора при низком давлении испарителя - полный набор показаний их различает.", "qr": "Чтобы отличить недозаправку от засора дозатора, техник сравнивает:", "optsr": ["Superheat, subcooling и давления вместе с ожидаемыми значениями", "Только напряжение", "Толщину дакта", "Бренд термостата"]}, {"id": 370, "sec": "TR", "q": "A noisy compressor that knocks on startup and shows frost at the suction may be experiencing:", "opts": ["High SEER", "Liquid slugging from refrigerant migration or overcharge", "Low voltage only", "Normal operation"], "correct": 1, "re": "Knocking with suction frost suggests liquid entering the compressor (migration during off-cycle or overcharge); a crankcase heater and correct charge help prevent slugging.", "rr": "Стук с инеем на всасывании указывает на попадание жидкости в компрессор (миграция в простое или перезаправка); подогрев картера и верный заряд помогают избежать гидроудара.", "qr": "Шумный компрессор, стучащий при пуске и с инеем на всасывании, может испытывать:", "optsr": ["Высокий SEER", "Гидроудар от миграции хладагента или перезаправки", "Только низкое напряжение", "Нормальную работу"]}, {"id": 371, "sec": "TR", "q": "A maintenance check finds a 10 F+ approach across a clean condenser on a mild day; the next step is to:", "opts": ["Add refrigerant blindly", "Change the thermostat", "Verify charge (subcooling) and condenser airflow before any correction", "Replace the compressor"], "correct": 2, "re": "Diagnose with measurements: confirm subcooling, airflow, and ambient before adjusting charge; never add refrigerant without verifying it is actually low.", "rr": "Диагностируйте измерениями: подтвердите subcooling, обдув и наружную температуру до правки заряда; не добавляйте хладагент, не убедившись, что его реально мало.", "qr": "При ТО обнаружен большой 'approach' (10+ F) на чистом конденсаторе в мягкий день; следующий шаг:", "optsr": ["Доливать хладагент вслепую", "Сменить термостат", "Проверить заправку (subcooling) и обдув конденсатора до любых правок", "Заменить компрессор"]}, {"id": 372, "sec": "TR", "q": "A dirty air filter that is left unchanged over time most directly causes:", "opts": ["Higher refrigerant cost", "More subcooling", "Reduced airflow, lower capacity, and possible coil freezing or limit trips", "Higher voltage"], "correct": 2, "re": "A clogged filter starves airflow, dropping capacity and efficiency; in cooling it can freeze the coil, in heating it can trip the limit - routine filter changes prevent this.", "rr": "Забитый фильтр душит расход, снижая производительность и КПД; в охлаждении может заморозить испаритель, в нагреве - выбить лимит; регулярная замена фильтра это предотвращает.", "qr": "Грязный воздушный фильтр, который долго не меняют, напрямую вызывает:", "optsr": ["Рост стоимости хладагента", "Больше subcooling", "Снижение расхода, падение производительности и возможное обмерзание или срабатывание лимита", "Высокое напряжение"]}, {"id": 373, "sec": "TR", "q": "When the thermostat calls for cooling but nothing runs, a logical first check is:", "opts": ["Flame sensor", "Refrigerant subcooling", "Duct leakage", "24 V at the contactor coil and proper line voltage/disconnect"], "correct": 3, "re": "Trace the circuit: confirm power/disconnect, then 24 V control signal to the contactor; no control voltage points upstream (thermostat, transformer, safeties), not the refrigerant side.", "rr": "Прослеживайте цепь: подтвердите питание/разъединитель, затем сигнал 24 В на контактор; нет управляющего напряжения - проблема выше (термостат, трансформатор, защиты), а не в хладагенте.", "qr": "Когда термостат запрашивает охлаждение, но ничего не работает, логичная первая проверка:", "optsr": ["Датчик пламени", "Subcooling хладагента", "Утечка воздуховодов", "24 В на катушке контактора и нормальное линейное напряжение/разъединитель"]}, {"id": 374, "sec": "TR", "q": "A heat pump providing weak heat with low suction pressure and a frosted outdoor coil that won't clear suggests:", "opts": ["A cracked heat exchanger", "A defrost problem and/or low charge in heating", "Overcharge", "Too much airflow"], "correct": 1, "re": "In heating the outdoor coil is the evaporator; if defrost fails or charge is low, ice builds and heating capacity falls - check the defrost control and charge.", "rr": "В нагреве наружная батарея - испаритель; при отказе разморозки или недозаправке нарастает лёд и падает теплопроизводительность - проверьте управление defrost и заряд.", "qr": "Тепловой насос слабо греет, низкое давление всасывания, наружная батарея обмерзла и не оттаивает - это указывает на:", "optsr": ["Трещину теплообменника", "Проблему разморозки и/или недозаправку в нагреве", "Перезаправку", "Слишком большой расход воздуха"]}, {"id": 375, "sec": "TR", "q": "During maintenance, tightening electrical lugs/terminals is important because loose connections cause:", "opts": ["Higher SEER", "Lower amps", "Heat, voltage drop, and burnt connections/component failure", "More refrigerant"], "correct": 2, "re": "Loose connections add resistance, generating heat and voltage drop that burns terminals and damages contactors/wiring; check and tighten during service.", "rr": "Слабые соединения добавляют сопротивление, создавая нагрев и падение напряжения, что жжёт клеммы и повреждает контакторы/проводку; проверяйте и подтягивайте при обслуживании.", "qr": "При ТО затяжка электрических наконечников/клемм важна, потому что слабые соединения вызывают:", "optsr": ["Высокий SEER", "Меньший ток", "Нагрев, падение напряжения и подгоревшие соединения/отказ компонентов", "Больше хладагента"]}, {"id": 376, "sec": "TR", "q": "A 24 V control fuse that blows the instant power is restored indicates a:", "opts": ["Bad duct", "Short in the low-voltage wiring or a shorted component (e.g., contactor coil)", "Low refrigerant condition", "Dirty filter"], "correct": 1, "re": "An immediately blown control fuse means a dead short in the 24 V circuit - chafed thermostat wire, shorted coil, or pinched cable; find and clear it before re-fusing.", "rr": "Мгновенно сгорающий управляющий предохранитель - это короткое в цепи 24 В: протёртый провод термостата, замкнутая катушка или зажатый кабель; найдите и устраните до замены предохранителя.", "qr": "Управляющий предохранитель 24 В, перегорающий сразу при подаче питания, указывает на:", "optsr": ["Плохой дакт", "Короткое в низковольтной проводке или замкнутый компонент (например катушку контактора)", "Недозаправку", "Грязный фильтр"]}, {"id": 377, "sec": "TR", "q": "Annual maintenance on a gas furnace should include cleaning the flame sensor and:", "opts": ["Disabling the rollout switch", "Removing the limit switch", "Adding refrigerant", "Inspecting the heat exchanger and verifying safe combustion/venting"], "correct": 3, "re": "Maintenance includes flame-sensor cleaning, heat-exchanger inspection, combustion/venting check, and confirming all safeties function - never disable a safety control.", "rr": "ТО включает чистку датчика пламени, осмотр теплообменника, проверку сгорания/дымоудаления и подтверждение работы всех защит - защитное устройство отключать нельзя.", "qr": "Ежегодное ТО газовой печи должно включать чистку датчика пламени и:", "optsr": ["Отключение rollout-выключателя", "Снятие лимитного выключателя", "Добавление хладагента", "Осмотр теплообменника и проверку безопасного сгорания/дымоудаления"]}, {"id": 378, "sec": "TR", "q": "Comparing measured compressor running amps to the nameplate RLA helps determine whether the compressor is:", "opts": ["The right color", "A heat pump", "Overloaded, undersized for conditions, or operating normally", "Out of refrigerant by itself"], "correct": 2, "re": "Running amps near RLA at design conditions is normal; well over RLA suggests high head/overcharge/mechanical issues, far below may indicate undercharge or unloading - interpret with the pressures.", "rr": "Ток около RLA при расчётных условиях нормален; заметно выше RLA - высокое давление/перезаправка/механика, заметно ниже - недозаправка или разгрузка; трактуйте вместе с давлениями.", "qr": "Сравнение измеренного рабочего тока компрессора с RLA на шильдике помогает определить, что компрессор:", "optsr": ["Правильного цвета", "Тепловой насос", "Перегружен, недогружен по условиям или работает нормально", "Сам по себе без хладагента"]}, {"id": 379, "sec": "Safety & Field Practices", "q": "Refrigerant cylinders transported in a vehicle should be:", "opts": ["Laid on their side near the engine", "Secured upright, valve protected, in a ventilated area (not the passenger cabin)", "Loose in the passenger cabin", "Heated for pressure"], "correct": 1, "re": "Secure cylinders upright with valve caps on, in a ventilated cargo area away from occupants and heat, to prevent leaks, rolling, and asphyxiation hazards.", "rr": "Закрепляйте баллоны вертикально с колпачками на вентилях, в проветриваемом грузовом отсеке вдали от людей и тепла - чтобы избежать утечек, перекатывания и удушья.", "qr": "Баллоны с хладагентом при перевозке в автомобиле должны быть:", "optsr": ["Лежать на боку у двигателя", "Закреплены вертикально, с защитой вентиля, в проветриваемой зоне (не в салоне)", "Свободно в салоне", "Подогреты для давления"]}, {"id": 380, "sec": "Safety & Field Practices", "q": "In a permit-required confined space, a safe oxygen level is generally:", "opts": ["19.5% to 23.5%", "Above 30%", "Exactly 50%", "Below 15%"], "correct": 0, "re": "Normal/safe oxygen is 19.5-23.5%; below 19.5% is oxygen-deficient (asphyxiation risk) and above 23.5% is oxygen-enriched (fire risk). Test before entry.", "rr": "Нормальный/безопасный кислород 19.5-23.5%; ниже 19.5% - кислородное голодание (удушье), выше 23.5% - переобогащение (пожароопасно). Проверяйте до входа.", "qr": "В замкнутом пространстве с допуском безопасный уровень кислорода обычно:", "optsr": ["19.5% - 23.5%", "Выше 30%", "Ровно 50%", "Ниже 15%"]}, {"id": 381, "sec": "Safety & Field Practices", "q": "Old thermostats containing a mercury bulb must be:", "opts": ["Disposed of as universal/hazardous waste (mercury recovery)", "Thrown in regular trash", "Burned", "Buried on site"], "correct": 0, "re": "Mercury is toxic; mercury-switch thermostats are universal waste and must be recycled through approved programs, never landfilled or incinerated.", "rr": "Ртуть токсична; ртутные термостаты - universal waste, их сдают через одобренные программы переработки, не на свалку и не на сжигание.", "qr": "Старые термостаты с ртутной колбой необходимо:", "optsr": ["Утилизировать как universal/опасные отходы (сбор ртути)", "Выбросить в обычный мусор", "Сжечь", "Закопать на месте"]}, {"id": 382, "sec": "Safety & Field Practices", "q": "Old fluorescent ballasts or capacitors may contain PCBs, which require:", "opts": ["Handling and disposal as hazardous waste", "Regular trash disposal", "No precautions", "Burning on site"], "correct": 0, "re": "PCB-containing ballasts/capacitors are hazardous waste; handle to avoid leaks and dispose through proper hazardous-waste channels.", "rr": "Балласты/конденсаторы с PCB - опасные отходы; обращайтесь так, чтобы избежать течи, и утилизируйте через надлежащие каналы опасных отходов.", "qr": "Старые люминесцентные балласты или конденсаторы могут содержать PCB (ПХБ), что требует:", "optsr": ["Обращения и утилизации как опасные отходы", "Выброса в обычный мусор", "Никаких мер", "Сжигания на месте"]}, {"id": 383, "sec": "Safety & Field Practices", "q": "The first action when someone is being shocked and cannot let go of an energized circuit is to:", "opts": ["Wait and watch", "De-energize the circuit (kill power) before touching them", "Pour water on them", "Pull them with bare hands"], "correct": 1, "re": "Never touch a person in contact with live current; shut off the power/disconnect first (or use a non-conductive means), then call for help and give aid.", "rr": "Никогда не касайтесь человека в контакте с током; сначала отключите питание/разъединитель (или используйте непроводящее средство), затем зовите помощь и оказывайте её.", "qr": "Первое действие, когда человека бьёт током и он не может оторваться от цепи под напряжением:", "optsr": ["Ждать и наблюдать", "Обесточить цепь (снять питание) до прикосновения к нему", "Облить водой", "Тянуть его голыми руками"]}, {"id": 384, "sec": "Safety & Field Practices", "q": "First aid for inhaling a high concentration of refrigerant vapor is to:", "opts": ["Have them keep working", "Move the person to fresh air immediately and seek medical help", "Apply heat", "Give the person caffeine"], "correct": 1, "re": "Refrigerant vapor displaces oxygen and can cause dizziness/asphyxiation; get the person to fresh air at once, monitor breathing, and get medical attention per the SDS.", "rr": "Пары хладагента вытесняют кислород и вызывают головокружение/удушье; немедленно выведите человека на свежий воздух, контролируйте дыхание и обратитесь за медпомощью по SDS.", "qr": "Первая помощь при вдыхании высокой концентрации паров хладагента:", "optsr": ["Заставить продолжать работу", "Немедленно вывести человека на свежий воздух и обратиться за медпомощью", "Приложить тепло", "Дать кофеин"]}, {"id": 385, "sec": "Safety & Field Practices", "q": "A respirator selected for a specific dust or vapor must be:", "opts": ["Any mask available", "Matched to the hazard, fit-tested, and used within a respiratory-protection program", "A surgical mask", "Optional always"], "correct": 1, "re": "Respirator choice (e.g., N95/P100 for particulates, cartridges for vapors) must match the hazard, be fit-tested, and follow Cal/OSHA's respiratory-protection requirements.", "rr": "Выбор респиратора (например N95/P100 для частиц, картриджи для паров) должен соответствовать опасности, пройти fit-test и следовать требованиям Cal/OSHA по защите дыхания.", "qr": "Респиратор, выбранный под конкретную пыль или пар, должен быть:", "optsr": ["Любой имеющейся маской", "Подобран под опасность, проверен на прилегание (fit-test) и использован в программе защиты органов дыхания", "Хирургической маской", "Всегда необязателен"]}, {"id": 386, "sec": "Safety & Field Practices", "q": "Heat stroke differs from heat exhaustion in that heat stroke:", "opts": ["Only causes thirst", "Needs no action", "Is a medical emergency (high body temp, confusion) requiring immediate cooling and 911", "Is minor"], "correct": 2, "re": "Heat exhaustion (heavy sweating, weakness) is serious; heat stroke (hot dry skin or confusion, very high temperature) is life-threatening - cool rapidly and call 911 immediately.", "rr": "Тепловое истощение (сильное потоотделение, слабость) серьёзно; тепловой удар (горячая сухая кожа или спутанность, очень высокая температура) опасен для жизни - быстро охлаждайте и звоните 911.", "qr": "Тепловой удар отличается от теплового истощения тем, что тепловой удар:", "optsr": ["Вызывает только жажду", "Не требует действий", "Это неотложное состояние (высокая температура тела, спутанность), требующее немедленного охлаждения и 911", "Незначителен"]}, {"id": 387, "sec": "Safety & Field Practices", "q": "Under Cal/OSHA's heat illness standard, new or returning workers in high heat should be:", "opts": ["Sent to the roof alone", "Denied water", "Acclimatized gradually and closely observed", "Worked at full pace immediately"], "correct": 2, "re": "Acclimatization (gradually building heat tolerance over days) and close observation of new/returning workers reduce heat-illness risk during heat waves.", "rr": "Акклиматизация (постепенное наращивание переносимости жары за несколько дней) и пристальное наблюдение за новыми/вернувшимися работниками снижают риск тепловых болезней в жару.", "qr": "По стандарту Cal/OSHA о тепловых болезнях новые или вернувшиеся работники в сильную жару должны:", "optsr": ["Отправлены на крышу в одиночку", "Быть лишены воды", "Постепенно акклиматизироваться и быть под пристальным наблюдением", "Сразу работать в полном темпе"]}, {"id": 388, "sec": "Safety & Field Practices", "q": "An extension ladder used on the job should have a duty rating that:", "opts": ["Meets or exceeds the combined weight of worker plus tools/materials", "Does not matter", "Is the cheapest available", "Is always Type III"], "correct": 0, "re": "Choose a ladder duty rating (e.g., Type IA = 300 lb) at or above the total load; overloading a ladder risks structural failure and falls.", "rr": "Выбирайте нагрузочный рейтинг лестницы (например Type IA = 300 фунтов) не ниже полной нагрузки; перегрузка лестницы грозит разрушением и падением.", "qr": "Раздвижная лестница на работе должна иметь нагрузочный рейтинг, который:", "optsr": ["Соответствует или превышает суммарный вес работника плюс инструмент/материалы", "Неважен", "Самый дешёвый из доступных", "Всегда Type III"]}, {"id": 389, "sec": "Safety & Field Practices", "q": "Before touching a circuit you believe is de-energized, the safest practice is to:", "opts": ["Test before touch: verify zero voltage with a meter proven on a known live source", "Touch it quickly", "Wear gloves only", "Assume it is off"], "correct": 0, "re": "'Test before touch' (live-dead-live): confirm your meter works on a known live source, verify the circuit reads zero, then re-confirm the meter - this catches LOTO errors.", "rr": "'Проверь до касания' (живое-мёртвое-живое): убедитесь, что прибор работает на заведомо живом источнике, проверьте нуль на цепи, затем перепроверьте прибор - это ловит ошибки LOTO.", "qr": "Перед прикосновением к цепи, которую считаете обесточенной, безопаснее всего:", "optsr": ["Проверить до касания: убедиться в нуле напряжения мультиметром, проверенным на заведомо живом источнике", "Быстро коснуться", "Только надеть перчатки", "Предположить, что она выключена"]}, {"id": 390, "sec": "Safety & Field Practices", "q": "Portable fire extinguishers on a jobsite must be:", "opts": ["Used only by managers", "Left empty", "Inspected/maintained and charged, with the right class for the hazard", "Painted any color"], "correct": 2, "re": "Extinguishers must be accessible, inspected, fully charged, and of the correct class (ABC for general HVAC work near electrical) to be effective.", "rr": "Огнетушители должны быть доступны, проверены, полностью заряжены и нужного класса (ABC для общих HVAC-работ у электрики), чтобы быть эффективными.", "qr": "Переносные огнетушители на объекте должны быть:", "optsr": ["Использоваться только руководителями", "Оставлены пустыми", "Проверены/обслужены и заряжены, нужного класса под опасность", "Покрашены в любой цвет"]}, {"id": 391, "sec": "Safety & Field Practices", "q": "Hearing protection should be worn when:", "opts": ["Only indoors", "Noise levels are high enough to require it (e.g., near loud equipment/power tools)", "Only at night", "Never on HVAC jobs"], "correct": 1, "re": "Sustained high noise damages hearing; wear earplugs/muffs when working around loud blowers, compressors, or power tools per the noise exposure limits.", "rr": "Длительный высокий шум повреждает слух; надевайте беруши/наушники у громких вентиляторов, компрессоров или электроинструмента согласно лимитам шумового воздействия.", "qr": "Защиту слуха следует носить, когда:", "optsr": ["Только в помещении", "Уровень шума достаточно высок (например рядом с громким оборудованием/электроинструментом)", "Только ночью", "Никогда на HVAC-работах"]}, {"id": 392, "sec": "Safety & Field Practices", "q": "A compressed-gas cylinder (refrigerant or nitrogen) in use or storage should be:", "opts": ["Left in walkways", "Laid on its side unsecured", "Used as a roller", "Secured upright (chained/strapped) so it cannot fall"], "correct": 3, "re": "Cylinders must be secured upright so they cannot tip; a falling cylinder can shear the valve and become a dangerous projectile.", "rr": "Баллоны крепят вертикально, чтобы не опрокинулись; падающий баллон может срезать вентиль и стать опасным снарядом.", "qr": "Баллон со сжатым газом (хладагент или азот) при использовании или хранении должен быть:", "optsr": ["Оставлен в проходах", "Лежать на боку незакреплённым", "Использоваться как каток", "Закреплён вертикально (цепью/ремнём), чтобы не упасть"]}, {"id": 393, "sec": "Safety & Field Practices", "q": "When charging or recovering, a recovery cylinder must never be overfilled because:", "opts": ["It adds moisture", "It lowers efficiency", "It changes the color", "Hydrostatic pressure from liquid expansion can rupture it"], "correct": 3, "re": "Filling past 80% leaves no room for liquid expansion; as temperature rises, hydrostatic pressure can burst the cylinder - use a scale and never overfill.", "rr": "Заполнение свыше 80% не оставляет места для расширения жидкости; при росте температуры гидростатическое давление может разорвать баллон - используйте весы и не переполняйте.", "qr": "При заправке или откачке recovery-баллон нельзя переполнять, потому что:", "optsr": ["Это добавляет влагу", "Это снижает КПД", "Это меняет цвет", "Гидростатическое давление от расширения жидкости может его разорвать"]}, {"id": 394, "sec": "Safety & Field Practices", "q": "Before performing hot work (brazing) in an occupied building, a technician should:", "opts": ["Disable smoke alarms permanently", "Clear/protect combustibles, have an extinguisher and fire watch ready", "Use more flux", "Skip notifying anyone"], "correct": 1, "re": "Hot work requires removing or shielding combustibles, a charged extinguisher at hand, and a fire watch during and after the work to catch smoldering ignition.", "rr": "Огневые работы требуют убрать или прикрыть горючее, держать заряженный огнетушитель под рукой и вести пожарный надзор во время и после работы, чтобы поймать тлеющее возгорание.", "qr": "Перед огневыми работами (пайкой) в занятом здании техник должен:", "optsr": ["Навсегда отключить дымовые извещатели", "Убрать/защитить горючие материалы, иметь под рукой огнетушитель и пожарный надзор", "Использовать больше флюса", "Никого не предупреждать"]}, {"id": 395, "sec": "Safety & Field Practices", "q": "Eye protection rated for impact and brazing glare should be worn because:", "opts": ["It looks professional", "Flux spatter, hot metal, and intense light can injure unprotected eyes", "It is only for managers", "It increases SEER"], "correct": 1, "re": "Brazing produces glare and spatter; impact/shade-rated eyewear protects against burns, flying particles, and harmful light during fabrication.", "rr": "Пайка даёт блеск и брызги; очки с рейтингом на удар/затемнение защищают от ожогов, летящих частиц и вредного света при изготовлении.", "qr": "Защита глаз с рейтингом на удар и блеск пайки нужна, потому что:", "optsr": ["Это выглядит профессионально", "Брызги флюса, горячий металл и яркий свет травмируют незащищённые глаза", "Это только для руководителей", "Это повышает SEER"]}, {"id": 396, "sec": "Safety & Field Practices", "q": "Cal/OSHA's written Injury and Illness Prevention Program (IIPP) must include:", "opts": ["A marketing plan", "Hazard identification, correction, training, and communication procedures", "Refrigerant prices", "Only a logo"], "correct": 1, "re": "Every California employer must maintain an IIPP that identifies and corrects hazards, trains employees, and documents safety communication and responsibility.", "rr": "Каждый работодатель Калифорнии обязан вести IIPP, которая выявляет и устраняет опасности, обучает работников и документирует информирование и ответственность по безопасности.", "qr": "Письменная программа предотвращения травм и болезней (IIPP) Cal/OSHA должна включать:", "optsr": ["Маркетинговый план", "Выявление и устранение опасностей, обучение и процедуры информирования", "Цены на хладагент", "Только логотип"]}, {"id": 397, "sec": "Safety & Field Practices", "q": "A ladder set up to access a roof should extend above the roof edge by about:", "opts": ["About 3 feet (36 in) for a safe handhold", "0 inches", "It should be below the edge", "10 feet"], "correct": 0, "re": "Extend the ladder ~3 ft above the landing/roof edge and secure the top so the worker has a stable handhold when stepping on and off.", "rr": "Выпускайте лестницу на ~3 фута над площадкой/краем крыши и закрепляйте верх, чтобы у работника был устойчивый хват при заходе и сходе.", "qr": "Лестница для выхода на крышу должна выступать над краем крыши примерно на:", "optsr": ["Около 3 футов (36 дюймов) для безопасного хвата", "0 дюймов", "Ниже края", "10 футов"]}, {"id": 398, "sec": "Safety & Field Practices", "q": "When entering an attic that may exceed safe temperatures in summer, the technician should:", "opts": ["Limit exposure, hydrate, ventilate, and watch for heat-illness symptoms", "Work as long as possible", "Wear heavy clothing", "Skip water breaks"], "correct": 0, "re": "Attics can reach dangerous heat; limit time, take water/rest breaks, ventilate if possible, and stop at the first signs of heat illness.", "rr": "Чердаки могут достигать опасной жары; ограничьте время, делайте перерывы на воду/отдых, проветривайте при возможности и прекращайте при первых признаках теплового удара.", "qr": "При входе на чердак, который летом может превышать безопасную температуру, техник должен:", "optsr": ["Ограничить пребывание, пить воду, проветривать и следить за симптомами теплового удара", "Работать как можно дольше", "Надеть тёплую одежду", "Пропускать перерывы на воду"]}, {"id": 399, "sec": "Safety & Field Practices", "q": "Recovered refrigerant and used compressor oil must be:", "opts": ["Mixed and burned", "Poured down a drain", "Managed and disposed of properly (oil as hazardous waste; refrigerant recovered/reclaimed)", "Vented outdoors"], "correct": 2, "re": "Never dump refrigerant or oil; recover refrigerant for reuse/reclaim and manage used oil as hazardous waste through approved disposal/recycling.", "rr": "Никогда не сливайте хладагент или масло; хладагент откачивают для повторного использования/регенерации, а отработанное масло сдают как опасные отходы через одобренную утилизацию/переработку.", "qr": "Откачанный хладагент и отработанное масло компрессора нужно:", "optsr": ["Смешать и сжечь", "Слить в канализацию", "Правильно собрать и утилизировать (масло как опасные отходы; хладагент - откачать/регенерировать)", "Стравить наружу"]}, {"id": 400, "sec": "Safety & Field Practices", "q": "The safest overall approach when any unfamiliar or hazardous condition is found on a job is to:", "opts": ["Remove the safety devices", "Proceed quickly and hope", "Ignore safety to save time", "Stop, assess the hazard, follow the SDS/codes, and use proper PPE and procedures"], "correct": 3, "re": "A stop-and-assess approach - reading the SDS, following code, and using correct PPE/lockout - prevents injuries; production never justifies bypassing safety.", "rr": "Подход 'остановись и оцени' - чтение SDS, соблюдение норм и правильные СИЗ/блокировки - предотвращает травмы; выработка никогда не оправдывает обход безопасности.", "qr": "Самый безопасный общий подход при обнаружении незнакомого или опасного условия на работе:", "optsr": ["Снять защитные устройства", "Быстро действовать и надеяться", "Игнорировать безопасность ради времени", "Остановиться, оценить опасность, следовать SDS/нормам и применять нужные СИЗ и процедуры"]}, {"id": 401, "sec": "Principles & Load Calculations", "q": "A pressure-temperature (P-T) chart is used by a technician to:", "opts": ["Size ductwork", "Find the saturation temperature of a refrigerant at a measured pressure", "Calculate wire size", "Set the gas pressure"], "correct": 1, "re": "A P-T chart lists the saturation (boiling/condensing) temperature of each refrigerant at a given pressure - essential for figuring superheat and subcooling.", "rr": "P-T таблица даёт температуру насыщения (кипения/конденсации) каждого хладагента при заданном давлении - нужна для расчёта superheat и subcooling.", "qr": "Таблицу давление-температура (P-T) техник использует, чтобы:", "optsr": ["Подбирать воздуховоды", "Найти температуру насыщения хладагента при измеренном давлении", "Рассчитать сечение провода", "Задать давление газа"]}, {"id": 402, "sec": "Principles & Load Calculations", "q": "Absolute pressure (psia) is equal to gauge pressure (psig) plus approximately:", "opts": ["100", "14.7", "32", "0"], "correct": 1, "re": "psia = psig + 14.7 (atmospheric pressure at sea level). Absolute pressure is used for compression-ratio and vacuum (micron) work.", "rr": "psia = psig + 14.7 (атмосферное давление на уровне моря). Абсолютное давление используют для compression ratio и вакуума (микроны).", "qr": "Абсолютное давление (psia) равно манометрическому (psig) плюс приблизительно:", "optsr": ["100", "14.7", "32", "0"]}, {"id": 403, "sec": "Principles & Load Calculations", "q": "The saturation temperature of a refrigerant is the temperature at which it:", "opts": ["Boils/condenses (changes state) at a given pressure", "Reaches room temperature", "Loses all heat", "Freezes solid"], "correct": 0, "re": "At saturation the refrigerant is changing state (liquid<->vapor) at the corresponding pressure; superheat and subcooling are measured relative to this temperature.", "rr": "При насыщении хладагент меняет состояние (жидкость<->пар) при соответствующем давлении; superheat и subcooling отсчитывают от этой температуры.", "qr": "Температура насыщения хладагента - это температура, при которой он:", "optsr": ["Кипит/конденсируется (меняет состояние) при данном давлении", "Достигает комнатной температуры", "Теряет всё тепло", "Замерзает в твёрдое тело"]}, {"id": 404, "sec": "Principles & Load Calculations", "q": "Specific heat is the amount of heat needed to raise the temperature of one pound of a substance by:", "opts": ["10 degrees", "1 degree F", "Any amount", "100 degrees"], "correct": 1, "re": "Specific heat is BTU per pound per degree F. Water is the reference at 1.0 BTU/lb/F; air is about 0.24.", "rr": "Удельная теплоёмкость - BTU на фунт на градус F. Вода - эталон 1.0 BTU/фунт/F; воздух около 0.24.", "qr": "Удельная теплоёмкость - это количество тепла для нагрева одного фунта вещества на:", "optsr": ["10 градусов", "1 градус F", "Любую величину", "100 градусов"]}, {"id": 405, "sec": "Principles & Load Calculations", "q": "During a change of state (e.g., boiling), heat added to a refrigerant:", "opts": ["Changes its state at a constant temperature (latent heat)", "Is lost entirely", "Lowers its pressure", "Raises its temperature rapidly"], "correct": 0, "re": "Latent heat changes state without a temperature change; sensible heat changes temperature. In the evaporator, latent absorption does the cooling work.", "rr": "Latent heat меняет состояние без изменения температуры; sensible heat меняет температуру. В испарителе именно latent-поглощение даёт охлаждение.", "qr": "Во время смены состояния (например кипения) тепло, добавленное хладагенту:", "optsr": ["Меняет его состояние при постоянной температуре (latent heat)", "Полностью теряется", "Снижает его давление", "Быстро повышает его температуру"]}, {"id": 406, "sec": "Principles & Load Calculations", "q": "HSPF is a rating that measures a heat pump's:", "opts": ["Cooling efficiency", "Seasonal heating efficiency", "Refrigerant charge", "Duct leakage"], "correct": 1, "re": "HSPF (Heating Seasonal Performance Factor) rates heating-mode efficiency over a season; SEER/SEER2 rates cooling. Higher HSPF means more efficient heating.", "rr": "HSPF (Heating Seasonal Performance Factor) оценивает эффективность в режиме нагрева за сезон; SEER/SEER2 - охлаждение. Выше HSPF - эффективнее нагрев.", "qr": "HSPF - это рейтинг, измеряющий у теплового насоса:", "optsr": ["Эффективность охлаждения", "Сезонную эффективность нагрева", "Заправку хладагентом", "Утечку воздуховодов"]}, {"id": 407, "sec": "Principles & Load Calculations", "q": "The newer SEER2/EER2 efficiency ratings differ from SEER/EER mainly because they are tested at:", "opts": ["Colder outdoor temps", "No airflow", "A higher external static pressure (more realistic duct conditions)", "Lower voltage"], "correct": 2, "re": "SEER2/EER2 (effective 2023) use higher external static pressure in testing to better reflect real installed duct systems, so the numbers run a bit lower than old SEER.", "rr": "SEER2/EER2 (с 2023) испытывают при более высоком внешнем статическом давлении, ближе к реальным дактам, поэтому значения чуть ниже старого SEER.", "qr": "Новые рейтинги SEER2/EER2 отличаются от SEER/EER главным образом тем, что испытываются при:", "optsr": ["Более холодной улице", "Нулевом расходе", "Более высоком внешнем статическом давлении (реалистичнее условия дактов)", "Меньшем напряжении"]}, {"id": 408, "sec": "Principles & Load Calculations", "q": "A gas furnace installed at high altitude typically must be derated by roughly:", "opts": ["About 4% per 1000 ft above ~2000 ft elevation", "No change", "Doubled", "50% always"], "correct": 0, "re": "Thinner air at altitude reduces combustion air; most manufacturers derate input about 4% per 1000 ft above 2000 ft (follow the rating-plate/manufacturer instructions).", "rr": "Разрежённый воздух на высоте уменьшает воздух горения; большинство производителей снижают input около 4% на 1000 футов выше 2000 футов (по шильдику/инструкции).", "qr": "Газовая печь на большой высоте обычно должна быть derate (снижение мощности) примерно на:", "optsr": ["Около 4% на 1000 футов выше ~2000 футов высоты", "Без изменений", "Удвоена", "Всегда 50%"]}, {"id": 409, "sec": "Principles & Load Calculations", "q": "The equal-friction method of duct design sizes ducts to maintain a constant:", "opts": ["Air temperature", "Refrigerant pressure", "Friction loss per 100 ft of duct", "Voltage"], "correct": 2, "re": "Equal-friction design keeps the friction rate (e.g., 0.1 in WC per 100 ft) constant throughout, sizing each section to that target for the required CFM.", "rr": "Equal-friction держит friction rate (например 0.1 in WC на 100 футов) постоянным по всей системе, подбирая каждый участок под этот таргет для нужного CFM.", "qr": "Метод равного трения (equal-friction) при проектировании воздуховодов поддерживает постоянным:", "optsr": ["Температуру воздуха", "Давление хладагента", "Потери на трение на 100 футов дакта", "Напряжение"]}, {"id": 410, "sec": "Principles & Load Calculations", "q": "Standard air used in HVAC calculations is assumed to have a density of about:", "opts": ["14.7 lb/ft3", "0.0 lb/ft3", "0.075 lb/ft3", "1.0 lb/ft3"], "correct": 2, "re": "Standard air is ~0.075 lb/ft3 (70 F, sea level, 50% RH). The 1.08 and 4.5 constants are based on this; high altitude/temperature requires correction.", "rr": "Стандартный воздух ~0.075 фунт/фт3 (70 F, уровень моря, 50% RH). Коэффициенты 1.08 и 4.5 основаны на этом; высота/температура требуют поправки.", "qr": "Стандартный воздух в расчётах HVAC принимают с плотностью около:", "optsr": ["14.7 фунт/фт3", "0.0 фунт/фт3", "0.075 фунт/фт3", "1.0 фунт/фт3"]}, {"id": 411, "sec": "Principles & Load Calculations", "q": "An air-side economizer saves energy by:", "opts": ["Using cool outdoor air for free cooling when conditions allow", "Closing all dampers", "Running the heat", "Adding refrigerant"], "correct": 0, "re": "When outdoor air is cool/dry enough, an economizer brings in outside air to cool the space instead of running the compressor, reducing energy use.", "rr": "Когда наружный воздух достаточно прохладный/сухой, экономайзер впускает его для охлаждения помещения вместо работы компрессора, снижая расход энергии.", "qr": "Воздушный экономайзер экономит энергию, используя:", "optsr": ["Прохладный наружный воздух для бесплатного охлаждения, когда условия позволяют", "Закрытие всех заслонок", "Нагрев", "Добавление хладагента"]}, {"id": 412, "sec": "Principles & Load Calculations", "q": "An ERV (energy recovery ventilator) is used to:", "opts": ["Replace the furnace", "Increase head pressure", "Recover heat (and moisture) from exhaust air to precondition incoming fresh air", "Add refrigerant"], "correct": 2, "re": "An ERV transfers heat and moisture between exhaust and intake air, providing fresh-air ventilation while reducing the heating/cooling load of that ventilation.", "rr": "ERV передаёт тепло и влагу между вытяжкой и притоком, обеспечивая вентиляцию свежим воздухом и снижая нагрузку отопления/охлаждения от этой вентиляции.", "qr": "ERV (рекуператор энергии) применяют, чтобы:", "optsr": ["Заменить печь", "Поднять давление нагнетания", "Возвращать тепло (и влагу) из вытяжного воздуха для подготовки притока", "Добавить хладагент"]}, {"id": 413, "sec": "Principles & Load Calculations", "q": "Make-up air must be provided when a building has large exhaust fans in order to:", "opts": ["Increase the SEER", "Replace exhausted air and prevent negative pressure/backdrafting", "Lower the gas pressure", "Add refrigerant"], "correct": 1, "re": "Without make-up air, big exhaust fans depressurize the building, which can backdraft combustion appliances and pull in unconditioned air. Provide balanced make-up air.", "rr": "Без make-up воздуха мощные вытяжки создают разрежение, что вызывает обратную тягу у топливных приборов и подсос неподготовленного воздуха. Обеспечьте сбалансированный приток.", "qr": "Подпиточный (make-up) воздух нужен, когда в здании мощные вытяжки, чтобы:", "optsr": ["Повысить SEER", "Заменить удаляемый воздух и не допустить разрежения/обратной тяги", "Снизить давление газа", "Добавить хладагент"]}, {"id": 414, "sec": "Principles & Load Calculations", "q": "A bypass damper in a zoned system is used to:", "opts": ["Increase the load", "Relieve excess air pressure when only a few zones call", "Add refrigerant", "Close the gas valve"], "correct": 1, "re": "When only small zones are open, a bypass damper relieves excess airflow to prevent high static pressure and noise, though proper zone design limits its need.", "rr": "Когда открыты лишь малые зоны, bypass-заслонка сбрасывает избыток воздуха, предотвращая высокое статическое давление и шум, хотя грамотная зональность снижает её необходимость.", "qr": "Перепускная (bypass) заслонка в зональной системе нужна, чтобы:", "optsr": ["Увеличить нагрузку", "Сбросить избыточное давление воздуха, когда открыто мало зон", "Добавить хладагент", "Закрыть газовый клапан"]}, {"id": 415, "sec": "Principles & Load Calculations", "q": "In a home with central returns, a door undercut or transfer grille is provided so that:", "opts": ["Gas can vent", "Air can return from closed rooms back to the return (pressure balance)", "Refrigerant flows", "The duct gets smaller"], "correct": 1, "re": "Closed-door rooms need a return path (undercut/transfer grille/jump duct); without it, supply air pressurizes the room and starves return airflow.", "rr": "Комнатам с закрытой дверью нужен путь возврата (подрез/transfer-решётка/jump-дакт); без него приток создаёт избыточное давление в комнате и душит обратку.", "qr": "В доме с центральной обраткой подрез двери или transfer-решётку делают, чтобы:", "optsr": ["Газ выходил", "Воздух мог вернуться из закрытых комнат к обратке (баланс давления)", "Тёк хладагент", "Дакт стал меньше"]}, {"id": 416, "sec": "Principles & Load Calculations", "q": "To convert electrical power in kilowatts to BTU/h, multiply kW by approximately:", "opts": ["12000", "3412", "100", "746"], "correct": 1, "re": "1 kW = 3412 BTU/h. This converts electric-heat or equipment kW into heat output/load (e.g., a 5 kW strip heater = ~17,060 BTU/h).", "rr": "1 кВт = 3412 BTU/ч. Так переводят электронагрев или оборудование в кВт в теплоотдачу/нагрузку (например ТЭН 5 кВт = ~17 060 BTU/ч).", "qr": "Чтобы перевести электрическую мощность из киловатт в BTU/ч, умножьте кВт примерно на:", "optsr": ["12000", "3412", "100", "746"]}, {"id": 417, "sec": "Principles & Load Calculations", "q": "For natural-gas billing/sizing, one therm equals about:", "opts": ["3412 BTU", "100,000 BTU", "12,000 BTU", "1000 BTU"], "correct": 1, "re": "A therm is 100,000 BTU of gas energy. Knowing therms and meter clocking lets a tech relate fuel use to furnace input.", "rr": "Therm - это 100 000 BTU энергии газа. Зная термы и clocking счётчика, техник связывает расход топлива с input печи.", "qr": "Для учёта/подбора природного газа один therm равен примерно:", "optsr": ["3412 BTU", "100 000 BTU", "12 000 BTU", "1000 BTU"]}, {"id": 418, "sec": "Principles & Load Calculations", "q": "EER and COP are related by the expression:", "opts": ["EER = COP / 100", "EER = COP", "EER = COP x 3.412", "EER = COP + 12"], "correct": 2, "re": "EER (BTU/h per watt) = COP x 3.412, since 1 watt = 3.412 BTU/h. COP is the dimensionless ratio of heat moved to energy input.", "rr": "EER (BTU/ч на ватт) = COP x 3.412, т.к. 1 ватт = 3.412 BTU/ч. COP - безразмерное отношение перемещённого тепла к затраченной энергии.", "qr": "EER и COP связаны выражением:", "optsr": ["EER = COP / 100", "EER = COP", "EER = COP x 3.412", "EER = COP + 12"]}, {"id": 419, "sec": "Principles & Load Calculations", "q": "In California Title 24, a CF1R (Certificate of Compliance) is generally completed at the:", "opts": ["Sale of the home", "Final inspection only", "Design/permit-application stage", "Demolition"], "correct": 2, "re": "CF1R documents the design meets Title 24; CF2R is the installation certificate by the contractor; CF3R is the HERS rater verification - each at its stage.", "rr": "CF1R документирует соответствие проекта Title 24; CF2R - сертификат монтажа от подрядчика; CF3R - проверка HERS-оценщиком - каждая на своём этапе.", "qr": "В Title 24 (Калифорния) форму CF1R (Certificate of Compliance) обычно заполняют на этапе:", "optsr": ["Продажи дома", "Только финальной инспекции", "Проектирования/подачи на разрешение", "Сноса"]}, {"id": 420, "sec": "Principles & Load Calculations", "q": "The Noise Criteria (NC) level matters when selecting registers/diffusers because:", "opts": ["It sets refrigerant charge", "High air velocity through a register creates objectionable noise", "It changes the voltage", "It sizes the breaker"], "correct": 1, "re": "Registers/diffusers are selected so face velocity stays below the noise threshold for the space (bedrooms need a lower NC); oversizing airflow causes whistling.", "rr": "Решётки/диффузоры подбирают так, чтобы скорость на лицевой части была ниже порога шума для помещения (спальням нужен меньший NC); избыток расхода даёт свист.", "qr": "Уровень Noise Criteria (NC) важен при подборе решёток/диффузоров, потому что:", "optsr": ["Он задаёт заправку хладагентом", "Высокая скорость воздуха через решётку создаёт неприятный шум", "Меняет напряжение", "Подбирает автомат"]}, {"id": 421, "sec": "Principles & Load Calculations", "q": "In a humid climate, designing for better dehumidification often means selecting airflow toward the ___ end of the range:", "opts": ["Maximum possible", "Zero", "Higher (450 CFM/ton)", "Lower (about 350 CFM/ton)"], "correct": 3, "re": "Lower airflow per ton lowers the coil temperature and increases moisture removal (latent capacity), improving comfort in humid conditions.", "rr": "Меньший расход на тонну снижает температуру испарителя и усиливает удаление влаги (latent), повышая комфорт во влажных условиях.", "qr": "Во влажном климате для лучшего осушения часто выбирают расход ближе к ___ краю диапазона:", "optsr": ["Максимально возможному", "Нулю", "Верхнему (450 CFM/тонна)", "Нижнему (около 350 CFM/тонна)"]}, {"id": 422, "sec": "Principles & Load Calculations", "q": "Adding a contingency to a bid is intended to:", "opts": ["Guarantee a loss", "Replace the permit", "Cover unforeseen conditions and risk so the job stays profitable", "Lower the price below cost"], "correct": 2, "re": "A contingency allowance buffers against surprises (hidden conditions, price changes); it protects margin without relying on guesswork during the job.", "rr": "Резерв (contingency) защищает от сюрпризов (скрытые условия, рост цен); он сохраняет маржу без догадок по ходу работы.", "qr": "Добавление резерва (contingency) в заявку призвано:", "optsr": ["Гарантировать убыток", "Заменить разрешение", "Покрыть непредвиденные условия и риск, чтобы работа осталась прибыльной", "Снизить цену ниже себестоимости"]}, {"id": 423, "sec": "Principles & Load Calculations", "q": "Under California energy code, ducts in unconditioned spaces generally must be insulated to at least about:", "opts": ["R-8", "R-30", "No insulation", "R-2"], "correct": 0, "re": "Title 24 typically requires about R-8 duct insulation in unconditioned spaces (attics) to limit conductive losses; verify the current code value for the climate zone.", "rr": "Title 24 обычно требует около R-8 для дактов в неотапливаемых зонах (чердаках), чтобы ограничить теплопотери; сверьтесь с актуальным значением для климатической зоны.", "qr": "По энергокодексу Калифорнии воздуховоды в неотапливаемых зонах обычно должны быть утеплены минимум примерно до:", "optsr": ["R-8", "R-30", "Без утепления", "R-2"]}, {"id": 424, "sec": "Principles & Load Calculations", "q": "A 'block load' calculation differs from a room-by-room calculation in that it:", "opts": ["Ignores the climate", "Is only for gas", "Sizes each register", "Sizes the whole-building equipment but not individual room airflow"], "correct": 3, "re": "Block load gives the total equipment size; a room-by-room (Manual J detailed) is still needed to size ducts and distribute airflow to each room.", "rr": "Block load даёт общий размер оборудования; покомнатный (детальный Manual J) всё равно нужен для подбора дактов и распределения расхода по комнатам.", "qr": "Расчёт 'block load' отличается от покомнатного тем, что он:", "optsr": ["Игнорирует климат", "Только для газа", "Подбирает каждую решётку", "Подбирает оборудование на всё здание, но не расход по комнатам"]}, {"id": 425, "sec": "Principles & Load Calculations", "q": "Oversizing cooling equipment typically results in:", "opts": ["Short cycling, poor humidity control, and reduced comfort/efficiency", "Longer run times", "Better dehumidification", "Lower noise"], "correct": 0, "re": "Oversized AC satisfies the thermostat quickly (short cycles) before removing enough moisture, hurting comfort, efficiency, and equipment life - why Manual J/S sizing matters.", "rr": "Завышенный AC быстро удовлетворяет термостат (короткие циклы), не успев убрать влагу, что вредит комфорту, КПД и ресурсу - поэтому важен подбор по Manual J/S.", "qr": "Завышение охлаждающего оборудования обычно приводит к:", "optsr": ["Короткому циклированию, плохому контролю влажности и снижению комфорта/КПД", "Более длинным циклам работы", "Лучшему осушению", "Меньшему шуму"]}, {"id": 426, "sec": "Fabrication & Installation", "q": "Before flaring copper tubing, the end should be deburred/reamed so that:", "opts": ["The wall is thinner", "The flare forms evenly and seals without a leak path", "Brazing is faster", "The tube is shorter"], "correct": 1, "re": "Burrs cause an uneven flare and leak paths; deburr lightly (without removing much wall) so the flare seats evenly against the fitting.", "rr": "Заусенцы дают неровную раздачу и пути утечки; снимите заусенцы слегка (без съёма стенки), чтобы flare ровно сел на фитинг.", "qr": "Перед раздачей (flare) медной трубки торец нужно зачистить от заусенцев, чтобы:", "optsr": ["Стенка стала тоньше", "Раздача формировалась ровно и герметизировала без пути утечки", "Пайка шла быстрее", "Трубка стала короче"]}, {"id": 427, "sec": "Fabrication & Installation", "q": "Swaging two pieces of copper tubing allows the technician to:", "opts": ["Add refrigerant", "Bend without a tool", "Join them without a separate coupling (one end expanded over the other)", "Increase the SEER"], "correct": 2, "re": "A swage tool expands one tube end to slip over the matching tube, forming a brazed joint without buying a coupling.", "rr": "Инструмент для свагирования расширяет конец одной трубки, чтобы он наделся на ответную, образуя паяное соединение без покупки муфты.", "qr": "Свагирование (swaging) двух кусков медной трубки позволяет технику:", "optsr": ["Добавить хладагент", "Гнуть без инструмента", "Соединить их без отдельной муфты (один конец расширен поверх другого)", "Повысить SEER"]}, {"id": 428, "sec": "Fabrication & Installation", "q": "To bend soft copper tubing without kinking it, the technician should use:", "opts": ["His foot", "Pliers", "A hammer", "A tube bender (spring or lever) respecting the minimum radius"], "correct": 3, "re": "A tube bender supports the wall through the bend; kinks restrict flow and weaken the tube. Stay above the minimum bend radius.", "rr": "Трубогиб поддерживает стенку на изгибе; заломы сужают поток и ослабляют трубку. Соблюдайте минимальный радиус гиба.", "qr": "Чтобы согнуть мягкую медную трубку без залома, техник должен использовать:", "optsr": ["Ногу", "Плоскогубцы", "Молоток", "Трубогиб (пружинный или рычажный) с соблюдением минимального радиуса"]}, {"id": 429, "sec": "Fabrication & Installation", "q": "Press-type refrigerant fittings (e.g., RLS) are an alternative to brazing that:", "opts": ["Use solder", "Require an open flame", "Are only for water", "Form a permanent joint with a press tool and an O-ring, no flame"], "correct": 3, "re": "Press fittings make flameless refrigerant joints with a pressing tool - useful where a torch is hazardous; follow the listing and prep requirements.", "rr": "Press-фитинги делают беспламенные соединения хладагента прессовым инструментом - полезно там, где горелка опасна; соблюдайте листинг и требования подготовки.", "qr": "Press-фитинги для хладагента (например RLS) - это альтернатива пайке, которая:", "optsr": ["Использует припой", "Требует открытого огня", "Только для воды", "Создаёт постоянное соединение прессом и уплотнением, без огня"]}, {"id": 430, "sec": "Fabrication & Installation", "q": "A new gas-pipe connection is checked for leaks using:", "opts": ["Soap-bubble solution or an electronic gas detector", "Refrigerant", "An open flame", "Plain water"], "correct": 0, "re": "Never use a flame to find gas leaks. Apply leak-detection (soap) solution or use a combustible-gas detector with the line pressurized.", "rr": "Никогда не ищите утечки газа пламенем. Нанесите мыльный раствор или используйте детектор горючего газа при наддутой линии.", "qr": "Новое соединение газовой трубы проверяют на утечки с помощью:", "optsr": ["Мыльного раствора или электронного газового детектора", "Хладагента", "Открытого огня", "Простой воды"]}, {"id": 431, "sec": "Fabrication & Installation", "q": "After connecting a new gas line, air must be purged from the piping to:", "opts": ["Ensure the appliance gets pure gas and lights reliably", "Lower the voltage", "Increase static pressure", "Add refrigerant"], "correct": 0, "re": "Trapped air causes ignition problems and unsafe combustion; purge the line (safely, to outdoors) until gas is present before lighting the appliance.", "rr": "Запертый воздух вызывает проблемы розжига и небезопасное горение; стравите линию (безопасно, наружу), пока не пойдёт газ, до розжига прибора.", "qr": "После подключения новой газовой линии воздух нужно стравить из трубопровода, чтобы:", "optsr": ["Прибор получал чистый газ и надёжно зажигался", "Снизить напряжение", "Повысить статическое давление", "Добавить хладагент"]}, {"id": 432, "sec": "Fabrication & Installation", "q": "CSST (corrugated stainless-steel gas tubing) generally requires:", "opts": ["No grounding", "Refrigerant", "Painting", "Bonding to the grounding system (lightning protection)"], "correct": 3, "re": "Code requires CSST to be bonded to reduce the risk of lightning-induced arcing perforating the thin tubing; follow the manufacturer's bonding instructions.", "rr": "Нормы требуют bonding CSST для снижения риска дугообразования от молнии, прожигающего тонкую трубку; следуйте инструкции производителя по bonding.", "qr": "Гофрированная нержавеющая газовая трубка (CSST) обычно требует:", "optsr": ["Без заземления", "Хладагента", "Покраски", "Уравнивания с системой заземления (защита от молнии)"]}, {"id": 433, "sec": "Fabrication & Installation", "q": "A time-delay (dual-element) fuse is often used on motor circuits because it:", "opts": ["Trips instantly on any current", "Tolerates brief motor inrush current but protects against sustained overload", "Increases voltage", "Adds refrigerant"], "correct": 1, "re": "Motors draw high starting (inrush) current briefly; a time-delay fuse rides through that surge while still protecting against a real, sustained overcurrent.", "rr": "Двигатели кратко тянут большой пусковой ток; предохранитель с задержкой пропускает этот всплеск, но защищает от реальной длительной перегрузки.", "qr": "Предохранитель с задержкой (dual-element) часто ставят на двигательные цепи, потому что он:", "optsr": ["Срабатывает мгновенно на любой ток", "Терпит кратковременный пусковой ток, но защищает от длительной перегрузки", "Повышает напряжение", "Добавляет хладагент"]}, {"id": 434, "sec": "Fabrication & Installation", "q": "When terminating an aluminum conductor, the technician should:", "opts": ["Apply antioxidant compound and torque to the specified value", "Use it like copper with no prep", "Solder it", "Leave it loose"], "correct": 0, "re": "Aluminum oxidizes and creeps; use listed terminals, antioxidant paste where required, and torque to spec to prevent loose, overheating connections.", "rr": "Алюминий окисляется и 'течёт'; используйте листингованные клеммы, антиокислительную пасту где требуется и момент по спецификации, чтобы избежать слабых перегревающихся соединений.", "qr": "При оконцевании алюминиевого проводника техник должен:", "optsr": ["Нанести антиокислительный состав и затянуть на заданный момент", "Использовать как медь без подготовки", "Запаять", "Оставить слабым"]}, {"id": 435, "sec": "Fabrication & Installation", "q": "A 125 V receptacle installed outdoors or on a rooftop for service must be:", "opts": ["Removed in winter", "Unprotected", "GFCI-protected and in a weatherproof (in-use) cover", "240 V only"], "correct": 2, "re": "Outdoor/rooftop and other wet-location receptacles require GFCI protection and a weatherproof in-use cover for shock protection and weather resistance.", "rr": "Розетки снаружи/на крыше и в других влажных местах требуют GFCI-защиты и погодозащищённой крышки in-use для защиты от удара током и погоды.", "qr": "Розетка 125 В, установленная снаружи или на крыше для обслуживания, должна быть:", "optsr": ["Снята зимой", "Без защиты", "С GFCI-защитой и в погодозащищённой (in-use) крышке", "Только 240 В"]}, {"id": 436, "sec": "Fabrication & Installation", "q": "A control transformer with multiple primary taps (e.g., 208/240) is wired by:", "opts": ["Ignoring voltage", "Connecting the tap that matches the actual supply voltage", "Shorting all taps", "Using any tap"], "correct": 1, "re": "Match the primary tap to the measured supply (208 vs 240) so the secondary delivers proper 24 V; using the wrong tap gives high/low control voltage and faults.", "rr": "Подбирайте первичный отвод под измеренное питание (208 или 240), чтобы вторичка давала правильные 24 В; неверный отвод даёт высокое/низкое управляющее напряжение и сбои.", "qr": "Управляющий трансформатор с несколькими первичными отводами (например 208/240) подключают:", "optsr": ["Игнорируя напряжение", "Подключая отвод, соответствующий реальному напряжению питания", "Закоротив все отводы", "Используя любой отвод"]}, {"id": 437, "sec": "Fabrication & Installation", "q": "Class 2 low-voltage control wiring should generally be:", "opts": ["Separated from line-voltage conductors unless rated/divided per code", "Run in the same conduit as line voltage", "Spliced to line voltage", "Left energized to ground"], "correct": 0, "re": "Keep Class 2 (24 V) wiring separated from line-voltage conductors (or use barriers/rated cable) to avoid hazardous voltage transfer and interference.", "rr": "Держите проводку Class 2 (24 В) отдельно от сетевых проводников (или используйте барьеры/листингованный кабель), чтобы избежать опасного переноса напряжения и помех.", "qr": "Низковольтную управляющую проводку Class 2 обычно следует:", "optsr": ["Отделять от сетевых проводников, если нет рейтинга/разделения по нормам", "Прокладывать в одном кабель-канале с сетевым напряжением", "Сращивать с сетевым напряжением", "Оставлять под напряжением на землю"]}, {"id": 438, "sec": "Fabrication & Installation", "q": "Condensate that drains to a plumbing system must usually discharge through:", "opts": ["The refrigerant line", "A direct hard connection", "An indirect waste with an air gap", "The gas line"], "correct": 2, "re": "Codes require condensate to drain indirectly with an air gap to a suitable receptor, preventing sewer gas/back-siphonage into the equipment.", "rr": "Нормы требуют отводить конденсат непрямо, с воздушным разрывом к подходящему приёмнику, предотвращая канализационные газы/обратный сифон в оборудование.", "qr": "Конденсат, отводимый в канализацию, обычно должен сбрасываться через:", "optsr": ["Линию хладагента", "Прямое жёсткое подключение", "Непрямой слив с воздушным разрывом (air gap)", "Газовую линию"]}, {"id": 439, "sec": "Fabrication & Installation", "q": "A roof curb under a packaged rooftop unit (RTU) provides:", "opts": ["Extra voltage", "A level, weatherproof support that also connects supply/return ducts", "More SEER", "Refrigerant storage"], "correct": 1, "re": "The curb raises and supports the RTU, provides a weather seal, and aligns the supply/return duct openings - matching the curb to the unit is essential on changeouts.", "rr": "Curb поднимает и поддерживает RTU, даёт погодное уплотнение и совмещает проёмы подачи/обратки - подбор curb под блок критичен при заменах.", "qr": "Опорная рама (roof curb) под крышным моноблоком (RTU) обеспечивает:", "optsr": ["Дополнительное напряжение", "Ровную, погодозащищённую опору, также соединяющую подачу/обратку", "Больший SEER", "Хранение хладагента"]}, {"id": 440, "sec": "Fabrication & Installation", "q": "Where a refrigerant line set passes through an exterior wall, the penetration should be:", "opts": ["Filled with refrigerant", "Widened for airflow", "Sealed (and sleeved/protected) to keep out air, water, and pests and prevent chafing", "Left open"], "correct": 2, "re": "Seal and protect wall penetrations with a sleeve/grommet and approved sealant to stop air/water/pest intrusion and keep the tubing from abrading on the wall edge.", "rr": "Герметизируйте и защищайте проход через стену гильзой/втулкой и одобренным герметиком, чтобы не пускать воздух/воду/вредителей и чтобы трубка не истиралась о край стены.", "qr": "Там, где комплект линий хладагента проходит через наружную стену, проход должен быть:", "optsr": ["Заполнен хладагентом", "Расширен для воздуха", "Загерметизирован (и в гильзе/защите) от воздуха, воды и вредителей и от истирания", "Оставлен открытым"]}, {"id": 441, "sec": "Fabrication & Installation", "q": "When commissioning a ductless mini-split, the technician must evacuate the lines and indoor coil and then:", "opts": ["Open the service valves to release the factory charge into the system", "Leave the valves closed", "Add nitrogen", "Vent the charge"], "correct": 1, "re": "The outdoor unit ships pre-charged with valves closed; only after a proper vacuum does the tech open the service (stem) valves to release the charge into the evacuated lines/coil.", "rr": "Наружный блок поставляется заправленным с закрытыми вентилями; только после правильного вакуума техник открывает сервисные (штоковые) вентили, выпуская заряд в отвакуумированные линии/блок.", "qr": "При пусконаладке мини-сплита техник вакуумирует линии и внутренний блок, а затем:", "optsr": ["Открывает сервисные вентили, выпуская заводской заряд в систему", "Оставляет вентили закрытыми", "Добавляет азот", "Стравливает заряд"]}, {"id": 442, "sec": "Fabrication & Installation", "q": "The indoor head of a wall-mount mini-split must be installed so the condensate line:", "opts": ["Is sealed shut", "Connects to the gas line", "Maintains a continuous downward slope to drain by gravity", "Runs uphill"], "correct": 2, "re": "The condensate drain from the indoor head must slope continuously downward; a sag or uphill run causes water backup and leaks into the room.", "rr": "Дренаж конденсата от внутреннего блока должен идти непрерывно вниз; провис или подъём вызывают застой воды и протечки в комнату.", "qr": "Внутренний блок настенного мини-сплита монтируют так, чтобы линия конденсата:", "optsr": ["Была заглушена", "Подключалась к газовой линии", "Сохраняла непрерывный уклон вниз для самотёчного слива", "Шла вверх"]}, {"id": 443, "sec": "Fabrication & Installation", "q": "On a three-phase scroll compressor, verifying correct phase rotation at startup matters because:", "opts": ["It changes the color", "Reversed rotation makes a scroll run backward (loud, no pumping)", "It lowers voltage", "It adds refrigerant"], "correct": 1, "re": "A scroll runs in only one direction; if phased backward it is noisy, doesn't pump, and can be damaged. Swap two legs to correct rotation.", "rr": "Scroll работает только в одном направлении; при обратной фазировке он шумит, не качает и может повредиться. Поменяйте две фазы для исправления вращения.", "qr": "На трёхфазном scroll-компрессоре проверка правильного порядка фаз при запуске важна, потому что:", "optsr": ["Это меняет цвет", "Обратное вращение заставляет scroll работать задом наперёд (шум, нет перекачки)", "Снижает напряжение", "Это добавляет хладагент"]}, {"id": 444, "sec": "Fabrication & Installation", "q": "Subcooling is calculated by subtracting the measured liquid-line temperature from the:", "opts": ["Saturated condensing temperature (from liquid pressure)", "Suction temperature", "Outdoor air temperature", "Return-air temperature"], "correct": 0, "re": "Subcooling = saturated condensing temp (converted from liquid-line pressure via P-T) minus actual liquid-line temperature; it confirms charge on TXV systems.", "rr": "Subcooling = температура насыщенной конденсации (из давления жидкостной линии по P-T) минус фактическая температура жидкостной линии; подтверждает заправку на системах с TXV.", "qr": "Subcooling вычисляют, вычитая измеренную температуру жидкостной линии из:", "optsr": ["Температуры насыщенной конденсации (по давлению жидкости)", "Температуры всасывания", "Температуры наружного воздуха", "Температуры обратного воздуха"]}, {"id": 445, "sec": "Fabrication & Installation", "q": "After installing a unit with a crankcase heater, the heater should be energized before starting the compressor for about:", "opts": ["Several hours (often 24 h) to boil refrigerant out of the oil", "One minute", "No time", "One week"], "correct": 0, "re": "Energizing the crankcase heater for the recommended period (often ~24 h) drives liquid refrigerant out of the oil, preventing a flooded start and slugging.", "rr": "Включение подогрева картера на рекомендованный срок (часто ~24 ч) выгоняет жидкий хладагент из масла, предотвращая flooded start и гидроудар.", "qr": "После установки блока с подогревом картера нагреватель включают до запуска компрессора примерно на:", "optsr": ["Несколько часов (часто 24 ч), чтобы выпарить хладагент из масла", "Одну минуту", "Нисколько", "Одну неделю"]}, {"id": 446, "sec": "Fabrication & Installation", "q": "The temperature-rise method at furnace startup is used to:", "opts": ["Measure refrigerant", "Size the duct", "Set the gas type", "Verify airflow is within the rated rise range on the data plate"], "correct": 3, "re": "Measure return and supply air temperatures; the rise must fall within the nameplate range. Too high = low airflow; too low = high airflow - adjust blower speed.", "rr": "Измеряют температуры обратного и приточного воздуха; rise должен быть в диапазоне шильдика. Слишком высокий - малый расход; слишком низкий - большой; регулируйте скорость вентилятора.", "qr": "Метод temperature-rise при запуске печи применяют, чтобы:", "optsr": ["Измерить хладагент", "Подобрать дакт", "Задать тип газа", "Проверить, что расход в номинальном диапазоне rise на шильдике"]}, {"id": 447, "sec": "Fabrication & Installation", "q": "In an unconditioned attic, supply ducts should be insulated to the code R-value primarily to:", "opts": ["Reduce noise", "Add refrigerant", "Increase static pressure", "Limit conductive heat gain/loss between the air and the hot/cold attic"], "correct": 3, "re": "Attics swing hot and cold; insulating ducts (e.g., R-8 per Title 24) limits energy lost or gained through the duct walls, protecting capacity and efficiency.", "rr": "Чердаки то жаркие, то холодные; утепление дактов (например R-8 по Title 24) ограничивает энергию, теряемую/получаемую через стенки, сохраняя производительность и КПД.", "qr": "В неотапливаемом чердаке приточные дакты утепляют до нормативного R-value прежде всего чтобы:", "optsr": ["Снизить шум", "Добавить хладагент", "Повысить статическое давление", "Ограничить теплоприток/теплопотери между воздухом и жарким/холодным чердаком"]}, {"id": 448, "sec": "Fabrication & Installation", "q": "Supply boots and registers should be sealed to the drywall/floor opening to:", "opts": ["Increase the SEER", "Prevent air leakage into wall/floor cavities (lost conditioned air)", "Add refrigerant", "Lower the voltage"], "correct": 1, "re": "Unsealed boots leak conditioned air into cavities, wasting energy and reducing room airflow; seal the boot-to-opening connection with mastic/gasket.", "rr": "Негерметичные башмаки пропускают кондиционированный воздух в полости, теряя энергию и снижая расход в комнату; герметизируйте стык башмак-проём мастикой/уплотнением.", "qr": "Приточные башмаки (boots) и решётки герметизируют к проёму в гипсокартоне/полу, чтобы:", "optsr": ["Повысить SEER", "Предотвратить утечку воздуха в полости стен/пола (потеря кондиционированного воздуха)", "Добавить хладагент", "Снизить напряжение"]}, {"id": 449, "sec": "Fabrication & Installation", "q": "A direct-vent (sealed-combustion) furnace draws combustion air from outdoors through:", "opts": ["A dedicated intake pipe, exhausting through a separate/concentric vent", "The refrigerant line", "Room air only", "The return duct"], "correct": 0, "re": "Sealed-combustion units pipe outdoor air directly to the burner and vent flue gases outside (often a concentric pipe), isolating combustion from indoor air.", "rr": "Sealed-combustion блоки подводят наружный воздух прямо к горелке и отводят дымовые газы наружу (часто коаксиальная труба), изолируя горение от воздуха помещения.", "qr": "Печь с прямым дымоудалением (sealed-combustion) берёт воздух горения снаружи через:", "optsr": ["Выделенную приточную трубу, с отводом через отдельный/коаксиальный дымоход", "Линию хладагента", "Только воздух помещения", "Обратный дакт"]}, {"id": 450, "sec": "Fabrication & Installation", "q": "When a high-efficiency furnace replaces an older one that shared a chimney with a water heater, the technician must verify the water heater's vent because:", "opts": ["The 'orphaned' water heater may be oversized for the chimney and backdraft", "It needs refrigerant", "The gas type changed", "It now has more draft"], "correct": 0, "re": "Removing the furnace from a shared (common) vent can leave the water heater 'orphaned' in an oversized chimney, risking poor draft/backdrafting - re-evaluate venting per code.", "rr": "Удаление печи из общего дымохода оставляет водонагреватель 'осиротевшим' в слишком большом дымоходе, рискуя плохой тягой/обратной тягой - пересчитайте дымоудаление по нормам.", "qr": "Когда высокоэффективная печь заменяет старую, делившую дымоход с водонагревателем, техник обязан проверить дымоудаление водонагревателя, потому что:", "optsr": ["'Осиротевший' водонагреватель может оказаться мал для дымохода и давать обратную тягу", "Ему нужен хладагент", "Сменился тип газа", "Теперь у него больше тяги"]}, {"id": 451, "sec": "Fabrication & Installation", "q": "On a new installation, the condensate trap should be primed (filled with water) so that:", "opts": ["The compressor starts", "The trap seals immediately and air is not pulled through the empty drain", "The SEER rises", "The gas lights"], "correct": 1, "re": "A dry trap lets the blower pull air through the drain (or block drainage); priming the trap establishes the water seal so condensate flows correctly at startup.", "rr": "Сухой сифон даёт вентилятору подсасывать воздух через дренаж (или блокирует слив); заливка сифона создаёт водяной затвор, и конденсат течёт правильно при запуске.", "qr": "На новом монтаже сифон конденсата нужно залить водой (prime), чтобы:", "optsr": ["Запустился компрессор", "Сифон сразу герметизировал и воздух не подсасывался через пустой дренаж", "Вырос SEER", "Зажёгся газ"]}, {"id": 452, "sec": "Fabrication & Installation", "q": "In California, HVAC equipment and water heaters often require seismic strapping/anchorage to:", "opts": ["Improve airflow", "Raise the voltage", "Prevent the unit from shifting or toppling during an earthquake", "Add refrigerant"], "correct": 2, "re": "Seismic anchorage (strapping water heaters, securing rooftop/attic units) keeps equipment in place during a quake, preventing gas-line/refrigerant-line damage and hazards.", "rr": "Сейсмическая анкеровка (стяжка водонагревателей, крепление крышных/чердачных блоков) удерживает оборудование на месте при толчках, предотвращая повреждение газовых/хладагентных линий и опасности.", "qr": "В Калифорнии HVAC-оборудование и водонагреватели часто требуют сейсмического крепления/анкеровки, чтобы:", "optsr": ["Улучшить расход воздуха", "Поднять напряжение", "Не дать блоку сдвинуться или опрокинуться при землетрясении", "Добавить хладагент"]}, {"id": 453, "sec": "Fabrication & Installation", "q": "At installation, electrical lugs and terminals should be tightened to:", "opts": ["As tight as possible", "No particular value", "Hand-tight only", "The manufacturer's specified torque value"], "correct": 3, "re": "Both under- and over-torquing cause problems; use a torque screwdriver/wrench to the specified value for low-resistance, reliable connections that won't loosen or overheat.", "rr": "И недотяжка, и перетяжка вредны; используйте динамометрическую отвёртку/ключ на заданный момент для надёжных соединений с малым сопротивлением, которые не ослабнут и не перегреются.", "qr": "При монтаже электрические наконечники и клеммы следует затягивать до:", "optsr": ["Максимально туго", "Без конкретного значения", "Только от руки", "Заданного производителем момента затяжки"]}, {"id": 454, "sec": "Fabrication & Installation", "q": "Circuit breakers and disconnects serving HVAC equipment should be:", "opts": ["Bypassed", "Clearly labeled to identify the equipment they serve", "Left unlabeled", "Painted over"], "correct": 1, "re": "Proper labeling lets technicians and occupants quickly identify and de-energize the right circuit for service and emergencies, improving safety.", "rr": "Правильная маркировка позволяет техникам и жильцам быстро найти и обесточить нужную цепь при обслуживании и в аварии, повышая безопасность.", "qr": "Автоматы и разъединители, питающие HVAC-оборудование, должны быть:", "optsr": ["Зашунтированы", "Чётко промаркированы с указанием обслуживаемого оборудования", "Без подписи", "Закрашены"]}, {"id": 455, "sec": "TR", "q": "A three-phase scroll compressor that is loud and produces little or no cooling right after a service may be:", "opts": ["Low on oil", "Wired for reverse rotation (two phases swapped)", "Overcharged", "Out of filters"], "correct": 1, "re": "Reversed phase rotation makes a scroll spin backward - noisy, no pumping, and no cooling. Swapping any two line phases restores correct rotation.", "rr": "Обратный порядок фаз заставляет scroll крутиться назад - шум, нет перекачки и охлаждения. Перестановка любых двух фаз восстанавливает правильное вращение.", "qr": "Трёхфазный scroll-компрессор, который шумит и почти не охлаждает сразу после обслуживания, может быть:", "optsr": ["Без масла", "Подключён на обратное вращение (поменяны две фазы)", "Перезаправлен", "Без фильтров"]}, {"id": 456, "sec": "TR", "q": "A moisture-indicating sight glass that has turned yellow (instead of green) indicates:", "opts": ["Moisture in the system (replace the drier and evacuate)", "Correct charge", "High voltage", "Overcharge"], "correct": 0, "re": "The indicator changes color with moisture content (green = dry, yellow = wet). A wet reading calls for a new filter drier and proper evacuation.", "rr": "Индикатор меняет цвет по содержанию влаги (зелёный = сухо, жёлтый = влажно). Влажный показатель требует нового фильтра-осушителя и правильного вакуума.", "qr": "Смотровое стекло с индикатором влаги, ставшее жёлтым (вместо зелёного), указывает на:", "optsr": ["Влагу в системе (заменить осушитель и отвакуумировать)", "Правильную заправку", "Высокое напряжение", "Перезаправку"]}, {"id": 457, "sec": "TR", "q": "An abnormally high compressor discharge temperature is commonly caused by:", "opts": ["Low voltage only", "A high compression ratio (low suction/high head), low charge, or high superheat", "Overcharge only", "A clean filter"], "correct": 1, "re": "High discharge temp results from a high compression ratio and high return-gas superheat (often from undercharge or restriction); excessive heat breaks down oil and damages valves.", "rr": "Высокая температура нагнетания - от высокой степени сжатия и высокого superheat обратного газа (часто недозаправка или засор); избыток тепла разлагает масло и повреждает клапаны.", "qr": "Аномально высокая температура нагнетания компрессора обычно вызвана:", "optsr": ["Только низким напряжением", "Высокой степенью сжатия (низкое всасывание/высокое нагнетание), недозаправкой или высоким superheat", "Только перезаправкой", "Чистым фильтром"]}, {"id": 458, "sec": "TR", "q": "An oil acid test that reads positive after a compressor failure means the technician should:", "opts": ["Just recharge", "Perform a burnout cleanup (acid driers) until the system tests clean", "Ignore it", "Add more oil"], "correct": 1, "re": "Acidic oil indicates contamination from a burnout; install suction/liquid acid-removal driers, run, retest, and replace driers until the acid test is clean.", "rr": "Кислое масло указывает на загрязнение от выгорания; ставьте кислотные осушители на всасывание/жидкостную, гоняйте, перепроверяйте и меняйте, пока кислотный тест не чист.", "qr": "Положительный кислотный тест масла после отказа компрессора означает, что техник должен:", "optsr": ["Просто дозаправить", "Провести очистку после burnout (кислотные осушители), пока система не станет чистой", "Игнорировать", "Долить масла"]}, {"id": 459, "sec": "TR", "q": "A gas furnace pressure switch that will not close after the inducer starts is often caused by:", "opts": ["Too much airflow", "High refrigerant", "A blocked vent or a pressure-switch hose plugged with condensate", "A clean filter"], "correct": 2, "re": "The switch proves inducer draft; a blocked flue, cracked/plugged hose, or condensate in the port keeps it open, halting ignition for safety.", "rr": "Реле подтверждает тягу inducer; засор дымохода, треснувший/забитый шланг или конденсат в штуцере держат его разомкнутым, останавливая розжиг ради безопасности.", "qr": "Реле давления газовой печи, которое не замыкается после запуска inducer, часто вызвано:", "optsr": ["Слишком большим расходом", "Избытком хладагента", "Засором дымохода или шлангом реле, забитым конденсатом", "Чистым фильтром"]}, {"id": 460, "sec": "TR", "q": "A reversing valve with an internal (bypass) leak will cause:", "opts": ["Poor heating/cooling with suction and discharge pressures closer than normal", "Low voltage", "Perfect operation", "A blown fuse"], "correct": 0, "re": "An internally leaking reversing valve bleeds hot discharge gas to the suction side, equalizing pressures and reducing capacity even though the solenoid works.", "rr": "Внутренне текущий реверс-клапан перепускает горячий газ нагнетания на сторону всасывания, выравнивая давления и снижая производительность, хотя соленоид исправен.", "qr": "Реверс-клапан с внутренней (перепускной) утечкой вызывает:", "optsr": ["Плохой нагрев/охлаждение, давления всасывания и нагнетания ближе нормы", "Низкое напряжение", "Идеальную работу", "Перегорание предохранителя"]}, {"id": 461, "sec": "TR", "q": "A suction-line accumulator protects the compressor by:", "opts": ["Filtering air", "Trapping liquid refrigerant and metering it back as vapor (preventing slugging)", "Adding refrigerant", "Raising head pressure"], "correct": 1, "re": "The accumulator (common on heat pumps) holds liquid that returns during heating/defrost and feeds it back slowly so the compressor isn't slugged with liquid.", "rr": "Accumulator (часто на тепловых насосах) удерживает жидкость, возвращающуюся при нагреве/разморозке, и медленно подаёт её, чтобы компрессор не получал гидроудар.", "qr": "Накопитель (accumulator) на всасывающей линии защищает компрессор тем, что:", "optsr": ["Фильтрует воздух", "Удерживает жидкий хладагент и дозирует его обратно паром (предотвращая гидроудар)", "Добавляет хладагент", "Поднимает давление нагнетания"]}, {"id": 462, "sec": "TR", "q": "A bi-flow filter drier or a check valve installed backward in a heat pump will:", "opts": ["Restrict flow in one mode, causing poor performance in heating or cooling", "Add refrigerant", "Improve efficiency", "Lower the discharge temp"], "correct": 0, "re": "Heat pumps reverse flow; a directional drier/check valve installed wrong restricts one mode. Use a bi-flow drier or correct the arrow direction.", "rr": "Тепловые насосы реверсируют поток; направленный осушитель/обратный клапан наоборот ограничивает один режим. Ставьте bi-flow осушитель или верное направление стрелки.", "qr": "Bi-flow фильтр-осушитель или обратный клапан, установленный наоборот в тепловом насосе:", "optsr": ["Ограничит поток в одном режиме, ухудшив нагрев или охлаждение", "Добавит хладагент", "Улучшит эффективность", "Снизит температуру нагнетания"]}, {"id": 463, "sec": "TR", "q": "A plugged TXV external equalizer line will typically cause the valve to:", "opts": ["Increase subcooling only", "Add refrigerant", "Control poorly, usually starving the evaporator (high superheat)", "Overfeed badly"], "correct": 2, "re": "The external equalizer senses evaporator outlet pressure; if plugged, the TXV misreads and commonly underfeeds, producing high superheat and low capacity.", "rr": "Внешний эквалайзер измеряет давление на выходе испарителя; при засоре TXV ошибается и обычно недоподаёт, давая высокий superheat и низкую производительность.", "qr": "Забитая линия внешнего эквалайзера TXV обычно заставляет клапан:", "optsr": ["Только увеличивать subcooling", "Добавлять хладагент", "Плохо регулировать, обычно обедняя испаритель (высокий superheat)", "Сильно переподавать"]}, {"id": 464, "sec": "TR", "q": "A frequently overlooked cause of low airflow on a maintenance call is:", "opts": ["A dirty blower wheel packed with debris", "A clean coil", "High voltage", "Overcharge"], "correct": 0, "re": "Dirt loads the blower wheel blades, drastically cutting airflow even with a clean filter; inspect and clean the wheel as part of airflow troubleshooting.", "rr": "Грязь облепляет лопасти колеса вентилятора, резко срезая расход даже при чистом фильтре; осматривайте и чистите колесо при диагностике расхода.", "qr": "Часто упускаемая причина низкого расхода воздуха при ТО - это:", "optsr": ["Грязное колесо вентилятора, забитое мусором", "Чистый испаритель", "Высокое напряжение", "Перезаправка"]}, {"id": 465, "sec": "TR", "q": "In cooling, a dirty evaporator (air side) and a dirty condenser produce different symptoms: a dirty evaporator most directly reduces:", "opts": ["Airflow and evaporator capacity (low suction, possible icing)", "Head pressure", "Voltage", "Subcooling only"], "correct": 0, "re": "A dirty evaporator restricts airflow, lowering suction pressure and risking ice; a dirty condenser raises head pressure. Reading both pressures locates the fault.", "rr": "Грязный испаритель ограничивает расход, снижая давление всасывания и риск льда; грязный конденсатор поднимает давление нагнетания. Чтение обоих давлений локализует неисправность.", "qr": "В охлаждении грязный испаритель (со стороны воздуха) и грязный конденсатор дают разные симптомы: грязный испаритель напрямую снижает:", "optsr": ["Расход воздуха и производительность испарителя (низкое всасывание, риск обмерзания)", "Давление нагнетания", "Напряжение", "Только subcooling"]}, {"id": 466, "sec": "TR", "q": "On a pump-down system, a liquid-line solenoid valve that fails to close will cause:", "opts": ["High SEER", "Normal pump down", "The system to fail to pump down (refrigerant keeps flowing to the low side)", "A blown fuse"], "correct": 2, "re": "Pump-down relies on the solenoid closing so the compressor evacuates the low side into the condenser/receiver; a stuck-open valve defeats pump-down.", "rr": "Pump-down зависит от закрытия соленоида, чтобы компрессор откачал низкую сторону в конденсатор/ресивер; зависший открытым клапан срывает pump-down.", "qr": "В системе с pump-down соленоидный клапан жидкостной линии, не закрывающийся, вызовет:", "optsr": ["Высокий SEER", "Нормальный pump down", "Невозможность откачать систему (хладагент продолжает идти на низкую сторону)", "Перегорание предохранителя"]}, {"id": 467, "sec": "TR", "q": "A defrost-termination sensor that fails can cause a heat pump to:", "opts": ["Increase subcooling", "Stop the compressor permanently", "Never defrost or stay in defrost too long", "Run more efficiently"], "correct": 3, "re": "The termination sensor ends defrost at the right coil temperature; if it fails, the unit may not clear ice or may waste energy over-defrosting - check the sensor/board.", "rr": "Датчик завершения прекращает defrost при нужной температуре змеевика; при отказе блок может не очищать лёд или перерасходовать энергию на пере-разморозку - проверьте датчик/плату.", "qr": "Отказ датчика завершения разморозки может заставить тепловой насос:", "optsr": ["Увеличить subcooling", "Навсегда остановить компрессор", "Никогда не размораживаться или слишком долго быть в defrost", "Работать эффективнее"]}, {"id": 468, "sec": "TR", "q": "A hard-start kit using a potential (start) relay drops the start capacitor out of the circuit based on:", "opts": ["Refrigerant pressure", "Time only", "The back-EMF voltage as the motor nears running speed", "Outdoor temperature"], "correct": 2, "re": "A potential relay senses the rising back-EMF (start-winding voltage) and opens to remove the start cap once the motor is up to speed; a bad relay leaves the cap in or out wrongly.", "rr": "Потенциальное реле улавливает растущую противо-ЭДС (напряжение пусковой обмотки) и размыкается, убирая пусковой конденсатор при выходе мотора на скорость; неисправное реле оставляет конденсатор неверно.", "qr": "Hard-start комплект с потенциальным (пусковым) реле выводит пусковой конденсатор из цепи на основе:", "optsr": ["Давления хладагента", "Только времени", "Напряжения противо-ЭДС, когда мотор приближается к рабочей скорости", "Наружной температуры"]}, {"id": 469, "sec": "TR", "q": "A TXV sensing bulb that is loose or poorly insulated from the suction line tends to make the valve:", "opts": ["Close completely", "Overfeed the evaporator (it senses warm air instead of true line temperature)", "Have no effect", "Starve the evaporator"], "correct": 1, "re": "A bulb reading ambient air instead of the colder suction line senses a false high temperature and overfeeds, lowering superheat and risking floodback; mount and insulate the bulb properly.", "rr": "Колба, читающая окружающий воздух вместо более холодной всасывающей линии, чувствует ложно высокую температуру и переподаёт, снижая superheat и рискуя floodback; крепите и изолируйте колбу правильно.", "qr": "Колба-сенсор TXV, слабо закреплённая или плохо изолированная от всасывающей линии, обычно заставляет клапан:", "optsr": ["Полностью закрыться", "Переподавать в испаритель (чувствует тёплый воздух вместо реальной температуры линии)", "Не влиять", "Обеднять испаритель"]}, {"id": 470, "sec": "TR", "q": "A weak condenser-fan capacitor will cause the fan to:", "opts": ["Lower the SEER only", "Run slow or stall and overheat, raising head pressure", "Add refrigerant", "Spin faster"], "correct": 1, "re": "The fan motor needs its rated capacitor for torque; a weak cap makes it run slow/hot or fail to start, cutting condenser airflow and raising head pressure.", "rr": "Мотору вентилятора нужен номинальный конденсатор для момента; слабый даёт медленную/горячую работу или незапуск, срезая обдув конденсатора и поднимая давление нагнетания.", "qr": "Слабый конденсатор вентилятора конденсатора заставит вентилятор:", "optsr": ["Только снизить SEER", "Работать медленно или встать и перегреться, подняв давление нагнетания", "Добавить хладагент", "Крутиться быстрее"]}, {"id": 471, "sec": "TR", "q": "A hissing or 'gurgling' sound at the TXV often indicates:", "opts": ["Correct charge", "Flash gas at the valve from undercharge or a liquid-line restriction", "Overcharge", "High voltage"], "correct": 1, "re": "Vapor (flash gas) entering the TXV instead of solid liquid makes a hissing/gurgling noise and reduces capacity - check for undercharge or a restriction upstream.", "rr": "Пар (flash gas), входящий в TXV вместо сплошной жидкости, даёт шипение/бульканье и снижает производительность - проверьте недозаправку или засор выше по течению.", "qr": "Шипящий или 'булькающий' звук у TXV часто указывает на:", "optsr": ["Правильную заправку", "Flash gas у клапана из-за недозаправки или засора жидкостной линии", "Перезаправку", "Высокое напряжение"]}, {"id": 472, "sec": "TR", "q": "High compressor amp draw together with high head pressure most likely points to:", "opts": ["Undercharge", "Low voltage", "A dirty filter", "Overcharge or a condenser problem (dirty coil/failed fan)"], "correct": 3, "re": "High head makes the compressor work harder (high amps); causes include overcharge, dirty condenser, failed condenser fan, or non-condensables - verify before correcting.", "rr": "Высокое нагнетание заставляет компрессор работать тяжелее (высокий ток); причины - перезаправка, грязный конденсатор, отказ вентилятора или неконденсируемые - проверьте до правки.", "qr": "Высокий ток компрессора вместе с высоким давлением нагнетания скорее всего указывает на:", "optsr": ["Недозаправку", "Низкое напряжение", "Грязный фильтр", "Перезаправку или проблему конденсатора (грязь/отказ вентилятора)"]}, {"id": 473, "sec": "TR", "q": "Reducing indoor airflow in cooling (e.g., a closed-up duct) will tend to:", "opts": ["Raise the voltage", "Lower suction pressure and evaporator temperature, risking coil freeze", "Have no effect", "Raise suction pressure"], "correct": 1, "re": "Less airflow over the coil drops evaporator pressure/temperature; left unchecked it freezes the coil. Restore airflow before assuming a refrigerant fault.", "rr": "Меньший обдув испарителя снижает давление/температуру испарителя; без устранения он обмерзает. Восстановите расход до выводов о хладагенте.", "qr": "Снижение внутреннего расхода воздуха в охлаждении (например пережатый дакт) обычно:", "optsr": ["Повышает напряжение", "Снижает давление всасывания и температуру испарителя, рискуя обмерзанием", "Не влияет", "Повышает давление всасывания"]}, {"id": 474, "sec": "TR", "q": "On older thermostats, the heat anticipator setting that is too low causes:", "opts": ["Longer burner cycles and possible overshoot of the set temperature", "Refrigerant loss", "Higher SEER", "No cycling"], "correct": 0, "re": "The anticipator tunes cycle length; set too low it lengthens cycles and overshoots, too high it short-cycles. Modern thermostats use electronic cycle-rate settings instead.", "rr": "Anticipator настраивает длину цикла; слишком низко - длинные циклы и перегрев, слишком высоко - короткие циклы. Современные термостаты вместо этого используют электронную настройку cycle-rate.", "qr": "На старых термостатах слишком низкая уставка heat anticipator вызывает:", "optsr": ["Более длинные циклы горелки и возможный перегрев сверх уставки", "Потерю хладагента", "Более высокий SEER", "Отсутствие циклирования"]}, {"id": 475, "sec": "TR", "q": "A compressor that runs, then trips and restarts only after cooling down for a while, likely has:", "opts": ["A bad duct", "A clean filter", "An internal overload opening on heat (often from high amps/temperature)", "A wrong thermostat"], "correct": 2, "re": "The internal overload protects the motor by opening when too hot and resetting when cool; recurring trips signal high current/heat - investigate charge, airflow, voltage, capacitor.", "rr": "Внутренняя защита бережёт мотор, размыкаясь при перегреве и сбрасываясь при остывании; повторные срабатывания - сигнал высокого тока/нагрева; проверьте заряд, расход, напряжение, конденсатор.", "qr": "Компрессор, который работает, затем выключается и перезапускается лишь остыв, вероятно имеет:", "optsr": ["Плохой дакт", "Чистый фильтр", "Срабатывающую по нагреву внутреннюю защиту (часто от высокого тока/температуры)", "Неверный термостат"]}, {"id": 476, "sec": "TR", "q": "A run capacitor that is visibly bulged or leaking should be:", "opts": ["Reused", "Filed flat", "Replaced with one of the same uF and equal-or-higher voltage rating", "Filled with oil"], "correct": 2, "re": "A bulged/leaking capacitor has failed; replace it with the exact microfarad rating and the same or higher voltage rating - never a lower voltage rating.", "rr": "Вздутый/текущий конденсатор отказал; замените на точный номинал микрофарад и то же или большее напряжение - никогда не меньше.", "qr": "Рабочий конденсатор с видимым вздутием или течью следует:", "optsr": ["Использовать повторно", "Подпилить", "Заменить на такой же uF и равным-или-выше напряжением", "Залить маслом"]}, {"id": 477, "sec": "TR", "q": "Pitted, high-resistance contactor contacts can cause a compressor to receive:", "opts": ["Low voltage (voltage drop) and heat, leading to hard starts or failure", "More refrigerant", "Higher SEER", "Cleaner air"], "correct": 0, "re": "Worn contacts add resistance and voltage drop, starving the compressor of voltage and generating heat; replace the contactor rather than filing the contacts.", "rr": "Изношенные контакты добавляют сопротивление и падение напряжения, лишая компрессор напряжения и создавая нагрев; меняйте контактор, а не опиливайте контакты.", "qr": "Изъеденные контакты контактора с высоким сопротивлением могут давать компрессору:", "optsr": ["Низкое напряжение (падение напряжения) и нагрев, ведущие к тяжёлым пускам или отказу", "Больше хладагента", "Более высокий SEER", "Более чистый воздух"]}, {"id": 478, "sec": "TR", "q": "The most logical no-cooling diagnostic sequence is to verify:", "opts": ["Only the filter", "Only the thermostat", "Refrigerant first, always", "Power/disconnect, then 24 V control to the contactor, then the compressor and finally the refrigerant circuit"], "correct": 3, "re": "Work the circuit in order: confirm line power and disconnect, then the 24 V control signal, then contactor/compressor operation, and only then evaluate refrigerant pressures.", "rr": "Идите по цепи по порядку: подтвердите сетевое питание и разъединитель, затем сигнал 24 В, затем работу контактора/компрессора и лишь потом давления хладагента.", "qr": "Самая логичная последовательность диагностики отсутствия охлаждения - проверять:", "optsr": ["Только фильтр", "Только термостат", "Сначала всегда хладагент", "Питание/разъединитель, затем 24 В на контактор, затем компрессор и лишь потом контур хладагента"]}, {"id": 479, "sec": "Safety & Field Practices", "q": "When working on a system charged with an A2L (mildly flammable) refrigerant, the technician should:", "opts": ["Use any open flame nearby", "Eliminate ignition sources, ventilate, and use tools/practices rated for flammable refrigerant", "Vent it indoors", "Smoke while working"], "correct": 1, "re": "A2L refrigerants can ignite at high concentration; remove ignition sources, ventilate the area, use a listed leak detector, and follow the equipment's A2L service procedures.", "rr": "A2L могут воспламениться при высокой концентрации; уберите источники искр, проветрите зону, используйте листингованный течеискатель и соблюдайте сервисные процедуры A2L для оборудования.", "qr": "При работе с системой на хладагенте A2L (слабогорючем) техник должен:", "optsr": ["Использовать рядом открытый огонь", "Устранить источники возгорания, проветрить и применять инструмент/практики под горючий хладагент", "Стравить его в помещении", "Курить во время работы"]}, {"id": 480, "sec": "Safety & Field Practices", "q": "For A2L refrigerants, the maximum allowable charge in a space is limited based on:", "opts": ["The SEER", "The duct color", "The wire size", "The room floor area (to keep any leak below the flammable concentration)"], "correct": 3, "re": "Standards (e.g., UL 60335-2-40) cap charge by room area so that a full leak cannot reach a flammable concentration; larger charges require larger rooms or mitigation.", "rr": "Стандарты (например UL 60335-2-40) ограничивают заряд по площади помещения, чтобы полная утечка не достигла горючей концентрации; больший заряд требует большего помещения или мер защиты.", "qr": "Для хладагентов A2L максимально допустимый заряд в помещении ограничивается на основе:", "optsr": ["SEER", "Цвета дакта", "Сечения провода", "Площади пола помещения (чтобы любая утечка осталась ниже горючей концентрации)"]}, {"id": 481, "sec": "Safety & Field Practices", "q": "Detecting a leak in a flammable (A2L) refrigerant system requires:", "opts": ["A leak detector listed/rated for flammable refrigerants", "Your nose only", "Spraying water", "A lit match"], "correct": 0, "re": "Use only a leak detector approved for flammable refrigerants; an ignition source like a halide torch or flame is dangerous with A2L systems.", "rr": "Используйте только течеискатель, одобренный для горючих хладагентов; источник возгорания вроде галоидной горелки или пламени опасен с системами A2L.", "qr": "Обнаружение утечки в системе с горючим (A2L) хладагентом требует:", "optsr": ["Течеискателя, листингованного/рассчитанного на горючие хладагенты", "Только носа", "Распыления воды", "Зажжённой спички"]}, {"id": 482, "sec": "Safety & Field Practices", "q": "Before connecting to a refrigerant cylinder, the technician should confirm the refrigerant type by:", "opts": ["Its temperature", "The label and color code, to avoid mixing incompatible refrigerants", "The cylinder's weight", "Shaking it"], "correct": 1, "re": "Cylinders are labeled and color-coded; mixing refrigerants ruins the charge and the recovered refrigerant. Always verify the label before connecting.", "rr": "Баллоны имеют этикетку и цветовой код; смешивание хладагентов портит заряд и откачанный хладагент. Всегда проверяйте этикетку перед подключением.", "qr": "Перед подключением к баллону с хладагентом техник должен подтвердить тип хладагента по:", "optsr": ["Его температуре", "Этикетке и цветовому коду, чтобы не смешать несовместимые хладагенты", "Весу баллона", "Встряхиванию"]}, {"id": 483, "sec": "Safety & Field Practices", "q": "Acetylene used for brazing must never be used above a working pressure of about:", "opts": ["5 psig", "250 psig", "100 psig", "15 psig"], "correct": 3, "re": "Acetylene is unstable above ~15 psig and can decompose explosively; never set the regulator higher. Use proper oxy-acetylene safety practices.", "rr": "Ацетилен нестабилен выше ~15 psig и может взрывоопасно разлагаться; не выставляйте редуктор выше. Соблюдайте правила безопасности oxy-acetylene.", "qr": "Ацетилен для пайки нельзя использовать при рабочем давлении выше примерно:", "optsr": ["5 psig", "250 psig", "100 psig", "15 psig"]}, {"id": 484, "sec": "Safety & Field Practices", "q": "Flashback arrestors on an oxy-fuel torch set are installed to:", "opts": ["Prevent a flame from traveling back into the hoses/cylinders", "Save gas", "Increase flame size", "Add refrigerant"], "correct": 0, "re": "Flashback arrestors/check valves stop a flame or reverse gas flow from reaching the hoses and cylinders, preventing a dangerous explosion.", "rr": "Огнепреградители/обратные клапаны не дают пламени или обратному потоку газа дойти до шлангов и баллонов, предотвращая опасный взрыв.", "qr": "Обратные клапаны/огнепреградители (flashback arrestors) на oxy-fuel горелке ставят, чтобы:", "optsr": ["Не дать пламени уйти обратно в шланги/баллоны", "Сэкономить газ", "Увеличить пламя", "Добавить хладагент"]}, {"id": 485, "sec": "Safety & Field Practices", "q": "Acetylene cylinders should be stored and used:", "opts": ["On their side", "Horizontally in the sun", "Upright (the acetone inside requires it) and secured", "Upside down"], "correct": 2, "re": "Acetylene is dissolved in acetone inside the cylinder; storing/using it upright keeps the acetone from being drawn into the hose. Secure cylinders from tipping.", "rr": "Ацетилен растворён в ацетоне внутри баллона; вертикальное хранение/использование не даёт ацетону уйти в шланг. Крепите баллоны от опрокидывания.", "qr": "Ацетиленовые баллоны следует хранить и использовать:", "optsr": ["На боку", "Горизонтально на солнце", "Вертикально (ацетон внутри этого требует) и закреплёнными", "Вверх дном"]}, {"id": 486, "sec": "Safety & Field Practices", "q": "A brazing/oxy-fuel torch should be lit using:", "opts": ["An open candle", "A cigarette lighter", "A striker (spark lighter), not matches or a lighter", "Another torch"], "correct": 2, "re": "Use a friction striker to keep hands away from the igniting flame; matches/lighters put fingers at the torch tip and risk burns.", "rr": "Используйте искровой запальник, чтобы держать руки вдали от вспыхивающего пламени; спички/зажигалки подводят пальцы к соплу и грозят ожогами.", "qr": "Горелку для пайки/oxy-fuel следует зажигать с помощью:", "optsr": ["Открытой свечи", "Зажигалки", "Кремнёвого искрового запальника (striker), а не спичек или зажигалки", "Другой горелки"]}, {"id": 487, "sec": "Safety & Field Practices", "q": "After completing hot work near combustibles, a fire watch should continue for at least about:", "opts": ["No time", "5 seconds", "30 minutes (to catch smoldering ignition)", "1 week"], "correct": 2, "re": "Smoldering can ignite minutes after brazing/cutting; maintain a fire watch for at least 30 minutes (longer if conditions warrant) and keep an extinguisher ready.", "rr": "Тление может вспыхнуть через минуты после пайки/резки; ведите пожарный надзор минимум 30 минут (дольше при необходимости) и держите огнетушитель наготове.", "qr": "После завершения огневых работ рядом с горючим пожарный надзор должен продолжаться минимум примерно:", "optsr": ["Нисколько", "5 секунд", "30 минут (чтобы поймать тлеющее возгорание)", "1 неделю"]}, {"id": 488, "sec": "Safety & Field Practices", "q": "When carrying ladders or working with equipment near overhead power lines (under 50 kV), maintain a minimum clearance of at least:", "opts": ["2 inches", "1 foot", "10 feet", "No clearance needed"], "correct": 2, "re": "OSHA requires keeping at least 10 ft from energized overhead lines up to 50 kV (more for higher voltages); contact can be fatal - look up and plan the route.", "rr": "OSHA требует держать не менее 10 футов от воздушных линий под напряжением до 50 кВ (больше для высших напряжений); контакт смертелен - смотрите вверх и планируйте маршрут.", "qr": "При переноске лестниц или работе с оборудованием рядом с воздушными ЛЭП (до 50 кВ) держите минимальный зазор не менее:", "optsr": ["2 дюймов", "1 фута", "10 футов", "Зазор не нужен"]}, {"id": 489, "sec": "Safety & Field Practices", "q": "On a rooftop or other wet/outdoor location, power tools should be plugged into:", "opts": ["An extension cord with no ground", "A GFCI-protected circuit", "The disconnect terminals", "Any outlet"], "correct": 1, "re": "GFCI protection in wet/outdoor locations cuts power on a ground fault within milliseconds, protecting the worker from electrocution.", "rr": "GFCI-защита во влажных/уличных местах отключает питание при замыкании на землю за миллисекунды, защищая работника от поражения током.", "qr": "На крыше или в другом влажном/уличном месте электроинструмент следует включать в:", "optsr": ["Удлинитель без земли", "Цепь с GFCI-защитой", "Клеммы разъединителя", "Любую розетку"]}, {"id": 490, "sec": "Safety & Field Practices", "q": "The 'ABC' of a personal fall-arrest system stands for Anchorage, Body harness, and:", "opts": ["Battery", "Connector (lanyard/lifeline)", "Compressor", "Conduit"], "correct": 1, "re": "A personal fall-arrest system needs an Anchorage point, a full-Body harness, and a Connector (lanyard/SRL/lifeline) - all three rated and used correctly.", "rr": "Системе защиты от падения нужны точка анкеровки (Anchorage), полная привязь (Body harness) и соединитель (Connector - строп/SRL/линь) - все три рассчитаны и правильно применены.", "qr": "'ABC' системы защиты от падения - это Anchorage (анкер), Body harness (страховочная привязь) и:", "optsr": ["Battery (батарея)", "Connector (строп/линь)", "Compressor (компрессор)", "Conduit (кабель-канал)"]}, {"id": 491, "sec": "Safety & Field Practices", "q": "Open floor or roof holes and skylights on a jobsite must be:", "opts": ["Left open", "Guarded with a cover or guardrail to prevent falls", "Marked with paint only", "Filled with refrigerant"], "correct": 1, "re": "Skylights and floor/roof openings are fall hazards; protect them with a secured, load-rated cover or guardrails, and label covers.", "rr": "Световые люки и проёмы в полу/крыше - опасность падения; защищайте их закреплённой, нагрузочно-рассчитанной крышкой или ограждениями и маркируйте крышки.", "qr": "Открытые проёмы в полу/крыше и световые люки на объекте должны быть:", "optsr": ["Оставлены открытыми", "Защищены крышкой или ограждением для предотвращения падения", "Только помечены краской", "Заполнены хладагентом"]}, {"id": 492, "sec": "Safety & Field Practices", "q": "Disturbing painted surfaces in a home built before 1978 may release lead, so the technician should:", "opts": ["Burn the paint off", "Ignore it", "Sand it dry freely", "Follow lead-safe (RRP) work practices and contain dust"], "correct": 3, "re": "Pre-1978 paint may contain lead; use lead-safe renovation practices (containment, wet methods, cleanup) and proper certification when disturbing it.", "rr": "Краска до 1978 может содержать свинец; применяйте lead-safe методы ремонта (сдерживание, влажные методы, уборка) и нужную сертификацию при её нарушении.", "qr": "Нарушение окрашенных поверхностей в доме, построенном до 1978, может высвободить свинец, поэтому техник должен:", "optsr": ["Выжигать краску", "Игнорировать", "Свободно шлифовать насухо", "Соблюдать lead-safe (RRP) практики и сдерживать пыль"]}, {"id": 493, "sec": "Safety & Field Practices", "q": "If a CO alarm sounds and occupants have symptoms, the correct immediate action is to:", "opts": ["Silence the alarm", "Open a window and keep working", "Evacuate occupants to fresh air, then ventilate and find the source", "Run the furnace harder"], "correct": 2, "re": "Carbon monoxide is life-threatening; get everyone to fresh air first, call for help if symptomatic, then shut down the suspect appliance and diagnose the source.", "rr": "Угарный газ опасен для жизни; сначала выведите всех на свежий воздух, при симптомах вызовите помощь, затем отключите подозрительный прибор и найдите источник.", "qr": "Если сработал CO-сигнализатор и у людей есть симптомы, правильное немедленное действие:", "optsr": ["Заглушить сигнализатор", "Открыть окно и продолжать работать", "Вывести людей на свежий воздух, затем проветрить и найти источник", "Сильнее гонять печь"]}, {"id": 494, "sec": "Safety & Field Practices", "q": "A digital multimeter used for measuring on building power should carry a CAT rating that:", "opts": ["Is always CAT I", "Is the cheapest", "Does not matter", "Matches or exceeds the circuit's category (e.g., CAT III for distribution)"], "correct": 3, "re": "The CAT (measurement category) rating ensures the meter can safely handle transient overvoltages on that circuit; using an underrated meter risks arc-flash injury.", "rr": "Рейтинг CAT (категория измерения) гарантирует, что прибор безопасно выдержит переходные перенапряжения этой цепи; недостаточный рейтинг грозит травмой от дугового разряда.", "qr": "Цифровой мультиметр для измерений на сетевом питании здания должен иметь CAT-рейтинг, который:", "optsr": ["Всегда CAT I", "Самый дешёвый", "Неважен", "Соответствует или выше категории цепи (например CAT III для распределения)"]}, {"id": 495, "sec": "Safety & Field Practices", "q": "Lithium-ion power-tool batteries should be:", "opts": ["Charged on flammable surfaces", "Punctured to test them", "Thrown in water", "Kept from damage/heat and charged with the correct charger; damaged packs removed from service"], "correct": 3, "re": "Damaged, overheated, or improperly charged Li-ion packs can vent or catch fire; use the right charger, avoid heat/impact, and dispose of damaged packs safely.", "rr": "Повреждённые, перегретые или неправильно заряженные Li-ion могут воспламениться; используйте верное зарядное, берегите от жара/удара и безопасно утилизируйте повреждённые.", "qr": "Литий-ионные аккумуляторы электроинструмента следует:", "optsr": ["Заряжать на горючих поверхностях", "Прокалывать для проверки", "Бросать в воду", "Беречь от повреждений/жара и заряжать правильным зарядным; повреждённые - выводить из эксплуатации"]}, {"id": 496, "sec": "Safety & Field Practices", "q": "On a GHS chemical label, the 'flame' pictogram indicates the product is:", "opts": ["Heavy", "Flammable", "Cold", "Toxic"], "correct": 1, "re": "GHS pictograms convey hazards at a glance: the flame means flammable, the skull-and-crossbones means acutely toxic, the exploding-bomb means explosive, etc.", "rr": "GHS-пиктограммы передают опасности с первого взгляда: пламя - горюч, череп с костями - остротоксичен, взрывающаяся бомба - взрывоопасен и т.д.", "qr": "На GHS-этикетке химиката пиктограмма 'пламя' указывает, что продукт:", "optsr": ["Тяжёлый", "Горюч", "Холодный", "Токсичен"]}, {"id": 497, "sec": "Safety & Field Practices", "q": "First aid for a minor burn from hot metal or a torch is to:", "opts": ["Rub it with flux", "Cool the burn with running water and cover it; do not break blisters", "Apply ice directly and pop blisters", "Ignore it"], "correct": 1, "re": "Cool a thermal burn with cool (not ice-cold) running water, cover loosely, and avoid breaking blisters; seek medical care for serious burns.", "rr": "Охладите термический ожог прохладной (не ледяной) проточной водой, неплотно прикройте и не вскрывайте пузыри; при серьёзных ожогах обратитесь за медпомощью.", "qr": "Первая помощь при лёгком ожоге горячим металлом или горелкой:", "optsr": ["Натереть флюсом", "Охладить ожог проточной водой и прикрыть; не вскрывать пузыри", "Прикладывать лёд напрямую и вскрывать пузыри", "Игнорировать"]}, {"id": 498, "sec": "Safety & Field Practices", "q": "Safe ladder use requires maintaining three points of contact and:", "opts": ["Facing the ladder while climbing, not overreaching", "Climbing with both hands full", "Facing away from the ladder", "Standing on the top rung"], "correct": 0, "re": "Keep three points of contact, face the ladder, keep your belt buckle between the rails (no overreaching), and never stand on the top cap/rung.", "rr": "Сохраняйте три точки контакта, держитесь лицом к лестнице, пряжка ремня между стойками (без перетягивания) и никогда не стойте на верхней крышке/ступени.", "qr": "Безопасное использование лестницы требует сохранять три точки контакта и:", "optsr": ["Подниматься лицом к лестнице, не перетягиваясь вбок", "Лезть с занятыми обеими руками", "Стоять спиной к лестнице", "Стоять на верхней ступени"]}, {"id": 499, "sec": "Safety & Field Practices", "q": "Ladders and materials carried on a vehicle rack must be:", "opts": ["Stacked above the legal height", "Properly secured/tied down so they cannot shift or fall in transit", "Left untied for quick access", "Loosely placed"], "correct": 1, "re": "Unsecured loads can fall off and cause crashes or injuries; tie down ladders and materials and check the straps before driving.", "rr": "Незакреплённый груз может упасть и вызвать аварию или травмы; привязывайте лестницы и материалы и проверяйте стяжки перед поездкой.", "qr": "Лестницы и материалы на багажнике автомобиля должны быть:", "optsr": ["Сложены выше допустимой высоты", "Надёжно закреплены/привязаны, чтобы не сместились и не упали в пути", "Оставлены непривязанными для быстрого доступа", "Свободно положены"]}, {"id": 500, "sec": "Safety & Field Practices", "q": "If a job cannot be completed safely with the available tools, PPE, or conditions, the correct action is to:", "opts": ["Remove the safety guards", "Rush to finish anyway", "Skip the PPE", "Stop work, address the hazard, and get the right equipment/help before continuing"], "correct": 3, "re": "Production never justifies an unsafe shortcut; every worker can and should stop work to correct a hazard, obtain proper PPE/equipment, and follow the SDS and codes.", "rr": "Выработка никогда не оправдывает небезопасный обход; любой работник может и должен остановить работу, устранить опасность, получить нужные СИЗ/оборудование и соблюдать SDS и нормы.", "qr": "Если работу нельзя выполнить безопасно с имеющимися инструментами, СИЗ или условиями, правильное действие:", "optsr": ["Снять защитные ограждения", "Всё равно спешно закончить", "Пропустить СИЗ", "Остановить работу, устранить опасность и получить нужное оборудование/помощь до продолжения"]}]
};
